-- Poems batch 482
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-69','對雪寄荊幕知己','齊己','唐','御定全唐诗','yuding','','[]','猛勢微開萬里清，月中看似日中明。此時鷗鷺無人見，',40,'御定全唐詩/json/845.json','["猛勢微開萬里清，月中看似日中明。此時鷗鷺無人見，", "江齋卷箔含毫久，應想梁王禮不經。"]'),
('yuding-70','送相裏秀才赴舉','齊己','唐','御定全唐诗','yuding','','[]','兩上東堂不見春，文明重去有誰親。曾逢少海尊前客，',40,'御定全唐詩/json/845.json','["兩上東堂不見春，文明重去有誰親。曾逢少海尊前客，", "明年自此登龍後，回首荊門一路塵。"]'),
('yuding-71','荊門疾中喜謝尊師自南嶽來、相裏秀才自京至','齊己','唐','御定全唐诗','yuding','','[]','閑堂晝臥眼初開，強起徐行繞砌苔。鶴氅人從衡嶽至，',40,'御定全唐詩/json/845.json','["閑堂晝臥眼初開，強起徐行繞砌苔。鶴氅人從衡嶽至，", "西笑東遊此相別，兩途消息待誰回。"]'),
('yuding-72','吟興自述','齊己','唐','御定全唐诗','yuding','','[]','前習都由未盡空，生知雅學妙難窮。一千首出悲哀外，',40,'御定全唐詩/json/845.json','["前習都由未盡空，生知雅學妙難窮。一千首出悲哀外，", "曾無一字幹聲利，豈愧操心負至公。"]'),
('yuding-73','送謝尊師自南嶽出入京','齊己','唐','御定全唐诗','yuding','','[]','曾聽鹿鳴逢世亂，因披羽服隱衡陽。幾多事隔丹霄興，',40,'御定全唐詩/json/845.json','["曾聽鹿鳴逢世亂，因披羽服隱衡陽。幾多事隔丹霄興，", "中朝舊有知音在，可是悠悠入帝鄉。"]'),
('yuding-74','送司空學士赴京','齊己','唐','御定全唐诗','yuding','','[]','弘文初命下江邊，難戀沙鷗與釣船。藍綬乍稱新學士，',40,'御定全唐詩/json/845.json','["弘文初命下江邊，難戀沙鷗與釣船。藍綬乍稱新學士，", "重謁往年金榜主，便將才術佐陶甄。"]'),
('yuding-0','春寄尚顏','齊己','唐','御定全唐诗','yuding','','[]','含桃花謝杏花開，杜宇新啼燕子來。好事可能無分得，',40,'御定全唐詩/json/846.json','["含桃花謝杏花開，杜宇新啼燕子來。好事可能無分得，", "心跡共師爭幾許，似人嫌處自遲回。"]'),
('yuding-1','寄梁先輩','齊己','唐','御定全唐诗','yuding','','[]','慈恩塔下曲江邊，別後多應夢到仙。時去與誰論此事，',40,'御定全唐詩/json/846.json','["慈恩塔下曲江邊，別後多應夢到仙。時去與誰論此事，", "愛惜麻衣好顏色，未教朱紫汙天然。"]'),
('yuding-2','荊渚偶作','齊己','唐','御定全唐诗','yuding','','[]','無味吟詩即把經，竟將疏野訪誰行。身依江寺庭無樹，',40,'御定全唐詩/json/846.json','["無味吟詩即把經，竟將疏野訪誰行。身依江寺庭無樹，", "從容一覺清涼夢，歸到龍潭掃石枰。"]'),
('yuding-3','城中晚夏思山','齊己','唐','御定全唐诗','yuding','','[]','葛衣沾汗功雖健，紙扇搖風力甚卑。苦熱恨無行腳處，',40,'御定全唐詩/json/846.json','["葛衣沾汗功雖健，紙扇搖風力甚卑。苦熱恨無行腳處，", "天外有山歸即是，豈同遊子暮何之。"]'),
('yuding-4','憶舊山','齊己','唐','御定全唐诗','yuding','','[]','誰請衰羸住北州，七年魂夢舊山丘。心清檻底瀟湘月，',40,'御定全唐詩/json/846.json','["誰請衰羸住北州，七年魂夢舊山丘。心清檻底瀟湘月，", "應須脫灑孤峰去，始是分明個剃頭。"]'),
('yuding-5','寄體休','齊己','唐','御定全唐诗','yuding','','[]','南州君去為尋醫，病色應除似舊時。久別莫忘廬阜約，',40,'御定全唐詩/json/846.json','["南州君去為尋醫，病色應除似舊時。久別莫忘廬阜約，", "兩處山河見興廢，相思更切臥雲期。"]'),
('yuding-6','過陸鴻漸舊居','齊己','唐','御定全唐诗','yuding','','[]','楚客西來過舊居，讀碑尋傳見終初。佯狂未必輕儒業，',40,'御定全唐詩/json/846.json','["楚客西來過舊居，讀碑尋傳見終初。佯狂未必輕儒業，", "如今若更生來此，知有何人贈白驢。"]'),
('yuding-7','寄懷鐘陵舊游因寄知己','齊己','唐','御定全唐诗','yuding','','[]','洗井僧來說舊游，西江東岸是城樓。昔年淹跡因王化，',40,'御定全唐詩/json/846.json','["洗井僧來說舊游，西江東岸是城樓。昔年淹跡因王化，", "終拖老病重尋去，得到匡廬死便休。"]'),
('yuding-8','遣懷','齊己','唐','御定全唐诗','yuding','','[]','病腸休洗老休醫，七十能饒百歲期。不死任還蓬島客，',40,'御定全唐詩/json/846.json','["病腸休洗老休醫，七十能饒百歲期。不死任還蓬島客，", "既兆未萌閑酌度，不如中抱是尋思。"]'),
('yuding-9','懷武陵因寄幕中韓先輩、何從事','齊己','唐','御定全唐诗','yuding','','[]','武陵嘉致跡多幽，每見圖經恨白頭。溪浪碧通何處去，',40,'御定全唐詩/json/846.json','["武陵嘉致跡多幽，每見圖經恨白頭。溪浪碧通何處去，", "鑿井耕田人在否，如今天子正征搜。"]'),
('yuding-10','贈樊處士','齊己','唐','御定全唐诗','yuding','','[]','小子聲名天下知，滿簪霜雪白麻衣。誰將一著爭先後，',40,'御定全唐詩/json/846.json','["小子聲名天下知，滿簪霜雪白麻衣。誰將一著爭先後，", "閑尋道士過仙觀，賭得黃庭兩卷歸。"]'),
('yuding-11','荊渚逢禪友','齊己','唐','御定全唐诗','yuding','','[]','澤國相逢話一宵，雲山偶別隔前朝。社思匡岳無宗炳，',40,'御定全唐詩/json/846.json','["澤國相逢話一宵，雲山偶別隔前朝。社思匡岳無宗炳，", "閑吟莫忘傳心祖，曾立階前雪到腰。"]'),
('yuding-12','送僧歸洛中','齊己','唐','御定全唐诗','yuding','','[]','赤日彤霞照晚坡，東州道路興如何。蟬離楚柳鳴猶少，',40,'御定全唐詩/json/846.json','["赤日彤霞照晚坡，東州道路興如何。蟬離楚柳鳴猶少，", "叮嚀與訪春山寺，白樂天真在也麼。"]'),
('yuding-13','道林寓居','齊己','唐','御定全唐诗','yuding','','[]','秋泉一片樹千株，暮汲寒燒外有餘。青嶂這邊來已熟，',40,'御定全唐詩/json/846.json','["秋泉一片樹千株，暮汲寒燒外有餘。青嶂這邊來已熟，", "即問沃州開士僻，愛禽憐駿意何如。"]'),
('yuding-14','仙掌','齊己','唐','御定全唐诗','yuding','','[]','峭形寒倚夕陽天，毛女蓮花翠影連。雲外自為高出手，',40,'御定全唐詩/json/846.json','["峭形寒倚夕陽天，毛女蓮花翠影連。雲外自為高出手，", "晴露紅霞長滿掌，只應棲托是神仙。"]'),
('yuding-15','中秋月','齊己','唐','御定全唐诗','yuding','','[]','空碧無雲露濕衣，群星光外湧清規。東樓莫礙漸高勢，',40,'御定全唐詩/json/846.json','["空碧無雲露濕衣，群星光外湧清規。東樓莫礙漸高勢，", "可憐半夜嬋娟影，正對五侯殘酒池。"]'),
('yuding-16','送禪者游南嶽','齊己','唐','御定全唐诗','yuding','','[]','忽隨南棹去衡陽，誰住江邊樹下房。塵夢是非都覺了，',40,'御定全唐詩/json/846.json','["忽隨南棹去衡陽，誰住江邊樹下房。塵夢是非都覺了，", "想到中峰上層寺，石窗秋霽見瀟湘。"]'),
('yuding-17','聞道林諸友嘗茶因有寄','齊己','唐','御定全唐诗','yuding','','[]','槍旗冉冉綠叢園，穀雨初晴叫杜鵑。摘帶岳華蒸曉露，',40,'御定全唐詩/json/846.json','["槍旗冉冉綠叢園，穀雨初晴叫杜鵑。摘帶岳華蒸曉露，", "應念苦吟耽睡起，不堪無過夕陽天。"]'),
('yuding-18','將歸舊山留別錯公','齊己','唐','御定全唐诗','yuding','','[]','舊峰前昨下來時，白石叢叢間紫薇。章句不堪歌有道，',40,'御定全唐詩/json/846.json','["舊峰前昨下來時，白石叢叢間紫薇。章句不堪歌有道，", "欲去更思過丈室，二年頻此揖清暉。"]'),
('yuding-19','聞尚顏上人創居有寄','齊己','唐','御定全唐诗','yuding','','[]','麓山南面橘洲西，別構新齋與竹齊。野客已聞將鶴贈，',40,'御定全唐詩/json/846.json','["麓山南面橘洲西，別構新齋與竹齊。野客已聞將鶴贈，", "可想乍移禪榻處，松陰冷濕壁新泥。"]'),
('yuding-20','庚午歲九日作','齊己','唐','御定全唐诗','yuding','','[]','門底秋苔嫩似藍，此中消息興何堪。亂離偷過九月九，',40,'御定全唐詩/json/846.json','["門底秋苔嫩似藍，此中消息興何堪。亂離偷過九月九，", "故人今日在不在，胡雁背風飛向南。"]'),
('yuding-21','逢進士沈彬','齊己','唐','御定全唐诗','yuding','','[]','欲話趨時首重騷，因君倍惜剃頭刀。千般貴在能過達，',40,'御定全唐詩/json/846.json','["欲話趨時首重騷，因君倍惜剃頭刀。千般貴在能過達，", "時應記得長安事，曾向文場屬思勞。"]'),
('yuding-22','聞王員外新恩有寄','齊己','唐','御定全唐诗','yuding','','[]','欲退無因貴逼來，少儀官美右丞才。青袍早許淹花幕，',40,'御定全唐詩/json/846.json','["欲退無因貴逼來，少儀官美右丞才。青袍早許淹花幕，", "西峰有客思相賀，門隔瀟湘雪未開。"]'),
('yuding-23','秋夕言懷寄所知','齊己','唐','御定全唐诗','yuding','','[]','休問蒙莊材不材，孤燈影共傍寒灰。忘筌話道心甘死，',40,'御定全唐詩/json/846.json','["休問蒙莊材不材，孤燈影共傍寒灰。忘筌話道心甘死，", "相疏卻是相知分，誰訝經年一度來。"]'),
('yuding-24','答禪者','齊己','唐','御定全唐诗','yuding','','[]','五老峰前相遇時，兩無言語只揚眉。南宗北祖皆如此，',40,'御定全唐詩/json/846.json','["五老峰前相遇時，兩無言語只揚眉。南宗北祖皆如此，", "閑吟莫學湯從事，拋卻袈裟負本師。"]'),
('yuding-25','寄尚顏','齊己','唐','御定全唐诗','yuding','','[]','莫向孤峰道息機，有人偷眼羨吾師。滿身光化年前寵，',40,'御定全唐詩/json/846.json','["莫向孤峰道息機，有人偷眼羨吾師。滿身光化年前寵，", "清吟但憶徐方政，應恨當時不見時。"]'),
('yuding-26','梓栗杖送人','齊己','唐','御定全唐诗','yuding','','[]','禪家何物贈分襟，只有天臺杖一尋。拄去客歸青洛遠，',40,'御定全唐詩/json/846.json','["禪家何物贈分襟，只有天臺杖一尋。拄去客歸青洛遠，", "此日江邊贈君後，卻攜筇杖向東林。"]'),
('yuding-27','寄朗陵二禪友','齊己','唐','御定全唐诗','yuding','','[]','瀟湘曾宿話詩評，荊楚連秋阻野情。金錫罷游雙鬢白，',40,'御定全唐詩/json/846.json','["瀟湘曾宿話詩評，荊楚連秋阻野情。金錫罷游雙鬢白，", "南望山門石何處，滄浪雲夢浸天橫。"]'),
('yuding-28','燈','齊己','唐','御定全唐诗','yuding','','[]','幽光耿耿草堂空，窗隔飛蛾恨不通。紅燼自凝清夜朵，',40,'御定全唐詩/json/846.json','["幽光耿耿草堂空，窗隔飛蛾恨不通。紅燼自凝清夜朵，", "金屋玉堂開照睡，豈知螢雪有深功。"]'),
('yuding-29','寄金陵幕中李郎中','齊己','唐','御定全唐诗','yuding','','[]','龍門支派富才能，年少飛翔便大鵬。久待尊罍臨鐵甕，',40,'御定全唐詩/json/846.json','["龍門支派富才能，年少飛翔便大鵬。久待尊罍臨鐵甕，", "長憶相招宿華館，數宵忘寢盡寒燈。"]'),
('yuding-30','寄韓蛻秀才','齊己','唐','御定全唐诗','yuding','','[]','松門高不似侯門，蘚徑鞋蹤觸處分。遠事即為無害鳥，',40,'御定全唐詩/json/846.json','["松門高不似侯門，蘚徑鞋蹤觸處分。遠事即為無害鳥，", "知伴李膺琴酒外，絳紗閑卷共論文。"]'),
('yuding-31','湘中春興','齊己','唐','御定全唐诗','yuding','','[]','雨歇江明苑樹幹，物妍時泰恣遊盤。更無輕翠勝楊柳，',40,'御定全唐詩/json/846.json','["雨歇江明苑樹幹，物妍時泰恣遊盤。更無輕翠勝楊柳，", "紅芳片片由青帝，忍向西園看落殘。"]'),
('yuding-32','送錯公、棲公南游','齊己','唐','御定全唐诗','yuding','','[]','洪偃湯休道不殊，高帆共載興何俱。北京喪亂離丹鳳，',40,'御定全唐詩/json/846.json','["洪偃湯休道不殊，高帆共載興何俱。北京喪亂離丹鳳，", "威儀本是朝天士，暫向遼荒住得無。"]'),
('yuding-33','寄南嶽諸道友','齊己','唐','御定全唐诗','yuding','','[]','南望衡陽積瘴開，去年曾踏雪遊回。謾為楚客蹉跎過，',40,'御定全唐詩/json/846.json','["南望衡陽積瘴開，去年曾踏雪遊回。謾為楚客蹉跎過，", "終尋十八高人去，共坐蒼崖養聖胎。"]'),
('yuding-34','送韓蛻秀才赴舉','齊己','唐','御定全唐诗','yuding','','[]','槐花館驛暮塵昏，此去分明吏部孫。才器合居科第首，',40,'御定全唐詩/json/846.json','["槐花館驛暮塵昏，此去分明吏部孫。才器合居科第首，", "堪想都人齊指點，列仙相次上昆侖。"]'),
('yuding-35','溪居寓言','齊己','唐','御定全唐诗','yuding','','[]','秋蔬數壟傍潺湲，頗覺生涯異俗緣。詩興難窮花草外，',40,'御定全唐詩/json/846.json','["秋蔬數壟傍潺湲，頗覺生涯異俗緣。詩興難窮花草外，", "寄向東溪老樵道，莫催丹桂博青錢。"]'),
('yuding-36','遣懷','齊己','唐','御定全唐诗','yuding','','[]','詩病相兼老病深，世醫徒更費千金。餘生豈必虛拋擲，',40,'御定全唐詩/json/846.json','["詩病相兼老病深，世醫徒更費千金。餘生豈必虛拋擲，", "閑身自有閑消處，黃葉清風蟬一林。"]'),
('yuding-37','自湘中將入蜀留別諸友','齊己','唐','御定全唐诗','yuding','','[]','巾舄初隨入蜀船，風帆吼過洞庭煙。七千里路到何處，',40,'御定全唐詩/json/846.json','["巾舄初隨入蜀船，風帆吼過洞庭煙。七千里路到何處，", "來年五月峨嵋雪，坐看消融滿錦川。"]'),
('yuding-38','寄匡阜諸公二首','齊己','唐','御定全唐诗','yuding','','[]','松頭柏頂碧森森，虛檻寒吹夏景深。靜社可追長往跡，',80,'御定全唐詩/json/846.json','["松頭柏頂碧森森，虛檻寒吹夏景深。靜社可追長往跡，", "爭學忘言住幽勝，吾師遺集盡清吟。", "峰前林下東西寺，地角天涯來往僧。泉月淨流閑世界，", "曾寄鄰房掛瓶錫，雨聞岩溜解春冰。"]'),
('yuding-39','送人入蜀','齊己','唐','御定全唐诗','yuding','','[]','何必閑吟蜀道難，知君心出嶮巇間。尋常秋泛江陵去，',40,'御定全唐詩/json/846.json','["何必閑吟蜀道難，知君心出嶮巇間。尋常秋泛江陵去，", "文君酒市逢初雪，滿貰新沽洗旅顏。"]'),
('yuding-40','酬廬山張處士','齊己','唐','御定全唐诗','yuding','','[]','發枯身老任浮沉，懶泥秋風更役吟。新事向人堪結舌，',40,'御定全唐詩/json/846.json','["發枯身老任浮沉，懶泥秋風更役吟。新事向人堪結舌，", "終謝柴桑與彭澤，醉遊閑訪入東林。"]'),
('yuding-41','寄峴山道人','齊己','唐','御定全唐诗','yuding','','[]','鳳門高對鹿門青，往歲經過恨未平。辯鼎上人方話道，',40,'御定全唐詩/json/846.json','["鳳門高對鹿門青，往歲經過恨未平。辯鼎上人方話道，", "聞說東周天子聖，會搖金錫卻西行。"]'),
('yuding-42','送王處士游蜀','齊己','唐','御定全唐诗','yuding','','[]','又掛寒帆向錦川，木蘭舟裏過殘年。自修姹姹爐中物，',40,'御定全唐詩/json/846.json','["又掛寒帆向錦川，木蘭舟裏過殘年。自修姹姹爐中物，", "來年的有荊南信，回劄應緘十色箋。"]'),
('yuding-43','懷金陵李推官僧自牧','齊己','唐','御定全唐诗','yuding','','[]','秣陵長憶共吟遊，儒釋風騷道上流。蓮幕少年輕謝脁，',40,'御定全唐詩/json/846.json','["秣陵長憶共吟遊，儒釋風騷道上流。蓮幕少年輕謝脁，", "欲附別來千萬意，病身初起向殘秋。"]'),
('yuding-44','寄尋萍公','齊己','唐','御定全唐诗','yuding','','[]','聞在湓城多寄住，隨時談笑渾塵埃。孤峰恐憶便歸去，',40,'御定全唐詩/json/846.json','["聞在湓城多寄住，隨時談笑渾塵埃。孤峰恐憶便歸去，", "虎溪橋上龍潭寺，曾此相尋踏雪回。"]'),
('yuding-45','得李推官近寄懷','齊己','唐','御定全唐诗','yuding','','[]','荊門前歲使乎回，求得星郎近制來。連日借吟終不已，',40,'御定全唐詩/json/846.json','["荊門前歲使乎回，求得星郎近制來。連日借吟終不已，", "堪笑陳宮諸狎客，當時空有個追陪。"]'),
('yuding-46','對菊','齊己','唐','御定全唐诗','yuding','','[]','蝶醉風狂半折時，冷煙清露壓離披。欲傾琥珀杯浮爾，',40,'御定全唐詩/json/846.json','["蝶醉風狂半折時，冷煙清露壓離披。欲傾琥珀杯浮爾，", "何因栽向僧園裏，門外重陽過不知。"]'),
('yuding-47','憶東林因送二生歸','齊己','唐','御定全唐诗','yuding','','[]','好向東林度此生，半天山腳寺門平。紅霞嶂底潺潺色，',40,'御定全唐詩/json/846.json','["好向東林度此生，半天山腳寺門平。紅霞嶂底潺潺色，", "可憐二子同歸興，南國煙花路好行。"]'),
('yuding-48','渚宮西城池上居','齊己','唐','御定全唐诗','yuding','','[]','城東移錫住城西，綠繞春波引杖藜。翡翠滿身衣有異，',40,'御定全唐詩/json/846.json','["城東移錫住城西，綠繞春波引杖藜。翡翠滿身衣有異，", "猶有幽深不相似，剡溪乘棹入耶溪。"]'),
('yuding-49','中秋夕愴懷寄荊幕孫郎中','齊己','唐','御定全唐诗','yuding','','[]','白蓮香散沼痕幹，綠筱陰濃蘚地寒。年老寄居思隱切，',40,'御定全唐詩/json/846.json','["白蓮香散沼痕幹，綠筱陰濃蘚地寒。年老寄居思隱切，", "時謝孔璋操檄外，每將空病問衰殘。"]'),
('yuding-50','酬湘幕徐員外見寄','齊己','唐','御定全唐诗','yuding','','[]','東海儒宗事業全，冰棱孤峭類神仙。詩同李賀精通鬼，',40,'御定全唐詩/json/846.json','["東海儒宗事業全，冰棱孤峭類神仙。詩同李賀精通鬼，", "篇章幾謝傳西楚，空想雄風度十年。"]'),
('yuding-51','寄蜀國廣濟大師','齊己','唐','御定全唐诗','yuding','','[]','冰壓霜壇律格清，三千傳授盡門生。禪心盡入空無跡，',40,'御定全唐詩/json/846.json','["冰壓霜壇律格清，三千傳授盡門生。禪心盡入空無跡，", "終思相約岷峨去，不得攜筇一路行。"]'),
('yuding-52','答獻上人卷','齊己','唐','御定全唐诗','yuding','','[]','衲衣禪客袖篇章，江上相尋共感傷。秦甸亂來棲白沒，',40,'御定全唐詩/json/846.json','["衲衣禪客袖篇章，江上相尋共感傷。秦甸亂來棲白沒，", "珍重南宗好才子，灰心冥目外無妨。"]'),
('yuding-53','寄武陵貫微上人二首','齊己','唐','御定全唐诗','yuding','','[]','知泛滄浪棹未還，西峰房鎖夜潺潺。春陪相府遊仙洞，',80,'御定全唐詩/json/846.json','["知泛滄浪棹未還，西峰房鎖夜潺潺。春陪相府遊仙洞，", "莫忘一句曹溪妙，堪塞孫孫騁度關。", "吳頭東面楚西邊，雲接蒼梧水浸天。兩地別離身已老，", "不是傲他名利世，吾師本在雪山巔。"]'),
('yuding-54','懷體休上人','齊己','唐','御定全唐诗','yuding','','[]','仲宣樓上望重湖，君到瀟湘得健無。病遇何人分藥餌，',40,'御定全唐詩/json/846.json','["仲宣樓上望重湖，君到瀟湘得健無。病遇何人分藥餌，", "許送自身歸華嶽，待來朝暮拂瓶盂。"]'),
('yuding-55','招湖上兄弟','齊己','唐','御定全唐诗','yuding','','[]','去歲得君消息在，兩憑人信過重湖。忍貪風月當年少，',40,'御定全唐詩/json/846.json','["去歲得君消息在，兩憑人信過重湖。忍貪風月當年少，", "漢江江路西來便，好傍扁舟訪我無。"]'),
('yuding-56','江居寄關中知己','齊己','唐','御定全唐诗','yuding','','[]','多病多慵漢水邊，流年不覺已皤然。舊栽花地添黃竹，',40,'御定全唐詩/json/846.json','["多病多慵漢水邊，流年不覺已皤然。舊栽花地添黃竹，", "八行書劄君休問，不似風騷寄一篇。"]'),
('yuding-57','中秋十五夜寄人','齊己','唐','御定全唐诗','yuding','','[]','高河瑟瑟轉金盤，噴露吹光逆憑欄。四海魚龍精魄冷，',40,'御定全唐詩/json/846.json','["高河瑟瑟轉金盤，噴露吹光逆憑欄。四海魚龍精魄冷，", "何事清光與蟾兔，卻教才小少留難。"]'),
('yuding-58','謝人自鐘陵寄紙筆','齊己','唐','御定全唐诗','yuding','','[]','故人猶憶苦吟勞，所惠何殊金錯刀。霜雪剪栽新剡硾，',40,'御定全唐詩/json/846.json','["故人猶憶苦吟勞，所惠何殊金錯刀。霜雪剪栽新剡硾，", "詞客分張看欲盡，不堪來處隔秋濤。"]'),
('yuding-59','移居西湖作二首','齊己','唐','御定全唐诗','yuding','','[]','火雲陽焰欲燒空，小檻幽窗想舊峰。白汗此時流枕簟，',80,'御定全唐詩/json/846.json','["火雲陽焰欲燒空，小檻幽窗想舊峰。白汗此時流枕簟，", "只待秋聲滌心地，衲衣新洗健形容。", "官園樹影晝陰陰，咫尺清涼莫浣心。桃李別教人主掌，", "爭似出塵地行止，東林苔徑入西林。"]'),
('yuding-60','題玉泉寺','齊己','唐','御定全唐诗','yuding','','[]','高韻雙懸張曲江，聯題兼是孟襄陽。後人才地誰稱短，',40,'御定全唐詩/json/846.json','["高韻雙懸張曲江，聯題兼是孟襄陽。後人才地誰稱短，", "時移兩板成塵跡，猶掛吾師舊影堂。"]'),
('yuding-61','看金陵圖','齊己','唐','御定全唐诗','yuding','','[]','六朝圖畫戰爭多，最是陳宮計數訛。',32,'御定全唐詩/json/846.json','["六朝圖畫戰爭多，最是陳宮計數訛。", "若愛蒼生似歌舞，隋皇自合恥干戈。"]'),
('yuding-62','寄南嶽泰禪師','齊己','唐','御定全唐诗','yuding','','[]','江頭默想坐禪峰，白石山前萬丈空。',32,'御定全唐詩/json/846.json','["江頭默想坐禪峰，白石山前萬丈空。", "山下獵人應不到，雪深花鹿在庵中。"]'),
('yuding-63','片雲','齊己','唐','御定全唐诗','yuding','','[]','水底分明天上雲，可憐形影似吾身。',32,'御定全唐詩/json/846.json','["水底分明天上雲，可憐形影似吾身。", "何妨舒作從龍勢，一雨吹銷萬里塵。"]'),
('yuding-64','寄清溪道者','齊己','唐','御定全唐诗','yuding','','[]','萬重千疊紅霞嶂，夜燭朝香白石龕。',32,'御定全唐詩/json/846.json','["萬重千疊紅霞嶂，夜燭朝香白石龕。", "常寄溪窗憑危檻，看經影落古龍潭。"]'),
('yuding-65','病中勉送小師往清涼山禮大聖','齊己','唐','御定全唐诗','yuding','','[]','豐衣足食處莫住，聖跡靈蹤好遍尋。',32,'御定全唐詩/json/846.json','["豐衣足食處莫住，聖跡靈蹤好遍尋。", "忽遇文殊開慧眼，他年應記老師心。"]'),
('yuding-66','謝人惠拄杖','齊己','唐','御定全唐诗','yuding','','[]','何處雲根采得來，黑龍狂欲作風雷。',32,'御定全唐詩/json/846.json','["何處雲根采得來，黑龍狂欲作風雷。", "知師念我形骸老，教把經行拄綠苔。"]'),
('yuding-67','《送楚雲上人往南嶽刺血寫法華經》','齊己','唐','御定全唐诗','yuding','','[]','剝皮刺血誠何苦，欲寫靈山九會文。',32,'御定全唐詩/json/846.json','["剝皮刺血誠何苦，欲寫靈山九會文。", "十指瀝幹終七軸，後來求法更無君。"]'),
('yuding-68','送胎髮筆寄仁公','齊己','唐','御定全唐诗','yuding','','[]','內唯胎髮外秋毫，綠玉新栽管束牢。',32,'御定全唐詩/json/846.json','["內唯胎髮外秋毫，綠玉新栽管束牢。", "老病手疼無那爾，卻資年少寫風騷。"]'),
('yuding-69','謝西川曇域大師玉箸篆書','齊己','唐','御定全唐诗','yuding','','[]','玉箸真文久不興，李斯傳到李陽冰。',32,'御定全唐詩/json/846.json','["玉箸真文久不興，李斯傳到李陽冰。", "正悲千載無來者，果見僧中有個僧。"]'),
('yuding-70','偶作寄王秘書','齊己','唐','御定全唐诗','yuding','','[]','七絲湘水秋深夜，五字河橋日暮時。',32,'御定全唐詩/json/846.json','["七絲湘水秋深夜，五字河橋日暮時。", "借問秘書郎此意，靜彈高詠有誰知。"]'),
('yuding-71','謝人惠紙','齊己','唐','御定全唐诗','yuding','','[]','烘焙幾工成曉雪，輕明百幅疊春冰。',32,'御定全唐詩/json/846.json','["烘焙幾工成曉雪，輕明百幅疊春冰。", "何消才子題詩外，分與能書貝葉僧。"]'),
('yuding-72','答文勝大師清柱書','齊己','唐','御定全唐诗','yuding','','[]','才把文章幹聖主，便承恩澤換禪衣。',32,'御定全唐詩/json/846.json','["才把文章幹聖主，便承恩澤換禪衣。", "應嫌六祖傳空衲，只向曹溪求息機。"]'),
('yuding-73','寄懷曾口寺文英大師','齊己','唐','御定全唐诗','yuding','','[]','著紫袈裟名已貴，吟紅菡萏價兼高。',32,'御定全唐詩/json/846.json','["著紫袈裟名已貴，吟紅菡萏價兼高。", "秋風曾憶西遊處，門對平湖滿白濤。"]'),
('yuding-74','懷道林寺道友','齊己','唐','御定全唐诗','yuding','','[]','四絕堂前萬木秋，碧參差影壓湘流。',32,'御定全唐詩/json/846.json','["四絕堂前萬木秋，碧參差影壓湘流。", "閑思宋杜題詩板，一日憑欄到夜休。"]'),
('yuding-75','辭主人絕句四首：放鶴','齊己','唐','御定全唐诗','yuding','','[]','華亭來複去芝田，丹頂霜毛性可憐。',32,'御定全唐詩/json/846.json','["華亭來複去芝田，丹頂霜毛性可憐。", "縱與乘軒終誤主，不如還放卻遼天。"]'),
('yuding-76','辭主人絕句四首：放猿','齊己','唐','御定全唐诗','yuding','','[]','堪憶春雲十二峰，野桃山杏摘香紅。',32,'御定全唐詩/json/846.json','["堪憶春雲十二峰，野桃山杏摘香紅。", "王孫可念愁金鎖，從放斷腸明月中。"]'),
('yuding-77','辭主人絕句四首：放鷺鷥','齊己','唐','御定全唐诗','yuding','','[]','白萍紅蓼碧江涯，日暖雙雙立睡時。',32,'御定全唐詩/json/846.json','["白萍紅蓼碧江涯，日暖雙雙立睡時。", "顧揭金籠放歸去，卻隨沙鶴鬥輕絲。"]'),
('yuding-78','辭主人絕句四首：放鸚鵡','齊己','唐','御定全唐诗','yuding','','[]','隴西蒼巘結巢高，本為無人識翠毛。',32,'御定全唐詩/json/846.json','["隴西蒼巘結巢高，本為無人識翠毛。", "今日籠中強言語，乞歸天外啄含桃。"]'),
('yuding-0','猛虎行','齊己','唐','御定全唐诗','yuding','','[]','磨爾牙，錯爾爪。狐莫威，兔莫狡，饑來吞噬取腸飽。',48,'御定全唐詩/json/847.json','["磨爾牙，錯爾爪。狐莫威，兔莫狡，饑來吞噬取腸飽。", "橫行不怕日月明，皇天產爾為生獰。前村半夜聞吼聲，"]'),
('yuding-1','西山叟','齊己','唐','御定全唐诗','yuding','','[]','西山中，多狼虎，去歲傷兒複傷婦。官家不問孤老身，',24,'御定全唐詩/json/847.json','["西山中，多狼虎，去歲傷兒複傷婦。官家不問孤老身，"]'),
('yuding-2','君子行','齊己','唐','御定全唐诗','yuding','','[]','聖人不生，麟龍何瑞。梧桐不高，鳳凰何止。',45,'御定全唐詩/json/847.json','["聖人不生，麟龍何瑞。梧桐不高，鳳凰何止。", "吾聞古之有君子，行藏以時，進退求己。榮必為天下榮，"]'),
('yuding-3','善哉行','齊己','唐','御定全唐诗','yuding','','[]','大鵬刷翮謝溟渤，青雲萬層高突出。下視秋濤空渺彌，',40,'御定全唐詩/json/847.json','["大鵬刷翮謝溟渤，青雲萬層高突出。下視秋濤空渺彌，", "願除嗜欲待身輕，攜手同尋列仙事。"]'),
('yuding-4','日日曲','齊己','唐','御定全唐诗','yuding','','[]','日日日東上，日日日西沒。任是神仙容，也須成朽骨。',44,'御定全唐詩/json/847.json','["日日日東上，日日日西沒。任是神仙容，也須成朽骨。", "浮雲滅複生，芳草死還出。不知千古萬古人，"]'),
('yuding-5','耕叟','齊己','唐','御定全唐诗','yuding','','[]','春風吹蓑衣，暮雨滴箬笠。夫婦耕共勞，兒孫饑對泣。',48,'御定全唐詩/json/847.json','["春風吹蓑衣，暮雨滴箬笠。夫婦耕共勞，兒孫饑對泣。", "田園高且瘦，賦稅重複急。官倉鼠雀群，共待新租入。"]'),
('yuding-6','苦熱行','齊己','唐','御定全唐诗','yuding','','[]','離宮劃開赤帝怒，喝出六龍奔日馭。下土熬熬若煎煮，',40,'御定全唐詩/json/847.json','["離宮劃開赤帝怒，喝出六龍奔日馭。下土熬熬若煎煮，", "何當一雨蘇我苗，為君擊壤歌帝堯。"]'),
('yuding-7','苦寒行','齊己','唐','御定全唐诗','yuding','','[]','冰峰撐空寒矗矗，雲凝水凍埋海陸。殺物之性，傷人之欲。',73,'御定全唐詩/json/847.json','["冰峰撐空寒矗矗，雲凝水凍埋海陸。殺物之性，傷人之欲。", "既不能斷絕蒺藜荊棘之根株，又不能展鳳凰麒麟之拳局。", "如此，則何如為和煦，為膏雨，自然天下之榮枯，"]'),
('yuding-8','春風曲','齊己','唐','御定全唐诗','yuding','','[]','春風有何情，旦暮來林園。不問桃李主，吹落紅無言。',24,'御定全唐詩/json/847.json','["春風有何情，旦暮來林園。不問桃李主，吹落紅無言。"]'),
('yuding-9','城中懷山友','齊己','唐','御定全唐诗','yuding','','[]','春城來往桃李碧，暖豔紅香斷消息。',32,'御定全唐詩/json/847.json','["春城來往桃李碧，暖豔紅香斷消息。", "吾徒自有山中鄰，白晝冥心坐嵐壁。"]'),
('yuding-10','讀李賀歌集','齊己','唐','御定全唐诗','yuding','','[]','赤水無精華，荊山亦枯槁。玄珠與虹玉，璨璨李賀抱。',48,'御定全唐詩/json/847.json','["赤水無精華，荊山亦枯槁。玄珠與虹玉，璨璨李賀抱。", "清晨醉起臨春台，吳綾蜀錦胸襟開。狂多兩手掀蓬萊，"]'),
('yuding-11','風琴引','齊己','唐','御定全唐诗','yuding','','[]','挪吳絲，雕楚竹，高托天風拂為曲。一一宮商在素空，',48,'御定全唐詩/json/847.json','["挪吳絲，雕楚竹，高托天風拂為曲。一一宮商在素空，", "愁魂傍枕不肯去，翻疑住處鄰湘娥。金風聲盡熏風發，"]'),
('yuding-12','夏雲曲','齊己','唐','御定全唐诗','yuding','','[]','紅嵯峨，爍晚波，乖龍慵臥旱鬼多。爞爞萬里壓天塹，',44,'御定全唐詩/json/847.json','["紅嵯峨，爍晚波，乖龍慵臥旱鬼多。爞爞萬里壓天塹，", "男巫女覡更走魂，焚香祝天天不聞。天若聞，"]'),
('yuding-13','讀李白集','齊己','唐','御定全唐诗','yuding','','[]','竭雲濤，刳巨鼇，搜括造化空牢牢。冥心入海海神怖，',48,'御定全唐詩/json/847.json','["竭雲濤，刳巨鼇，搜括造化空牢牢。冥心入海海神怖，", "鏘金鏗玉千餘篇，膾吞炙嚼人口傳。須知一一丈夫氣，"]'),
('yuding-14','祈真壇','齊己','唐','御定全唐诗','yuding','','[]','玉甕瑤壇二三級，學仙弟子參差入。霓旌隊仗下不下，',50,'御定全唐詩/json/847.json','["玉甕瑤壇二三級，學仙弟子參差入。霓旌隊仗下不下，", "茫茫俗骨醉更昏，樓臺十二遙昆侖。昆侖縱廣一萬二千里，"]'),
('yuding-15','黃雀行','齊己','唐','御定全唐诗','yuding','','[]','雙雙野田雀，上下同飲啄。暖去棲蓬蒿，寒歸傍籬落。',48,'御定全唐詩/json/847.json','["雙雙野田雀，上下同飲啄。暖去棲蓬蒿，寒歸傍籬落。", "殷勤避羅網，乍可遇雕鶚。雕鶚雖不仁，分明在寥廓。"]'),
('yuding-16','石竹花','齊己','唐','御定全唐诗','yuding','','[]','石竹花開照庭石，紅蘚自稟離宮色。一枝兩枝初笑風，',48,'御定全唐詩/json/847.json','["石竹花開照庭石，紅蘚自稟離宮色。一枝兩枝初笑風，", "誰為根尋造化功，為君吐出淳元膽。白日當午方盛開，"]'),
('yuding-17','寄南嶽白蓮道士能于長嘯','齊己','唐','御定全唐诗','yuding','','[]','猿猱休啼月皎皎，蟋蟀不吟山悄悄。',32,'御定全唐詩/json/847.json','["猿猱休啼月皎皎，蟋蟀不吟山悄悄。", "大耳仙人滿頷須，醉倚長松一聲嘯。"]'),
('yuding-18','古劍歌','齊己','唐','御定全唐诗','yuding','','[]','古人手中鑄神物，百煉百淬始提出。今人不要強硎磨，',40,'御定全唐詩/json/847.json','["古人手中鑄神物，百煉百淬始提出。今人不要強硎磨，", "何時得遇英雄主，用爾平治天下去。"]'),
('yuding-19','湘妃廟','齊己','唐','御定全唐诗','yuding','','[]','湘煙濛濛湘水急，汀露凝紅裛蓮濕。蒼梧雲疊九嶷深，',48,'御定全唐詩/json/847.json','["湘煙濛濛湘水急，汀露凝紅裛蓮濕。蒼梧雲疊九嶷深，", "廟荒松朽啼飛猩，筍鞭迸出階基傾。黃昏一岸陰風起，"]'),
('yuding-20','巫山高','齊己','唐','御定全唐诗','yuding','','[]','巫山高，巫女妖，雨為暮兮雲為朝，楚王憔悴魂欲銷。',64,'御定全唐詩/json/847.json','["巫山高，巫女妖，雨為暮兮雲為朝，楚王憔悴魂欲銷。", "秋猿嗥嗥日將夕，紅霞紫煙凝老壁。千岩萬壑花皆坼，", "雲深廟遠不可覓，十二峰頭插天碧。"]'),
('yuding-21','《贈持法華經》僧','齊己','唐','御定全唐诗','yuding','','[]','眾人有口，不說是，即說非。吾師有口何所為，',63,'御定全唐詩/json/847.json','["眾人有口，不說是，即說非。吾師有口何所為，", "我聞念經功德緣，舌根可算金剛堅。他時劫火洞燃後，", "魔王輪幢自摧折，何況更如理行如理說。"]'),
('yuding-22','刳腸龜','齊己','唐','御定全唐诗','yuding','','[]','爾既能于靈，應久存其生。爾既能于瑞，胡得迷其死。',48,'御定全唐詩/json/847.json','["爾既能于靈，應久存其生。爾既能于瑞，胡得迷其死。", "刳腸徒自屠，曳尾複何累。可憐濮水流，一葉泛莊子。"]'),
('yuding-23','贈岩居僧','齊己','唐','御定全唐诗','yuding','','[]','石如騏驎岩作室，秋苔漫壇淨於漆。',32,'御定全唐詩/json/847.json','["石如騏驎岩作室，秋苔漫壇淨於漆。", "袈裟蓋頭心在無，黃猿白猿啼日日。"]'),
('yuding-24','觀李瓊處士畫海濤','齊己','唐','御定全唐诗','yuding','','[]','巨鼇轉側長鰍翻，狂濤顛浪高漫漫。李瓊奪得造化本，',72,'御定全唐詩/json/847.json','["巨鼇轉側長鰍翻，狂濤顛浪高漫漫。李瓊奪得造化本，", "葉撲仙槎擺欲沉，下頭應是驪龍窟。昔年曾要涉蓬瀛，", "千尋萬派功難測，海門山小濤頭白。令人錯認錢塘城，"]'),
('yuding-25','升天行','齊己','唐','御定全唐诗','yuding','','[]','身不沉，骨不重。驅青鸞，駕白鳳。幢蓋飄搖入冷空，',48,'御定全唐詩/json/847.json','["身不沉，骨不重。驅青鸞，駕白鳳。幢蓋飄搖入冷空，", "三五仙子乘龍車，堂前碾爛蟠桃花。回頭卻顧蓬萊頂，"]'),
('yuding-26','還人卷','齊己','唐','御定全唐诗','yuding','','[]','李白李賀遺機杼，散在人間不知處。聞君收在芙蓉江，',48,'御定全唐詩/json/847.json','["李白李賀遺機杼，散在人間不知處。聞君收在芙蓉江，", "鴛鴦浴煙鸞鳳飛，澄江曉映餘霞輝。仙人手持玉刀尺，"]'),
('yuding-27','輕薄行','齊己','唐','御定全唐诗','yuding','','[]','玉鞭金鐙驊騮蹄，橫眉吐氣如虹霓。五陵春暖芳草齊，',40,'御定全唐詩/json/847.json','["玉鞭金鐙驊騮蹄，橫眉吐氣如虹霓。五陵春暖芳草齊，", "伯陽道德何唾咦，仲尼禮樂徒卑棲。"]'),
('yuding-28','浮雲行','齊己','唐','御定全唐诗','yuding','','[]','大野有賢人，大朝有聖君。如何彼浮雲，掩蔽白日輪。',48,'御定全唐詩/json/847.json','["大野有賢人，大朝有聖君。如何彼浮雲，掩蔽白日輪。", "安得東南風，吹散八表外。使之天下人，共見堯眉彩。"]'),
('yuding-29','煌煌京洛行','齊己','唐','御定全唐诗','yuding','','[]','聖君垂衣裳，蕩蕩若朝旭。大觀無遺物，四夷來率服。',72,'御定全唐詩/json/847.json','["聖君垂衣裳，蕩蕩若朝旭。大觀無遺物，四夷來率服。", "清晨回北極，紫氣蓋黃屋。雙闕聳雙鼇，九門如川瀆。", "梯山航海至，晝夜車相續。我恐紅塵深，變為黃河曲。"]'),
('yuding-30','吊汨羅','齊己','唐','御定全唐诗','yuding','','[]','落日倚闌幹，徘徊汨羅曲。冤魂如可吊，煙浪聲似哭。',46,'御定全唐詩/json/847.json','["落日倚闌幹，徘徊汨羅曲。冤魂如可吊，煙浪聲似哭。", "我欲考黿鼉之心，烹魚龍之腹。爾既啖大夫之血，"]'),
('yuding-31','《贈念法華經》僧','齊己','唐','御定全唐诗','yuding','','[]','念念念兮入惡易，念念念兮入善難。念經念佛能一般，',140,'御定全唐詩/json/847.json','["念念念兮入惡易，念念念兮入善難。念經念佛能一般，", "心心緣經口緣字，一室寥寥燈照地。沈檀卷軸寶函盛，", "牙根舌根水滴寒，珊瑚捶打紅琅玕。但恐蓮花七朵一時折，", "況聞此經甚微妙，百千諸佛真秘要。靈山說後始傳來，", "舜弦和雅熏風吹，文王武王弦更悲。", "如此爭不遣碧空中有龍來聽，有鬼來聽。亦使人間聞者敬，"]'),
('yuding-32','短歌寄鼓山長老','齊己','唐','御定全唐诗','yuding','','[]','雪峰雪峰高且雄，峨峨堆積青冥中。六月赤日燒不熔，',72,'御定全唐詩/json/847.json','["雪峰雪峰高且雄，峨峨堆積青冥中。六月赤日燒不熔，", "行圍坐繞同一色，森森影動旃檀香。於中一子最雄猛，", "我聞岷國民歸依，前王后王皆師資。甯同梁武遇達磨，"]'),
('yuding-33','漁父','齊己','唐','御定全唐诗','yuding','','[]','夜釣洞庭月，朝醉巴陵市。卻歸君山下，魚龍窟邊睡。',48,'御定全唐詩/json/847.json','["夜釣洞庭月，朝醉巴陵市。卻歸君山下，魚龍窟邊睡。", "生涯在何處，白浪千萬里。曾笑楚臣迷，蒼黃汨羅水。"]'),
('yuding-34','採蓮曲','齊己','唐','御定全唐诗','yuding','','[]','越溪女，越江蓮。齊菡萏，雙嬋娟。嬉游向何處，',22,'御定全唐詩/json/847.json','["越溪女，越江蓮。齊菡萏，雙嬋娟。嬉游向何處，"]'),
('yuding-35','啄木','齊己','唐','御定全唐诗','yuding','','[]','啄木啄啄，鳴林響壑。貪心既緣，利嘴斯鑿。',60,'御定全唐詩/json/847.json','["啄木啄啄，鳴林響壑。貪心既緣，利嘴斯鑿。", "有朽百尺，微蟲斯宅。以啄去害，啄更彌劇。", "層崖豫章，聳幹蒼蒼。無縱爾啄，摧我棟樑。"]'),
('yuding-36','靈松歌','齊己','唐','御定全唐诗','yuding','','[]','靈松靈松，是何根株。盤擗枝幹，與群木殊。',116,'御定全唐詩/json/847.json','["靈松靈松，是何根株。盤擗枝幹，與群木殊。", "世眼爭知蒼翠容，薜蘿遮體深朦朧。先秋瑟瑟生穀風，", "唯有此松高下枝，一枝枝在無摧折。癡凍頑冰如鐵堅，", "有時深洞興雷雹，飛電繞身光閃爍。乍似蒼龍驚起時，", "千年朽枿魍魎出，一株寒韻鏘琉璃。安得良工妙圖雘，"]'),
('yuding-37','蠹','齊己','唐','御定全唐诗','yuding','','[]','蠹不自蠹，而蠹於木。蠹極木心，以豐爾腹。',60,'御定全唐詩/json/847.json','["蠹不自蠹，而蠹於木。蠹極木心，以豐爾腹。", "偶或成之，胡為勖人。人而不真，繇爾亂神。", "蠹兮蠹兮，何全其生。無托爾形，霜松雪檉。"]'),
('yuding-38','行路難','齊己','唐','御定全唐诗','yuding','','[]','行路難，君好看，驚波不在黤黮間，小人心裏藏崩湍。',63,'御定全唐詩/json/847.json','["行路難，君好看，驚波不在黤黮間，小人心裏藏崩湍。", "七盤九折寒崷崒，翻車倒蓋猶堪出。未似是非唇舌危，", "又不見李太白，一朝卻作江南客。"]'),
('yuding-39','謝徽上人見惠二龍障子，以短歌酬之','齊己','唐','御定全唐诗','yuding','','[]','我見蘇州昆山金城中，金城柱上有二龍。',120,'御定全唐詩/json/847.json','["我見蘇州昆山金城中，金城柱上有二龍。", "老僧相傳道是僧繇手，尋常入海共龍鬥。", "又聞蜀國玉局觀有孫遇跡，盤屈身長八十尺。", "遊人爭看不敢近，頭覷寒泉萬丈碧。近有五羊徽上人，", "徽上人，真藝者。惠我雙龍不言價，等閒不敢將懸掛。", "恐是葉公好假龍，及見真龍卻驚怕。"]'),
('yuding-40','送人往長沙','齊己','唐','御定全唐诗','yuding','','[]','荊門歸路指湖南，千里風帆興可諳。',32,'御定全唐詩/json/847.json','["荊門歸路指湖南，千里風帆興可諳。", "好聽鷓鴣啼雨處，木蘭舟晚泊春潭。"]'),
('yuding-41','偶題','齊己','唐','御定全唐诗','yuding','','[]','時事懶言多忌諱，野吟無主若縱橫。',32,'御定全唐詩/json/847.json','["時事懶言多忌諱，野吟無主若縱橫。", "君看三百篇章首，何處分明著姓名。"]'),
('yuding-42','寄山中叟','齊己','唐','御定全唐诗','yuding','','[]','青泉碧樹夏風涼，紫蕨紅粳午爨香。',32,'御定全唐詩/json/847.json','["青泉碧樹夏風涼，紫蕨紅粳午爨香。", "應笑晨持一盂苦，腥膻市里叫家常。"]'),
('yuding-43','贈琴客','齊己','唐','御定全唐诗','yuding','','[]','曾攜五老峰前過，幾向雙松石上彈。',32,'御定全唐詩/json/847.json','["曾攜五老峰前過，幾向雙松石上彈。", "此境此身誰更愛，掀天羯鼓滿長安。"]'),
('yuding-44','勉吟僧','齊己','唐','御定全唐诗','yuding','','[]','千途萬轍亂真源，白晝勞形夜斷魂。',32,'御定全唐詩/json/847.json','["千途萬轍亂真源，白晝勞形夜斷魂。", "忍著袈裟把名紙，學他低折五侯門。"]'),
('yuding-45','送人歸華下','齊己','唐','御定全唐诗','yuding','','[]','蓮花峰翠濕凝秋，舊業園林在下頭。',32,'御定全唐詩/json/847.json','["蓮花峰翠濕凝秋，舊業園林在下頭。", "好束詩書且歸去，而今不愛事風流。"]'),
('yuding-46','夏日城中作二首','齊己','唐','御定全唐诗','yuding','','[]','三面僧鄰一面牆，更無風路可吹涼。',64,'御定全唐詩/json/847.json','["三面僧鄰一面牆，更無風路可吹涼。", "他年舍此歸何處，青壁紅霞裹石房。", "竹低莎淺雨濛濛，水檻幽窗暑月中。", "有境牽懷人不會，東林門外翠橫空。"]'),
('yuding-47','默坐','齊己','唐','御定全唐诗','yuding','','[]','燈引飛蛾拂焰迷，露淋棲鶴壓枝低。',32,'御定全唐詩/json/847.json','["燈引飛蛾拂焰迷，露淋棲鶴壓枝低。", "冥心坐滿蒲團穩，夢到天臺過剡溪。"]'),
('yuding-48','水邊行','齊己','唐','御定全唐诗','yuding','','[]','身著袈裟手杖藤，水邊行止不妨僧。',32,'御定全唐詩/json/847.json','["身著袈裟手杖藤，水邊行止不妨僧。", "禽棲日落猶孤立，隔浪秋山千萬層。"]'),
('yuding-49','寄鄭谷郎中','齊己','唐','御定全唐诗','yuding','','[]','人間近遇風騷匠，鳥外曾逢心印師。',32,'御定全唐詩/json/847.json','["人間近遇風騷匠，鳥外曾逢心印師。", "除此二門無別妙，水邊松下獨尋思。"]'),
('yuding-50','翡翠','齊己','唐','御定全唐诗','yuding','','[]','水邊飛去青難辨，竹裏歸來色一般。',32,'御定全唐詩/json/847.json','["水邊飛去青難辨，竹裏歸來色一般。", "磨吻鷹鸇莫相害，白鷗鴻鶴滿沙灘。"]'),
('yuding-51','與節供奉大德遊京口寺留題','齊己','唐','御定全唐诗','yuding','','[]','柳岸晴緣十裏來，水邊精舍絕塵埃。',32,'御定全唐詩/json/847.json','["柳岸晴緣十裏來，水邊精舍絕塵埃。", "煮茶嘗摘興何極，直至殘陽未欲回。"]'),
('yuding-52','《謝荊幕孫郎中見示樂府歌集》二十八字','齊己','唐','御定全唐诗','yuding','','[]','長吉才狂太白顛，二公文陣勢橫前。',32,'御定全唐詩/json/847.json','["長吉才狂太白顛，二公文陣勢橫前。", "誰言後代無高手，奪得秦皇鞭鬼鞭。"]'),
('yuding-53','《謝陰符經》勉送藏休上人二首','齊己','唐','御定全唐诗','yuding','','[]','事遂鼎湖遺劍履，時來渭水擲魚竿。',64,'御定全唐詩/json/847.json','["事遂鼎湖遺劍履，時來渭水擲魚竿。", "欲知賢聖存亡道，自向心機反復看。", "一林霜雪未沾頭，爭遣藏休肯便休。", "學盡世間難學事，始堪隨處任虛舟。"]'),
('yuding-54','幽齋偶作','齊己','唐','御定全唐诗','yuding','','[]','幽院才容個小庭，疏篁低短不堪情。',32,'御定全唐詩/json/847.json','["幽院才容個小庭，疏篁低短不堪情。", "春來猶賴鄰僧樹，時引流鶯送好聲。"]'),
('yuding-55','《贈念法華經》僧','齊己','唐','御定全唐诗','yuding','','[]','萬境心隨一念平，紅芙蓉折愛河清。',32,'御定全唐詩/json/847.json','["萬境心隨一念平，紅芙蓉折愛河清。", "持經功力能如是，任駕白牛安穩行。"]'),
('yuding-56','對菊','齊己','唐','御定全唐诗','yuding','','[]','無豔無妖別有香，栽多不為待重陽。',32,'御定全唐詩/json/847.json','["無豔無妖別有香，栽多不為待重陽。", "莫嫌醒眼相看過，卻是真心愛澹黃。"]'),
('yuding-57','閉門','齊己','唐','御定全唐诗','yuding','','[]','正是閉門爭合閉，大家開處不須開。',32,'御定全唐詩/json/847.json','["正是閉門爭合閉，大家開處不須開。", "還防朗月清風夜，有個詩人相訪來。"]'),
('yuding-58','勉送吳國三五新戒歸','齊己','唐','御定全唐诗','yuding','','[]','法王遺制付仁王，難得難持劫數長。',32,'御定全唐詩/json/847.json','["法王遺制付仁王，難得難持劫數長。", "努力只須堅守護，三千八萬是垣牆。"]'),
('yuding-59','夏日寄清溪道者','齊己','唐','御定全唐诗','yuding','','[]','老病不能求藥餌，朝昏只是但焚燒。',32,'御定全唐詩/json/847.json','["老病不能求藥餌，朝昏只是但焚燒。", "不知誰為收灰骨，壘石栽松傍寺橋。"]'),
('yuding-60','送惠空北游','齊己','唐','御定全唐诗','yuding','','[]','君向峴山遊聖境，我將何以記多才。',32,'御定全唐詩/json/847.json','["君向峴山遊聖境，我將何以記多才。", "叮嚀墮淚碑前過，寫取斯文寄我來。"]'),
('yuding-61','寄懷歸州馬判官','齊己','唐','御定全唐诗','yuding','','[]','三年為倅興何長，歸計應多事少忙。',32,'御定全唐詩/json/847.json','["三年為倅興何長，歸計應多事少忙。", "又見秋風霜裛樹，滿山椒熟水雲香。"]'),
('yuding-62','觀荷葉露珠','齊己','唐','御定全唐诗','yuding','','[]','霏微曉露成珠顆，宛轉田田未有風。',32,'御定全唐詩/json/847.json','["霏微曉露成珠顆，宛轉田田未有風。", "任器方圓性終在，不妨翻覆落池中。"]'),
('yuding-63','苦熱懷玉泉寺寄仁上人','齊己','唐','御定全唐诗','yuding','','[]','火雲如燒接蒼梧，原野煙連大澤枯。',32,'御定全唐詩/json/847.json','["火雲如燒接蒼梧，原野煙連大澤枯。", "謾費葛衫葵扇力，爭禁泉石潤肌膚。"]'),
('yuding-64','觀盆池白蓮','齊己','唐','御定全唐诗','yuding','','[]','素萼金英噴露開，倚風凝立獨徘徊。',32,'御定全唐詩/json/847.json','["素萼金英噴露開，倚風凝立獨徘徊。", "應思瀲灩秋池底，更有歸天伴侶來。"]'),
('yuding-65','折楊柳詞四首','齊己','唐','御定全唐诗','yuding','','[]','鳳樓高映綠陰陰，凝重多含雨露深。',128,'御定全唐詩/json/847.json','["鳳樓高映綠陰陰，凝重多含雨露深。", "莫謂一枝柔軟力，幾曾牽破別離心。", "館娃宮畔響廊前，依託吳王養翠煙。", "劍去國亡台殿毀，卻隨紅樹噪秋蟬。", "穠低似中陶潛酒，軟極如傷宋玉風。", "多謝將軍繞營種，翠中閑卓戰旗紅。", "高僧愛惜遮江寺，遊子傷殘露野橋。", "爭似著行垂上苑，碧桃紅杏對搖搖。"]'),
('yuding-66','答長沙丁秀才書','齊己','唐','御定全唐诗','yuding','','[]','月月便車奔帝闕，年年貢士過荊台。',32,'御定全唐詩/json/847.json','["月月便車奔帝闕，年年貢士過荊台。", "如何三度槐花落，未見故人攜卷來。"]'),
('yuding-67','戒小師','齊己','唐','御定全唐诗','yuding','','[]','不肯吟詩不聽經，禪宗異嶽懶遊行。',32,'御定全唐詩/json/847.json','["不肯吟詩不聽經，禪宗異嶽懶遊行。", "他年白首當人問，將底言談對後生。"]'),
('yuding-68','題舊拄杖','齊己','唐','御定全唐诗','yuding','','[]','親采匡廬瀑布西，層崖懸壁更安梯。',32,'御定全唐詩/json/847.json','["親采匡廬瀑布西，層崖懸壁更安梯。", "攜行三十年吟伴，未有詩人□□□。"]'),
('yuding-69','酬歐陽秀才卷','齊己','唐','御定全唐诗','yuding','','[]','三十篇多十九章，□聲風力撼疏篁。',32,'御定全唐詩/json/847.json','["三十篇多十九章，□聲風力撼疏篁。", "不堪更有精搜處，誰見蕭蕭雨夜堂。"]'),
('yuding-70','聞雁','齊己','唐','御定全唐诗','yuding','','[]','瀟湘浦暖全迷鶴，邏逤川寒只有雕。',32,'御定全唐詩/json/847.json','["瀟湘浦暖全迷鶴，邏逤川寒只有雕。", "誰向孤舟憶兄弟，坐看連雁度橫橋。"]'),
('yuding-71','送高麗二僧南游','齊己','唐','御定全唐诗','yuding','','[]','日邊鄉井別年深，中國靈蹤欲遍尋。',32,'御定全唐詩/json/847.json','["日邊鄉井別年深，中國靈蹤欲遍尋。", "何處碧山逢長老，分明認取祖師心。"]'),
('yuding-72','謝猿皮','齊己','唐','御定全唐诗','yuding','','[]','貴向獵師家買得，攜來乞與坐禪床。',32,'御定全唐詩/json/847.json','["貴向獵師家買得，攜來乞與坐禪床。", "不知摘月秋潭畔，曾對何人啼斷腸。"]'),
('yuding-73','酬光上人','齊己','唐','御定全唐诗','yuding','','[]','禪言難後到詩言，坐石心同立月魂。',32,'御定全唐詩/json/847.json','["禪言難後到詩言，坐石心同立月魂。", "應記前秋會吟處，五更猶在老松根。"]'),
('yuding-74','送僧歸日本','齊己','唐','御定全唐诗','yuding','','[]','日東來向日西遊，一缽閑尋遍九州。',32,'御定全唐詩/json/847.json','["日東來向日西遊，一缽閑尋遍九州。", "卻憶雞林本師寺，欲歸還待海風秋。"]'),
('yuding-75','庚午歲十五夜對月','齊己','唐','御定全唐诗','yuding','','[]','海澄空碧正團圓，吟想玄宗此夜寒。',32,'御定全唐詩/json/847.json','["海澄空碧正團圓，吟想玄宗此夜寒。", "玉兔有情應記得，西邊不見舊長安。"]'),
('yuding-76','紅薔薇花','齊己','唐','御定全唐诗','yuding','','[]','晴日當樓曉香歇，錦帶盤空欲成結。',32,'御定全唐詩/json/847.json','["晴日當樓曉香歇，錦帶盤空欲成結。", "鶯聲漸老柳飛時，狂風吹落猩猩血。"]'),
('yuding-77','貽九華上人','齊己','唐','御定全唐诗','yuding','','[]','一法傳聞繼老能，九華閑臥最高層。',32,'御定全唐詩/json/847.json','["一法傳聞繼老能，九華閑臥最高層。", "秋鐘盡後殘陽暝，門掩松邊雨夜燈。"]'),
('yuding-78','寄賡匡圖兄弟','齊己','唐','御定全唐诗','yuding','','[]','僧外閑吟樂最清，年登八十喪南荊。',32,'御定全唐詩/json/847.json','["僧外閑吟樂最清，年登八十喪南荊。", "風騷作者為商確，道去碧雲爭幾程。"]'),
('yuding-79','句','齊己','唐','御定全唐诗','yuding','','[]','春晴遊寺客，花落閉門僧。',111,'御定全唐詩/json/847.json','["春晴遊寺客，花落閉門僧。", "香傳天下口，□貴火前名。角開香滿室，爐動綠凝鐺。", "園林將向夕，風雨更吹花。", "相思坐溪石，□□□山風。", "夕照背高臺，殘鐘殘角催。", "五老峰前相見時，兩無言語各揚眉。", "高人愛惜藏岩裏，白bv封題寄火前。（《詠茶》，"]'),
('yuding-0','言興','尚顏','唐','御定全唐诗','yuding','','[]','矻矻被吟牽，因師賈浪仙。江山風月處，一十二三年。',48,'御定全唐詩/json/848.json','["矻矻被吟牽，因師賈浪仙。江山風月處，一十二三年。", "雅頌在於此，浮華致那邊。猶慚功未至，謾道近千篇。"]'),
('yuding-1','江上秋思','尚顏','唐','御定全唐诗','yuding','','[]','到來江上久，誰念旅遊心。故國無秋信，鄰家有夜砧。',48,'御定全唐詩/json/848.json','["到來江上久，誰念旅遊心。故國無秋信，鄰家有夜砧。", "坐遙翻不睡，愁極卻成吟。即恐髭連鬢，還為白所侵。"]'),
('yuding-2','匡山居','尚顏','唐','御定全唐诗','yuding','','[]','無才加性拙，道理合藏蹤。是處非深遠，其山已萬重。',48,'御定全唐詩/json/848.json','["無才加性拙，道理合藏蹤。是處非深遠，其山已萬重。", "經時鄰境戰，獨夜隔雲舂。昨日泉中見，常魚亦化龍。"]'),
('yuding-3','夷陵即事','尚顏','唐','御定全唐诗','yuding','','[]','不難饒白髮，相續是灘波。避世嫌身晚，思家乞夢多。',48,'御定全唐詩/json/848.json','["不難饒白髮，相續是灘波。避世嫌身晚，思家乞夢多。", "暑衣經雪著，凍硯向陽呵。豈謂臨岐路，還聞聖主過。"]'),
('yuding-4','紫閣隱者','尚顏','唐','御定全唐诗','yuding','','[]','天高紫閣侵，隱者信沉沉。道長年兼長，雲深草複深。',48,'御定全唐詩/json/848.json','["天高紫閣侵，隱者信沉沉。道長年兼長，雲深草複深。", "如非禪客見，即是獵人尋。北笑長安道，埃塵古到今。"]'),
('yuding-5','與陳陶處士','尚顏','唐','御定全唐诗','yuding','','[]','鐘陵城外住，喻似玉沈泥。道直貧嫌殺，神清語亦低。',48,'御定全唐詩/json/848.json','["鐘陵城外住，喻似玉沈泥。道直貧嫌殺，神清語亦低。", "雪深加酒債，春盡減詩題。記得曾邀宿，山茶獨自攜。"]'),
('yuding-6','與王嵩隱','尚顏','唐','御定全唐诗','yuding','','[]','一生吟興僻，方見業精微。事若終難得，鄉應不易歸。',48,'御定全唐詩/json/848.json','["一生吟興僻，方見業精微。事若終難得，鄉應不易歸。", "亂收西日葉，雙掩北風扉。合國諸卿相，皆曾著布衣。"]'),
('yuding-7','懷陸龜蒙處士','尚顏','唐','御定全唐诗','yuding','','[]','布褐東南隱，相傳繼謝敷。高譚夫子道，靜看海山圖。',48,'御定全唐詩/json/848.json','["布褐東南隱，相傳繼謝敷。高譚夫子道，靜看海山圖。", "事免傷心否，棋逢敵手無。關中花數內，獨不見菖蒲。"]'),
('yuding-8','寄華陰司空侍郎','尚顏','唐','御定全唐诗','yuding','','[]','劍佩已深扃，茅為嶽面亭。詩猶少綺美，畫肯愛丹青。',48,'御定全唐詩/json/848.json','["劍佩已深扃，茅為嶽面亭。詩猶少綺美，畫肯愛丹青。", "換筆修僧史，焚香閱道經。相邀來未得，但想鶴儀形。"]'),
('yuding-9','送陸肱入關','尚顏','唐','御定全唐诗','yuding','','[]','舟行複陸行，始得到咸京。准擬何人口，吹噓六義名。',48,'御定全唐詩/json/848.json','["舟行複陸行，始得到咸京。准擬何人口，吹噓六義名。", "亂山遙減翠，叢菊早含英。衣錦還鄉日，他時有此榮。"]'),
('yuding-10','送劉必先','尚顏','唐','御定全唐诗','yuding','','[]','力進憑詩業，心焦闕問安。遠行無處易，孤立本來難。',48,'御定全唐詩/json/848.json','["力進憑詩業，心焦闕問安。遠行無處易，孤立本來難。", "楚月船中沒，秦星馬上殘。明年有公道，更以命推看。"]'),
('yuding-11','寄方幹處士','尚顏','唐','御定全唐诗','yuding','','[]','格外綴清詩，詩名獨得知。閒居公道日，醉臥牡丹時。',48,'御定全唐詩/json/848.json','["格外綴清詩，詩名獨得知。閒居公道日，醉臥牡丹時。", "海鳥和濤望，山僧帶雪期。仍聞稱處士，聖主肯相違。"]'),
('yuding-12','寄劉逸士','尚顏','唐','御定全唐诗','yuding','','[]','無愁無累者，偶向市朝遊。此後乘孤艇，依前入亂流。',48,'御定全唐詩/json/848.json','["無愁無累者，偶向市朝遊。此後乘孤艇，依前入亂流。", "高眠歌聖日，下釣坐清秋。道不離方寸，而能混俗求。"]'),
('yuding-13','送獨孤處士','尚顏','唐','御定全唐诗','yuding','','[]','萬里去非忙，惟攜貯藥囊。山家宵夜景，酒肆過年光。',48,'御定全唐詩/json/848.json','["萬里去非忙，惟攜貯藥囊。山家宵夜景，酒肆過年光。", "立鶴洲侵浪，喧蛩壁近床。誰人臨上路，乞得變髭方。"]'),
('yuding-14','早春送人歸岳陽','尚顏','唐','御定全唐诗','yuding','','[]','久食主人魚，春來復舊居。遠無千里浪，輕有半船書。',48,'御定全唐詩/json/848.json','["久食主人魚，春來復舊居。遠無千里浪，輕有半船書。", "過片晴雲淡，消殘暮雪虛。岳陽多異境，搜思勿令疏。"]'),
('yuding-15','冬暮送人','尚顏','唐','御定全唐诗','yuding','','[]','長安冬欲盡，又送一遺賢。醉後情渾可，言休理不然。',48,'御定全唐詩/json/848.json','["長安冬欲盡，又送一遺賢。醉後情渾可，言休理不然。", "射衣秦嶺雪，搖月漢江船。亦過春兼夏，回期信有蟬。"]'),
('yuding-16','送徐道人東游','尚顏','唐','御定全唐诗','yuding','','[]','長安人擾擾，獨自有閒心。海上山中去，風前月下吟。',48,'御定全唐詩/json/848.json','["長安人擾擾，獨自有閒心。海上山中去，風前月下吟。", "引猿秋果熟，藏鶴曉雲深。易姓更名數，難教弟子尋。"]'),
('yuding-17','自紀','尚顏','唐','御定全唐诗','yuding','','[]','諸機忘盡未忘詩，似向詩中有所依。遠境等閒支枕覓，',40,'御定全唐詩/json/848.json','["諸機忘盡未忘詩，似向詩中有所依。遠境等閒支枕覓，", "欲畫淨名居士像，焚香願見陸探微。"]'),
('yuding-18','懷智棲上人','尚顏','唐','御定全唐诗','yuding','','[]','臨水登山自有期，不同遊子暮何之。閑眠默坐身堪賞，',40,'御定全唐詩/json/848.json','["臨水登山自有期，不同遊子暮何之。閑眠默坐身堪賞，", "思君最易令人老，倚檻空吟所寄詩。"]'),
('yuding-19','峽中酬荊南鄭准','尚顏','唐','御定全唐诗','yuding','','[]','山齋西向蜀江濆，四載安居複有群。風雁勢高猶可見，',40,'御定全唐詩/json/848.json','["山齋西向蜀江濆，四載安居複有群。風雁勢高猶可見，", "每喜溯流賓客說，元瑜刀筆潤雄軍。"]'),
('yuding-20','寄荊門鄭准','尚顏','唐','御定全唐诗','yuding','','[]','傳衣傳缽理難論，綺靡銷磨二雅尊。不許姓名留月觀，',40,'御定全唐詩/json/848.json','["傳衣傳缽理難論，綺靡銷磨二雅尊。不許姓名留月觀，", "珍重荊門鄭從事，十年同受景升恩。"]'),
('yuding-21','將欲再游荊渚留辭岐下司徒','尚顏','唐','御定全唐诗','yuding','','[]','竹錫銅瓶配衲衣，殷公樓畔偶然離。白蓮幾看從開日，',40,'御定全唐詩/json/848.json','["竹錫銅瓶配衲衣，殷公樓畔偶然離。白蓮幾看從開日，", "今朝回去精神別，為得頭廳宰相詩。"]'),
('yuding-22','贈村公','尚顏','唐','御定全唐诗','yuding','','[]','綢衣木突此鄉尊，白盡鬚眉眼未昏。醉舞神筵隨鼓笛，',40,'御定全唐詩/json/848.json','["綢衣木突此鄉尊，白盡鬚眉眼未昏。醉舞神筵隨鼓笛，", "也笑長安名利處，紅塵半是馬蹄翻。"]'),
('yuding-23','秋夜吟','尚顏','唐','御定全唐诗','yuding','','[]','梧桐雨畔夜愁吟，抖擻衣裾蘚色侵。',32,'御定全唐詩/json/848.json','["梧桐雨畔夜愁吟，抖擻衣裾蘚色侵。", "枉道一生無系著，湘南山水別人尋。"]'),
('yuding-24','讀齊己上人集','尚顏','唐','御定全唐诗','yuding','','[]','詩為儒者禪，此格的惟仙。古雅如周頌，清和甚舜弦。',48,'御定全唐詩/json/848.json','["詩為儒者禪，此格的惟仙。古雅如周頌，清和甚舜弦。", "冰生聽瀑句，香發早梅篇。想得吟成夜，文星照楚天。"]'),
('yuding-25','除夜','尚顏','唐','御定全唐诗','yuding','','[]','九冬三十夜，寒與暖分開。坐到四更後，身添一歲來。',48,'御定全唐詩/json/848.json','["九冬三十夜，寒與暖分開。坐到四更後，身添一歲來。", "魚燈延臘火，獸炭化春灰。青帝今應老，迎新見幾回。"]'),
('yuding-26','送人歸鄉','尚顏','唐','御定全唐诗','yuding','','[]','多才與命違，末路憶柴扉。白髮何人問，青山一劍歸。',48,'御定全唐詩/json/848.json','["多才與命違，末路憶柴扉。白髮何人問，青山一劍歸。", "晴煙獨鳥沒，野渡亂花飛。寂寞長亭外，依然空落暉。"]'),
('yuding-27','述懷','尚顏','唐','御定全唐诗','yuding','','[]','青門聊極望，何事久離群。芳草失歸路，故鄉空暮雲。',96,'御定全唐詩/json/848.json','["青門聊極望，何事久離群。芳草失歸路，故鄉空暮雲。", "信回陵樹老，夢斷灞流分。兄弟正南北，鴻聲堪獨聞。", "五城初罷構，海上憶閑行。觸雪麻衣靜，登山竹錫輕。", "天寒嶽寺出，日晚島泉清。坐與幽期遇，何湖心渺冥。"]'),
('yuding-28','宿壽安甘棠館','尚顏','唐','御定全唐诗','yuding','','[]','行人方倦役，到此似還鄉。流水來關外，青山近洛陽。',96,'御定全唐詩/json/848.json','["行人方倦役，到此似還鄉。流水來關外，青山近洛陽。", "溪雲歸洞鶴，松月半軒霜。坐恐晨鐘動，天涯道路長。", "山空蕙氣香，乳管折雲房。願值壺中客，親傳肘後方。", "三更禮星斗，寸匕服丹霜。默坐樹陰下，仙經橫石床。"]'),
('yuding-29','送樸山人歸新羅','尚顏','唐','御定全唐诗','yuding','','[]','浩渺行無極，揚帆但信風。雲山過海半，鄉樹入舟中。',48,'御定全唐詩/json/848.json','["浩渺行無極，揚帆但信風。雲山過海半，鄉樹入舟中。", "波定遙天出，沙平遠岸窮。離心寄何處，目擊曙霞東。"]'),
('yuding-30','宿清遠峽山寺','尚顏','唐','御定全唐诗','yuding','','[]','寺近朝天路，多聞玉佩音。鑒人開慧眼，歸鳥息禪心。',48,'御定全唐詩/json/848.json','["寺近朝天路，多聞玉佩音。鑒人開慧眼，歸鳥息禪心。", "磬接星河曙，窗連夏木深。此中能宴坐，何必在雲林。"]'),
('yuding-31','松山嶺','尚顏','唐','御定全唐诗','yuding','','[]','平生閑放久，野鹿許為群。居止鄰西嶽，軒窗度白雲。',48,'御定全唐詩/json/848.json','["平生閑放久，野鹿許為群。居止鄰西嶽，軒窗度白雲。", "齋心飯松子，話道接茅君。漢主恩情去，空山起夕氛。"]'),
('yuding-32','句','尚顏','唐','御定全唐诗','yuding','','[]','浸浸三楚白，渺渺九江寒。',12,'御定全唐詩/json/848.json','["浸浸三楚白，渺渺九江寒。"]'),
('yuding-33','泊洞庭','虛中','唐','御定全唐诗','yuding','','[]','槐柳未知秋，依依館驛頭。客心俱念遠，時雨自相留。',48,'御定全唐詩/json/848.json','["槐柳未知秋，依依館驛頭。客心俱念遠，時雨自相留。", "浪沒貨魚市，帆高賣酒樓。夜來思輾轉，故里在南州。"]'),
('yuding-34','善卷壇','虛中','唐','御定全唐诗','yuding','','[]','耕荒鑿原時，高趣在希夷。大舜欲遜國，先生空斂眉。',48,'御定全唐詩/json/848.json','["耕荒鑿原時，高趣在希夷。大舜欲遜國，先生空斂眉。", "五溪清不足，千古美無虧。縱遣亡淳者，何人投所思。"]'),
('yuding-35','石城金穀','虛中','唐','御定全唐诗','yuding','','[]','晉祚一傾摧，驕奢去不回。只應荊棘地，猶作綺羅灰。',48,'御定全唐詩/json/848.json','["晉祚一傾摧，驕奢去不回。只應荊棘地，猶作綺羅灰。", "狐兔閑生長，樵蘇靜往來。踟躕意無盡，寒日又西頹。"]'),
('yuding-36','庾樓','虛中','唐','御定全唐诗','yuding','','[]','郡樓名甚遠，幾換見樓人。庾亮魂應在，清風到白蘋。',48,'御定全唐詩/json/848.json','["郡樓名甚遠，幾換見樓人。庾亮魂應在，清風到白蘋。", "晴軒分楚漢，夜酒揖星辰。何必匡山上，獨言無世塵。"]'),
('yuding-37','經賀監舊居','虛中','唐','御定全唐诗','yuding','','[]','不戀明皇寵，歸來鏡水隅。道裝汀鶴識，春醉釣人扶。',48,'御定全唐詩/json/848.json','["不戀明皇寵，歸來鏡水隅。道裝汀鶴識，春醉釣人扶。", "逐朵雲如吐，成行雁侶驅。蘭亭名景在，蹤跡未為孤。"]'),
('yuding-38','獻鄭都官','虛中','唐','御定全唐诗','yuding','','[]','早晚辭班列，歸尋舊隱峰。代移家集在，身老詔書重。',48,'御定全唐詩/json/848.json','["早晚辭班列，歸尋舊隱峰。代移家集在，身老詔書重。", "藥秘仙都訣，茶開蜀國封。何當答群望，高躡傅岩蹤。"]'),
('yuding-39','寄華山司空圖二首','虛中','唐','御定全唐诗','yuding','','[]','門徑放莎垂，往來投刺稀。有時開禦劄，特地掛朝衣。',96,'御定全唐詩/json/848.json','["門徑放莎垂，往來投刺稀。有時開禦劄，特地掛朝衣。", "嶽信僧傳去，仙香鶴帶歸。他年二南化，無複更衰微。", "逍遙短褐成，一劍動精靈。白晝夢仙島，清晨禮道經。", "黍苗侵野徑，桑椹汙閒庭。肯要為鄰者，西南太華青。"]'),
('yuding-40','贈屏風岩棲蟾上人','虛中','唐','御定全唐诗','yuding','','[]','岩房高且靜，住此幾寒暄。鹿嗅安禪石，猿啼乞食村。',48,'御定全唐詩/json/848.json','["岩房高且靜，住此幾寒暄。鹿嗅安禪石，猿啼乞食村。", "朝陽生樹罅，古路透雲根。獨我閑相覓，淒涼碧洞門。"]'),
('yuding-41','贈秀才','虛中','唐','御定全唐诗','yuding','','[]','筠陽多勝致，夫子縱游遨。鳳鳥瑞不見，鱸魚價轉高。',48,'御定全唐詩/json/848.json','["筠陽多勝致，夫子縱游遨。鳳鳥瑞不見，鱸魚價轉高。", "門開沙觜靜，船系樹根牢。誰解伊人趣，村沽對郁陶。"]'),
('yuding-42','送遷客','虛中','唐','御定全唐诗','yuding','','[]','倏忽墮鵷行，天南去路長。片言曾不諂，獲罪亦何傷。',48,'御定全唐詩/json/848.json','["倏忽墮鵷行，天南去路長。片言曾不諂，獲罪亦何傷。", "象戀藏牙浦，人貪賣子鄉。此心終合雪，去已莫思量。"]'),
('yuding-43','哭悼朝賢','虛中','唐','御定全唐诗','yuding','','[]','前昨回私第，旋聞寢疾終。四鄰方響絕，二月牡丹空。',48,'御定全唐詩/json/848.json','["前昨回私第，旋聞寢疾終。四鄰方響絕，二月牡丹空。", "塚已遷名境，碑仍待至公。只應遺愛理，長在楚南風。"]'),
('yuding-44','悼方幹處士','虛中','唐','御定全唐诗','yuding','','[]','先生在世日，只向鏡湖居。明主未巡狩，白頭閑釣魚。',48,'御定全唐詩/json/848.json','["先生在世日，只向鏡湖居。明主未巡狩，白頭閑釣魚。", "煙莎一徑小，洲島四鄰疏。獨有為儒者，時來吊舊廬。"]'),
('yuding-45','聽軒轅先生琴','虛中','唐','御定全唐诗','yuding','','[]','訣妙與功精，通宵膝上橫。一堂風冷淡，千古意分明。',48,'御定全唐詩/json/848.json','["訣妙與功精，通宵膝上橫。一堂風冷淡，千古意分明。", "坐客神魂凝，巢禽耳目傾。酷哉商紂世，曾不遇先生。"]'),
('yuding-46','芳草','虛中','唐','御定全唐诗','yuding','','[]','綿綿芳草綠，何處動深思。金穀人亡後，沙場日暖時。',48,'御定全唐詩/json/848.json','["綿綿芳草綠，何處動深思。金穀人亡後，沙場日暖時。", "龍鱗藏有瑞，風雨灑無私。欲采蘭兼蕙，清香可贈誰。"]'),
('yuding-47','句','虛中','唐','御定全唐诗','yuding','','[]','喜魚在深處，幽鳥立多時。',72,'御定全唐詩/json/848.json','["喜魚在深處，幽鳥立多時。", "菖蒲花不豔，鴝鵒性多靈。", "盤中是祥瑞，天下恰炎蒸。", "待暖還須去，門前有路岐。", "春雨無高下，花枝有短長。", "老負峨眉月，閑看雲水心。"]'),
('yuding-48','短歌行','棲蟾','唐','御定全唐诗','yuding','','[]','蟾光堪自笑，浮世懶思量。身得幾時活，眼開終日忙。',48,'御定全唐詩/json/848.json','["蟾光堪自笑，浮世懶思量。身得幾時活，眼開終日忙。", "千門無壽藥，一鏡有愁霜。早向塵埃外，光陰任短長。"]'),
('yuding-49','除夜','棲蟾','唐','御定全唐诗','yuding','','[]','九冬三十夜，寒與暖分開。坐到四更後，身添一歲來。',48,'御定全唐詩/json/848.json','["九冬三十夜，寒與暖分開。坐到四更後，身添一歲來。", "魚燈延臘火，獸炭化春灰。青帝今應老，迎新見幾回。"]'),
('yuding-50','宿巴江','棲蟾','唐','御定全唐诗','yuding','','[]','江聲五十裏，瀉碧急於弦。不覺日又夜，爭教人少年。',48,'御定全唐詩/json/848.json','["江聲五十裏，瀉碧急於弦。不覺日又夜，爭教人少年。", "一汀巫峽月，兩岸子規天。山影似相伴，濃遮到曉船。"]'),
('yuding-51','游邊','棲蟾','唐','御定全唐诗','yuding','','[]','邊雲四顧濃，饑馬嗅枯叢。萬里八九月，一身西北風。',48,'御定全唐詩/json/848.json','["邊雲四顧濃，饑馬嗅枯叢。萬里八九月，一身西北風。", "偷營天正黑，戰地雪多紅。昨夜東歸夢，桃花暖色中。"]'),
('yuding-52','居南嶽懷沈彬','棲蟾','唐','御定全唐诗','yuding','','[]','石房開竹扉，茗外獨支頤。萬木還無葉，百年能幾時。',48,'御定全唐詩/json/848.json','["石房開竹扉，茗外獨支頤。萬木還無葉，百年能幾時。", "隔雲聞狖過，截雨見虹垂。因憶岳南客，晏眠吟好詩。"]'),
('yuding-53','南中懷友生','棲蟾','唐','御定全唐诗','yuding','','[]','荔枝江上立，望北幾思量。隔海無書劄，前年在漢陽。',48,'御定全唐詩/json/848.json','["荔枝江上立，望北幾思量。隔海無書劄，前年在漢陽。", "瘴村人起早，銅柱象揩光。居此成何事，尋君過碧湘。"]'),
('yuding-54','贈南嶽玄泰布衲','棲蟾','唐','御定全唐诗','yuding','','[]','曹溪入室人，終老甚難群。四十餘年內，青山與白雲。',48,'御定全唐詩/json/848.json','["曹溪入室人，終老甚難群。四十餘年內，青山與白雲。", "松和巢鶴看，果共野猿分。海外僧來說，名高自小聞。"]'),
('yuding-55','寄問政山聶威儀','棲蟾','唐','御定全唐诗','yuding','','[]','先生臥碧岑，諸祖是知音。得道無一法，孤雲同寸心。',48,'御定全唐詩/json/848.json','["先生臥碧岑，諸祖是知音。得道無一法，孤雲同寸心。", "嵐光熏鶴詔，茶味敵人參。苦向壺中去，他年許我尋。"]'),
('yuding-56','送遷客','棲蟾','唐','御定全唐诗','yuding','','[]','諫頻甘得罪，一騎入南深。若順吾皇意，即無臣子心。',48,'御定全唐詩/json/848.json','["諫頻甘得罪，一騎入南深。若順吾皇意，即無臣子心。", "織花蠻市布，搗月象州砧。蒙雪知何日，憑樓望北吟。"]'),
('yuding-57','讀齊己上人集','棲蟾','唐','御定全唐诗','yuding','','[]','詩為儒者禪，此格的惟仙。古雅如周頌，清和甚舜弦。',48,'御定全唐詩/json/848.json','["詩為儒者禪，此格的惟仙。古雅如周頌，清和甚舜弦。", "冰生聽瀑句，香發早梅篇。想得吟成夜，文星照楚天。"]'),
('yuding-58','牧童','棲蟾','唐','御定全唐诗','yuding','','[]','牛得自由騎，春風細雨飛。青山青草裏，一笛一蓑衣。',48,'御定全唐詩/json/848.json','["牛得自由騎，春風細雨飛。青山青草裏，一笛一蓑衣。", "日出唱歌去，月明撫掌歸。何人得似爾，無是亦無非。"]'),
('yuding-59','再宿京口禪院','棲蟾','唐','御定全唐诗','yuding','','[]','灘聲依舊水溶溶，岸影參差對梵宮。楚樹七回凋舊葉，',40,'御定全唐詩/json/848.json','["灘聲依舊水溶溶，岸影參差對梵宮。楚樹七回凋舊葉，", "多病支郎念行止，晚年生計轉如蓬。"]'),
('yuding-0','耕田鼓詩','可朋','唐','御定全唐诗','yuding','','[]','農舍田頭鼓，王孫筵上鼓。擊鼓兮皆為鼓，',19,'御定全唐詩/json/849.json','["農舍田頭鼓，王孫筵上鼓。擊鼓兮皆為鼓，"]'),
('yuding-1','賦洞庭','可朋','唐','御定全唐诗','yuding','','[]','周極八百里，凝眸望則勞。水涵天影闊，山拔地形高。',48,'御定全唐詩/json/849.json','["周極八百里，凝眸望則勞。水涵天影闊，山拔地形高。", "賈客停非久，漁翁轉幾遭。颯然風起處，又是鼓波濤。"]'),
('yuding-2','贈方幹','可朋','唐','御定全唐诗','yuding','','[]','盛名傳出自皇州，一舉參差便縮頭。月裏豈無攀桂分，',40,'御定全唐詩/json/849.json','["盛名傳出自皇州，一舉參差便縮頭。月裏豈無攀桂分，", "獨泛短舟何限景，波濤西接洞庭秋。"]'),
('yuding-3','桐花鳥','可朋','唐','御定全唐诗','yuding','','[]','五色毛衣比鳳雛，深花叢裏只如無。',32,'御定全唐詩/json/849.json','["五色毛衣比鳳雛，深花叢裏只如無。", "美人買得偏憐惜，移向金釵重幾銖。"]'),
('yuding-4','句','可朋','唐','御定全唐诗','yuding','','[]','來多不似客，坐久卻垂簾。',88,'御定全唐詩/json/849.json','["來多不似客，坐久卻垂簾。", "虹收千嶂雨，潮展半江天。", "詩因試客分題僻，棋為饒人下著低。", "傷心盡日有啼鳥，獨步殘春空落花。", "唯陪北楚三千客，多話東林十八賢。", "乍當暖景飛仍慢，欲就芳叢舞更高。"]'),
('yuding-5','宿鄭諫議山居','曇域','唐','御定全唐诗','yuding','','[]','堂開星斗邊，大諫采薇還。禽隱石中樹，月生池上山。',48,'御定全唐詩/json/849.json','["堂開星斗邊，大諫采薇還。禽隱石中樹，月生池上山。", "涼風吹詠思，幽語隔禪關。莫擬歸城計，終妨此地閑。"]'),
('yuding-6','懷齊己','曇域','唐','御定全唐诗','yuding','','[]','鬢髯秋景兩蒼蒼，靜對茅齋一炷香。病後身心俱澹泊，',40,'御定全唐詩/json/849.json','["鬢髯秋景兩蒼蒼，靜對茅齋一炷香。病後身心俱澹泊，", "猶喜深交有支遁，時時音信到松房。"]'),
('yuding-7','贈島雲禪師','曇域','唐','御定全唐诗','yuding','','[]','遠庵枯葉滿，群鹿亦相隨。頂骨生新發，庭松長舊枝。',48,'御定全唐詩/json/849.json','["遠庵枯葉滿，群鹿亦相隨。頂骨生新發，庭松長舊枝。", "禪高太白月，行出祖師碑。亂後潛來此，南人總不知。"]'),
('yuding-8','垓下懷古','棲一','唐','御定全唐诗','yuding','','[]','緬想咸陽事可嗟，楚歌哀怨思無涯。八千子弟歸何處，',40,'御定全唐詩/json/849.json','["緬想咸陽事可嗟，楚歌哀怨思無涯。八千子弟歸何處，", "拔山力盡烏江水，今古悠悠空浪花。"]'),
('yuding-9','武昌懷古','棲一','唐','御定全唐诗','yuding','','[]','戰國城池盡悄然，昔人遺跡遍山川。笙歌罷吹幾多日，',40,'御定全唐詩/json/849.json','["戰國城池盡悄然，昔人遺跡遍山川。笙歌罷吹幾多日，", "堪嗟世事如流水，空見蘆花一釣船。"]'),
('yuding-10','聖果寺','處默','唐','御定全唐诗','yuding','','[]','路自中峰上，盤回出薜蘿。到江吳地盡，隔岸越山多。',48,'御定全唐詩/json/849.json','["路自中峰上，盤回出薜蘿。到江吳地盡，隔岸越山多。", "古木叢青靄，遙天浸白波。下方城郭近，鐘磬雜笙歌。"]'),
('yuding-11','送僧遊西域','處默','唐','御定全唐诗','yuding','','[]','一盂兼一錫，只此度流沙。野性雖為客，禪心即是家。',48,'御定全唐詩/json/849.json','["一盂兼一錫，只此度流沙。野性雖為客，禪心即是家。", "寺披雲嶠雪，路入曉天霞。自說游諸國，回應歲月賒。"]'),
('yuding-12','遠煙','處默','唐','御定全唐诗','yuding','','[]','靄靄前山上，凝光滿薜蘿。高風吹不盡，遠樹得偏多。',48,'御定全唐詩/json/849.json','["靄靄前山上，凝光滿薜蘿。高風吹不盡，遠樹得偏多。", "翠與晴雲合，輕將淑氣和。正堪流野目，朱閣意如何。"]'),
('yuding-13','螢','處默','唐','御定全唐诗','yuding','','[]','熠熠與娟娟，池塘竹樹邊。亂飛如拽火，成聚卻無煙。',48,'御定全唐詩/json/849.json','["熠熠與娟娟，池塘竹樹邊。亂飛如拽火，成聚卻無煙。", "微雨灑不滅，輕風吹欲燃。昔時書案上，頻把作囊懸。"]'),
('yuding-14','憶廬山舊居','處默','唐','御定全唐诗','yuding','','[]','粗衣糲食老煙霞，勉把衰顏惜歲華。獨鶴只為山客伴，',40,'御定全唐詩/json/849.json','["粗衣糲食老煙霞，勉把衰顏惜歲華。獨鶴只為山客伴，", "明月清風舊相得，十年歸恨可能賒。"]'),
('yuding-15','題棲霞寺僧房','處默','唐','御定全唐诗','yuding','','[]','名山不取買山錢，任構花宮近碧巔。松檜老依雲裏寺，',40,'御定全唐詩/json/849.json','["名山不取買山錢，任構花宮近碧巔。松檜老依雲裏寺，", "欲結茅庵共師住，肯饒多少薜蘿煙。"]'),
('yuding-16','山中作','處默','唐','御定全唐诗','yuding','','[]','席簾高卷枕高欹，門掩垂蘿蘸碧溪。',32,'御定全唐詩/json/849.json','["席簾高卷枕高欹，門掩垂蘿蘸碧溪。", "閑把史書眠一覺，起來山日過松西。"]'),
('yuding-17','織婦','處默','唐','御定全唐诗','yuding','','[]','蓬鬢蓬門積恨多，夜闌燈下不停梭。',32,'御定全唐詩/json/849.json','["蓬鬢蓬門積恨多，夜闌燈下不停梭。", "成縑猶自陪錢納，未直青樓一曲歌。"]'),
('yuding-18','句','處默','唐','御定全唐诗','yuding','','[]','太平時節無人看，雪刃閑封滿匣塵。（《劍》，',21,'御定全唐詩/json/849.json','["太平時節無人看，雪刃閑封滿匣塵。（《劍》，"]'),
('yuding-19','秋日閒居','修睦','唐','御定全唐诗','yuding','','[]','是事不相關，誰人似此閑。捲簾當白晝，移榻對青山。',48,'御定全唐詩/json/849.json','["是事不相關，誰人似此閑。捲簾當白晝，移榻對青山。", "野鶴眠松上，秋苔長雨間。嶽僧頻有信，昨日得書還。"]'),
('yuding-20','宿岳陽開元寺','修睦','唐','御定全唐诗','yuding','','[]','竟夕憑虛檻，何當興歎頻。往來人自老，今古月常新。',48,'御定全唐詩/json/849.json','["竟夕憑虛檻，何當興歎頻。往來人自老，今古月常新。", "風逆沈魚唱，松疏露鶴身。無眠鐘又動，幾客在迷津。"]'),
('yuding-21','送邊將','修睦','唐','御定全唐诗','yuding','','[]','人盡有離別，而君獨可嗟。言將身報國，敢望祿榮家。',48,'御定全唐詩/json/849.json','["人盡有離別，而君獨可嗟。言將身報國，敢望祿榮家。", "戰思風吹野，鄉心月照沙。歸期定何日，塞北樹無花。"]'),
('yuding-22','雪中送人北游','修睦','唐','御定全唐诗','yuding','','[]','然知心去速，其奈雪飛頻。莫喜無危道，雖平更陷人。',48,'御定全唐詩/json/849.json','["然知心去速，其奈雪飛頻。莫喜無危道，雖平更陷人。", "遠郊光接漢，曠野色通秦。此去迢遙極，卻回應過春。"]'),
('yuding-23','落葉','修睦','唐','御定全唐诗','yuding','','[]','雨過閒田地，重重落葉紅。翻思向春日，肯信有秋風。',48,'御定全唐詩/json/849.json','["雨過閒田地，重重落葉紅。翻思向春日，肯信有秋風。", "幾處隨流水，河邊亂暮空。只應松自立，而不與君同。"]'),
('yuding-24','落花','修睦','唐','御定全唐诗','yuding','','[]','一片又一片，等閒苔面紅。不能延數日，開亦是春風。',48,'御定全唐詩/json/849.json','["一片又一片，等閒苔面紅。不能延數日，開亦是春風。", "公子歌聲歇，詩人眼界空。遙思故山下，經雨兩三叢。"]'),
('yuding-25','題田道者院','修睦','唐','御定全唐诗','yuding','','[]','入門空寂寂，真個出家兒。有行鬼不見，無心人謂癡。',48,'御定全唐詩/json/849.json','["入門空寂寂，真個出家兒。有行鬼不見，無心人謂癡。", "古岩寒柏對，流水落花隨。欲別一何懶，相從所恨遲。"]'),
('yuding-26','東林寺','修睦','唐','御定全唐诗','yuding','','[]','欲去不忍去，徘徊吟繞廊。水光秋澹蕩，僧好語尋常。',48,'御定全唐詩/json/849.json','["欲去不忍去，徘徊吟繞廊。水光秋澹蕩，僧好語尋常。", "碑古苔文疊，山晴鐘韻長。翻思南嶽上，欠此白蓮香。"]'),
('yuding-27','寄貫休上人','修睦','唐','御定全唐诗','yuding','','[]','常語亦關詩，常流安得知。楚郊來未久，吳地住多時。',48,'御定全唐詩/json/849.json','["常語亦關詩，常流安得知。楚郊來未久，吳地住多時。", "立月無人近，歸林有鶴隨。所居渾不遠，相識偶然遲。"]'),
('yuding-28','喜僧友到','修睦','唐','御定全唐诗','yuding','','[]','十年消息斷，空使夢煙蘿。嵩嶽幾時下，洞庭何日過。',48,'御定全唐詩/json/849.json','["十年消息斷，空使夢煙蘿。嵩嶽幾時下，洞庭何日過。", "瓶幹離澗久，衲壞臥雲多。意欲相留住，游方肯舍麼。"]'),
('yuding-29','懷虛中上人','修睦','唐','御定全唐诗','yuding','','[]','簷雨滴更殘，思君安未安。湘川聞不遠，道路去尋難。',48,'御定全唐詩/json/849.json','["簷雨滴更殘，思君安未安。湘川聞不遠，道路去尋難。", "吟鬢霜應蝕，禪衣雪漸寒。倚松因獨立，一鳥下江幹。"]'),
('yuding-30','簡寂觀','修睦','唐','御定全唐诗','yuding','','[]','正同高士坐煙霞，思著閑忙又是嗟。碧岫觀中人似鶴，',40,'御定全唐詩/json/849.json','["正同高士坐煙霞，思著閑忙又是嗟。碧岫觀中人似鶴，", "莫道此間無我分，遺民長在惠持家。"]'),
('yuding-31','睡起作','修睦','唐','御定全唐诗','yuding','','[]','長空秋雨歇，睡起覺精神。看水看山坐，無名無利身。',48,'御定全唐詩/json/849.json','["長空秋雨歇，睡起覺精神。看水看山坐，無名無利身。", "偈吟諸祖意，茶碾去年春。此外誰相識，孤雲到砌頻。"]'),
('yuding-32','賣松者','修睦','唐','御定全唐诗','yuding','','[]','求利有何限，將松入市來。直饒人買去，也向柳邊栽。',48,'御定全唐詩/json/849.json','["求利有何限，將松入市來。直饒人買去，也向柳邊栽。", "細葉猶粘雪，孤根尚惹苔。知君用心錯，舉世重花開。"]'),
('yuding-33','思齊己上人','修睦','唐','御定全唐诗','yuding','','[]','同人與流俗，相謂好襟靈。有口不他說，長年自誦經。',48,'御定全唐詩/json/849.json','["同人與流俗，相謂好襟靈。有口不他說，長年自誦經。", "水聲秋後石，山色晚來庭。客問修何法，指松千歲青。"]'),
('yuding-34','送玄泰禪師','修睦','唐','御定全唐诗','yuding','','[]','去去去何住，一盂兼一瓶。水邊寒草白，島外晚峰青。',48,'御定全唐詩/json/849.json','["去去去何住，一盂兼一瓶。水邊寒草白，島外晚峰青。", "宿處林聞虎，行時天有星。回期誰可定，浮世重看經。"]'),
('yuding-35','三生石','修睦','唐','御定全唐诗','yuding','','[]','聖跡誰會得，每到亦徘徊。一尚不可得，三從何處來。',48,'御定全唐詩/json/849.json','["聖跡誰會得，每到亦徘徊。一尚不可得，三從何處來。", "清宵寒露滴，白晝野雲隈。應是表靈異，凡情安可猜。"]'),
('yuding-36','題僧夢微房','修睦','唐','御定全唐诗','yuding','','[]','東海日未出，九衢人已行。吾師無事坐，苔蘚入門生。',48,'御定全唐詩/json/849.json','["東海日未出，九衢人已行。吾師無事坐，苔蘚入門生。", "雨過閑花落，風來古木聲。天臺頻說法，石壁欠題名。"]'),
('yuding-37','秋台作','修睦','唐','御定全唐诗','yuding','','[]','獨上高樓上，客情何物同。孤雲無定處，長日信秋風。',48,'御定全唐詩/json/849.json','["獨上高樓上，客情何物同。孤雲無定處，長日信秋風。", "兄弟多年別，關河此夕中。到頭歸去是，免使歎洪蒙。"]'),
('yuding-38','懷故園','修睦','唐','御定全唐诗','yuding','','[]','故園歸未得，此日意何傷。獨坐水邊草，水流春日長。',24,'御定全唐詩/json/849.json','["故園歸未得，此日意何傷。獨坐水邊草，水流春日長。"]'),
('yuding-39','謝武肅王','無作','唐','御定全唐诗','yuding','','[]','雲鶴性孤單，爭堪名利關。銜恩雖入國，辭命卻歸山。',24,'御定全唐詩/json/849.json','["雲鶴性孤單，爭堪名利關。銜恩雖入國，辭命卻歸山。"]'),
('yuding-40','哭僧','清尚','唐','御定全唐诗','yuding','','[]','道力自超然，身亡同坐禪。水流元在海，月落不離天。',48,'御定全唐詩/json/849.json','["道力自超然，身亡同坐禪。水流元在海，月落不離天。", "溪白葬時雪，風香焚處煙。世人頻下淚，不見我師玄。"]'),
('yuding-41','投謁齊己','幹康','唐','御定全唐诗','yuding','','[]','隔岸紅塵忙似火，當軒青嶂冷如冰。',32,'御定全唐詩/json/849.json','["隔岸紅塵忙似火，當軒青嶂冷如冰。", "烹茶童子休相問，報導門前是衲僧。"]'),
('yuding-42','賦殘雪','幹康','唐','御定全唐诗','yuding','','[]','六出奇花已住開，郡城相次見樓臺。',32,'御定全唐詩/json/849.json','["六出奇花已住開，郡城相次見樓臺。", "時人莫把和泥看，一片飛從天上來。"]'),
('yuding-43','句','幹康','唐','御定全唐诗','yuding','','[]','鏡湖中有月，處士後無人。荻筍抽高節，鱸魚躍老鱗。',24,'御定全唐詩/json/849.json','["鏡湖中有月，處士後無人。荻筍抽高節，鱸魚躍老鱗。"]'),
('yuding-0','招隱','曇翼','唐','御定全唐诗','yuding','','[]','連峰數千里，修林帶平津。雲起遠山翳，風至□荒榛。',60,'御定全唐詩/json/850.json','["連峰數千里，修林帶平津。雲起遠山翳，風至□荒榛。", "茅茨隱不見，雞鳴知有人。躡磴踐其跡，處處見遺薪。", "乃知百代下，固有上皇民。"]'),
('yuding-1','石橋琪樹','隱求','唐','御定全唐诗','yuding','','[]','山上天將近，人間路漸遙。誰當雲裏見，知欲渡仙橋。',24,'御定全唐詩/json/850.json','["山上天將近，人間路漸遙。誰當雲裏見，知欲渡仙橋。"]'),
('yuding-2','律僧','智遠','唐','御定全唐诗','yuding','','[]','濾水與龕燈，長長護有情。自從青草出，便不下階行。',48,'御定全唐詩/json/850.json','["濾水與龕燈，長長護有情。自從青草出，便不下階行。", "北闕應無夢，南山舊有名。將何喻浮世，惟指浪漚輕。"]'),
('yuding-3','暮春送人','無悶','唐','御定全唐诗','yuding','','[]','折柳亭邊手重攜，江煙澹澹草萋萋。',32,'御定全唐詩/json/850.json','["折柳亭邊手重攜，江煙澹澹草萋萋。", "杜鵑不解離人意，更向落花枝上啼。"]'),
('yuding-4','寒林石屏','無悶','唐','御定全唐诗','yuding','','[]','草堂無物伴身閑，惟有屏風枕簟間。',32,'御定全唐詩/json/850.json','["草堂無物伴身閑，惟有屏風枕簟間。", "本向他山求得石，卻于石上看他山。"]'),
('yuding-5','江上秋志','尚志','唐','御定全唐诗','yuding','','[]','到來江上久，誰念旅遊心。故國無秋信，鄰家有暮砧。',48,'御定全唐詩/json/850.json','["到來江上久，誰念旅遊心。故國無秋信，鄰家有暮砧。", "坐遙翻不睡，愁極卻成吟。即恐髭連鬢，還為白所侵。"]'),
('yuding-6','路','玄寶','唐','御定全唐诗','yuding','','[]','南北東西去，茫茫萬古塵。關河無盡處，風雪有行人。',48,'御定全唐詩/json/850.json','["南北東西去，茫茫萬古塵。關河無盡處，風雪有行人。", "險極山通蜀，平多地入秦。營營名利者，來往豈辭頻。"]'),
('yuding-7','贈智舟三藏','懷浦','唐','御定全唐诗','yuding','','[]','壯歲心難伏，師心伏豈難。尋常獨在院，行坐不離壇。',48,'御定全唐詩/json/850.json','["壯歲心難伏，師心伏豈難。尋常獨在院，行坐不離壇。", "嶽雪當禪暝，松聲入咒寒。更因文字外，多把史書看。"]'),
('yuding-8','初冬旅舍早懷','懷浦','唐','御定全唐诗','yuding','','[]','枕上角聲微，離情未息機。夢回三楚寺，寒入五更衣。',48,'御定全唐詩/json/850.json','["枕上角聲微，離情未息機。夢回三楚寺，寒入五更衣。", "月沒棲禽動，霜晴凍葉飛。自慚行役早，深與道相違。"]'),
('yuding-9','對禦書後一絕','亞棲','唐','御定全唐诗','yuding','','[]','通神筆法得玄門，親入長安謁至尊。',32,'御定全唐詩/json/850.json','["通神筆法得玄門，親入長安謁至尊。", "莫怪出來多意氣，草書曾悅聖明君。"]'),
('yuding-10','題英禪師','亞棲','唐','御定全唐诗','yuding','','[]','將知德行異尋常，每見持經在道場。',32,'御定全唐詩/json/850.json','["將知德行異尋常，每見持經在道場。", "欲識用心精潔處，一瓶秋水一爐香。"]'),
('yuding-11','別友人','惟審','唐','御定全唐诗','yuding','','[]','一身無定處，萬里獨銷魂。芳草迷歸路，春衣滴淚痕。',48,'御定全唐詩/json/850.json','["一身無定處，萬里獨銷魂。芳草迷歸路，春衣滴淚痕。", "幾時休旅食，向夜宿江村。欲識異鄉苦，空山啼暮猿。"]'),
('yuding-12','賦得聞曉鶯啼','惟審','唐','御定全唐诗','yuding','','[]','捲簾清夢後，芳樹引流鶯。隔葉傳春意，穿花送曉聲。',48,'御定全唐詩/json/850.json','["捲簾清夢後，芳樹引流鶯。隔葉傳春意，穿花送曉聲。", "未調雲路翼，空負桂枝情。莫盡關關興，羈愁正厭生。"]'),
('yuding-13','春日旅懷呈知己','惟審','唐','御定全唐诗','yuding','','[]','生涯萬事有蒼蒼，應任流萍便越鄉。春水獨行人漸遠，',40,'御定全唐詩/json/850.json','["生涯萬事有蒼蒼，應任流萍便越鄉。春水獨行人漸遠，", "不為知音皆鮑叔，信誰江上去茫茫。"]'),
('yuding-14','劍客','慕幽','唐','御定全唐诗','yuding','','[]','去住知何處，空將一劍行。殺人雖取次，為事愛公平。',48,'御定全唐詩/json/850.json','["去住知何處，空將一劍行。殺人雖取次，為事愛公平。", "戟立嗔髭鬢，星流忿眼睛。曉來湘市說，拂曙別遼城。"]'),
('yuding-15','酬和友人見寄','慕幽','唐','御定全唐诗','yuding','','[]','勞歌好自看，終久偶齊桓。五字若教易，一名爭得難。',48,'御定全唐詩/json/850.json','["勞歌好自看，終久偶齊桓。五字若教易，一名爭得難。", "侵窗紅樹老，蔭砌雪花殘。莫效齊僚屬，東歸剪釣竿。"]'),
('yuding-16','冬日淮上別文上人','慕幽','唐','御定全唐诗','yuding','','[]','家國各萬里，同吟六七年。可堪隨北雁，迢遞向南天。',48,'御定全唐詩/json/850.json','["家國各萬里，同吟六七年。可堪隨北雁，迢遞向南天。", "水共行人遠，山將落日連。春淮有雙鯉，莫忘尺書傳。"]'),
('yuding-17','柳','慕幽','唐','御定全唐诗','yuding','','[]','今古憑君一贈行，幾回折盡複重生。五株斜傍淵明宅，',40,'御定全唐詩/json/850.json','["今古憑君一贈行，幾回折盡複重生。五株斜傍淵明宅，", "隋皇堤畔依依在，曾惹當時歌吹聲。"]'),
('yuding-18','三峽聞猿','慕幽','唐','御定全唐诗','yuding','','[]','誰向茲來不恨生，聲聲都是斷腸聲。七千裏外一家住，',40,'御定全唐詩/json/850.json','["誰向茲來不恨生，聲聲都是斷腸聲。七千裏外一家住，", "憑君且聽哀吟好，會待青雲道路平。"]'),
('yuding-19','燈','慕幽','唐','御定全唐诗','yuding','','[]','鐘斷危樓鳥不飛，熒熒何處最相宜。香然水寺僧開卷，',40,'御定全唐詩/json/850.json','["鐘斷危樓鳥不飛，熒熒何處最相宜。香然水寺僧開卷，", "孫康勤苦誰能念，少減餘光借與伊。"]'),
('yuding-20','寶琴','釋彪','唐','御定全唐诗','yuding','','[]','吾有一寶琴，價重雙南金。刻作龍鳳象，彈為山水音。',48,'御定全唐詩/json/850.json','["吾有一寶琴，價重雙南金。刻作龍鳳象，彈為山水音。", "星從徽裏發，風來弦上吟。鐘期不可遇，誰辨曲中心。"]'),
('yuding-21','《觀大駕出敘事寄懷','法輪','唐','御定全唐诗','yuding','','[]','紫台宵漏竭，青門曙鼓通。輕霞照複道，徐吹轉相風。',120,'御定全唐詩/json/850.json','["紫台宵漏竭，青門曙鼓通。輕霞照複道，徐吹轉相風。", "玉鸞光萬騎，金輿鬱五戎。鳴笳猶度闕，清蹕尚喧宮。", "雲旗亂陌紫，羽旆雜塵紅。百城歸北麗，兩漢久慚雄。", "吾曹陋薄技，餘慶洽微躬。平源已起洛，印手亦還豐。", "得奉衣冠盛，仍觀書軌同。猶言待封告，未忍向華嵩。"]'),
('yuding-22','中秋旅懷','尚能','唐','御定全唐诗','yuding','','[]','所畜惟騷雅，兼之得固窮。望鄉連北斗，聽雨帶西風。',48,'御定全唐詩/json/850.json','["所畜惟騷雅，兼之得固窮。望鄉連北斗，聽雨帶西風。", "稼穡村坊遠，煙波路徑通。冥搜清絕句，恰似有神功。"]'),
('yuding-23','句','尚能','唐','御定全唐诗','yuding','','[]','霜洲楓落盡，月館竹生寒。',12,'御定全唐詩/json/850.json','["霜洲楓落盡，月館竹生寒。"]'),
('yuding-24','題伍相廟','常雅','唐','御定全唐诗','yuding','','[]','蒼蒼古廟映林巒，漠漠煙霞覆古壇。',32,'御定全唐詩/json/850.json','["蒼蒼古廟映林巒，漠漠煙霞覆古壇。", "精魄不知何處在，威風猶入浙江寒。"]'),
('yuding-25','懷舊山','滄浩','唐','御定全唐诗','yuding','','[]','一坐西林寺，從來未下山。不因尋長者，無事到人間。',48,'御定全唐詩/json/850.json','["一坐西林寺，從來未下山。不因尋長者，無事到人間。", "宿雨愁為客，寒花笑未還。空懷舊山月，童子誦經閑。"]'),
('yuding-26','題慧山泉','若水','唐','御定全唐诗','yuding','','[]','石脈綻寒光，松根噴曉涼。注瓶雲母滑，漱齒茯苓香。',48,'御定全唐詩/json/850.json','["石脈綻寒光，松根噴曉涼。注瓶雲母滑，漱齒茯苓香。", "野客偷煎茗，山僧借淨床。安禪何所問，孤月在中央。"]'),
('yuding-27','題馬跡山','文鑒','唐','御定全唐诗','yuding','','[]','瀛洲西望沃洲山，山在平湖縹緲間。',32,'御定全唐詩/json/850.json','["瀛洲西望沃洲山，山在平湖縹緲間。", "常說使君千里馬，至今龍跡尚堪攀。"]'),
('yuding-0','和禦制遊慈恩寺','慈恩寺沙門','唐','御定全唐诗','yuding','','[]','皇風扇祇樹，至德茂禪林。仙華曜日彩，神幡曳遠陰。',48,'御定全唐詩/json/851.json','["皇風扇祇樹，至德茂禪林。仙華曜日彩，神幡曳遠陰。", "綺殿籠霞影，飛閣出雲心。細草希慈澤，恩光重更深。"]'),
('yuding-1','贈賈松先輩','水心寺僧','唐','御定全唐诗','yuding','','[]','嵯峨山上石，歲歲色長新。若使盡成寶，誰為知己人。',24,'御定全唐詩/json/851.json','["嵯峨山上石，歲歲色長新。若使盡成寶，誰為知己人。"]'),
('yuding-2','古梅','無名釋','唐','御定全唐诗','yuding','','[]','火虐風饕水漬根，霜皴雪皺古苔痕。',32,'御定全唐詩/json/851.json','["火虐風饕水漬根，霜皴雪皺古苔痕。", "東風未肯隨寒暑，又蘖清香與返魂。"]'),
('yuding-3','月','南唐失名僧','唐','御定全唐诗','yuding','','[]','徐徐東海出，漸漸上天衢。此夜一輪滿，清光何處無。',24,'御定全唐詩/json/851.json','["徐徐東海出，漸漸上天衢。此夜一輪滿，清光何處無。"]'),
('yuding-4','武肅王有旨，石橋設齋會，進一詩，共六首','吳越僧','唐','御定全唐诗','yuding','','[]','南有天臺事可尊，孕靈含秀獨超群。重重曲澗侵危石，',240,'御定全唐詩/json/851.json','["南有天臺事可尊，孕靈含秀獨超群。重重曲澗侵危石，", "當知此界非凡界，一道幽奇各自分。", "仙源佛窟有天臺，今古嘉名遍九垓。石磴嵌空神匠出，", "一等翹誠依此處，自然靈貺作梯媒。", "智泉福海莫能逾，親自王恩運睿謨。感現盡冥心境界，", "勝妙重重惟禱祝，永資軍庶息災虞。", "淩晨迎請倍精誠，親散鮮花異處清。羅漢攀枝呈梵相，", "都為王心標意切，滿空盈月瑞分明。", "幡花寶蓋滿青川，祈禱迎來聖半千。莫道勝緣無影響，", "何必更尋兜率去，重重靈應事昭然。", "登雲步嶺涉煙程，好景隨心次第生。聖者已符祥瑞事，", "願滿事圓歸去路，便風相送片帆輕。"]'),
('yuding-5','題戶詩','唐末僧','唐','御定全唐诗','yuding','','[]','枕有思鄉淚，門無問疾人。塵埋床下履，風動架頭巾。',24,'御定全唐詩/json/851.json','["枕有思鄉淚，門無問疾人。塵埋床下履，風動架頭巾。"]'),
('yuding-6','句','神迥','唐','御定全唐诗','yuding','','[]','鴉鳴東牖曙，草秀南湖春。',12,'御定全唐詩/json/851.json','["鴉鳴東牖曙，草秀南湖春。"]'),
('yuding-7','句','可隆','唐','御定全唐诗','yuding','','[]','萬般思後行，一失廢前功。',12,'御定全唐詩/json/851.json','["萬般思後行，一失廢前功。"]'),
('yuding-8','句','爾鳥','唐','御定全唐诗','yuding','','[]','鯨目光燒半海紅，鼇頭浪蹙掀天白。',16,'御定全唐詩/json/851.json','["鯨目光燒半海紅，鼇頭浪蹙掀天白。"]'),
('yuding-9','句','元礎','唐','御定全唐诗','yuding','','[]','寺隔殘潮去。',24,'御定全唐詩/json/851.json','["寺隔殘潮去。", "采藥過泉聲。", "林塘秋半宿，風雨夜深來。"]'),
('yuding-10','句','悟清','唐','御定全唐诗','yuding','','[]','鳥歸花影動，魚沒浪痕圓。',12,'御定全唐詩/json/851.json','["鳥歸花影動，魚沒浪痕圓。"]'),
('yuding-11','句','契盈','唐','御定全唐诗','yuding','','[]','三千裏外一條水，十二時中兩度潮。',16,'御定全唐詩/json/851.json','["三千裏外一條水，十二時中兩度潮。"]'),
('yuding-12','句','淡然','唐','御定全唐诗','yuding','','[]','到處自鑿井，不能飲常流。',12,'御定全唐詩/json/851.json','["到處自鑿井，不能飲常流。"]'),
('yuding-13','句','庭實','唐','御定全唐诗','yuding','','[]','吟中雙鬢白，笑裏一生貧。',12,'御定全唐詩/json/851.json','["吟中雙鬢白，笑裏一生貧。"]'),
('yuding-14','句','知業','唐','御定全唐诗','yuding','','[]','接岸橋通何處路，倚欄人是阿誰家。',16,'御定全唐詩/json/851.json','["接岸橋通何處路，倚欄人是阿誰家。"]'),
('yuding-15','句','雲容','唐','御定全唐诗','yuding','','[]','木末上明星。',6,'御定全唐詩/json/851.json','["木末上明星。"]'),
('yuding-16','句','玄幽','唐','御定全唐诗','yuding','','[]','三萬蓮經三十春，半生不蹋院門塵。',16,'御定全唐詩/json/851.json','["三萬蓮經三十春，半生不蹋院門塵。"]'),
('yuding-17','句','志定','唐','御定全唐诗','yuding','','[]','惟有樽前今夜月，當時曾照墮樓人。',32,'御定全唐詩/json/851.json','["惟有樽前今夜月，當時曾照墮樓人。", "梧桐葉老蟬聲死，一夜洞庭波上風。"]'),
('yuding-18','句','靈准','唐','御定全唐诗','yuding','','[]','晴看漢水廣，秋覺峴山高。',12,'御定全唐詩/json/851.json','["晴看漢水廣，秋覺峴山高。"]'),
('yuding-19','句','荊州僧','唐','御定全唐诗','yuding','','[]','犬熟護鄰房。',6,'御定全唐詩/json/851.json','["犬熟護鄰房。"]'),
('yuding-0','答宋之問','司馬承禎','唐','御定全唐诗','yuding','','[]','時既暮兮節欲春，山林寂兮懷幽人。登奇峰兮望白雲，',40,'御定全唐詩/json/852.json','["時既暮兮節欲春，山林寂兮懷幽人。登奇峰兮望白雲，", "不見其人誰與言，歸坐彈琴思逾遠。"]'),
('yuding-1','醉吟三首','張氳','唐','御定全唐诗','yuding','','[]','去歲無田種，今春乏酒材。從他花鳥笑，佯醉臥樓臺。',72,'御定全唐詩/json/852.json','["去歲無田種，今春乏酒材。從他花鳥笑，佯醉臥樓臺。", "下調無人睬，高心又被瞋。不知時俗意，教我若為人。", "入市非求利，過朝不為名。有時隨俗物，相伴且營營。"]'),
('yuding-2','洗心','司馬退之','唐','御定全唐诗','yuding','','[]','不踐名利道，始覺塵土腥。不味稻粱食，始覺精神清。',108,'御定全唐詩/json/852.json','["不踐名利道，始覺塵土腥。不味稻粱食，始覺精神清。", "羅浮奔走外，日月無短明。山瘦松亦勁，鶴老飛更輕。", "逍遙此中客，翠發皆長生。草木多古色，雞犬無新聲。", "君有出俗志，不貪英雄名。傲然脫冠帶，改換人間情。", "去矣丹霄路，向曉雲冥冥。"]'),
('yuding-3','夜醉臥街','裴翛然','唐','御定全唐诗','yuding','','[]','遮莫冬冬動，須傾滿滿杯。金吾如借問，但道玉山頹。',24,'御定全唐詩/json/852.json','["遮莫冬冬動，須傾滿滿杯。金吾如借問，但道玉山頹。"]'),
('yuding-4','謁堯帝廟','軒轅彌明','唐','御定全唐诗','yuding','','[]','祖龍開國盡遐荒，廟建唐堯鎮此邦。山卷白雲朝帝座，',40,'御定全唐詩/json/852.json','["祖龍開國盡遐荒，廟建唐堯鎮此邦。山卷白雲朝帝座，", "瞻仰威靈共回首，紫霞深處鎖軒窗。"]'),
('yuding-5','山居','陳寡言','唐','御定全唐诗','yuding','','[]','照水冰如鑒，掃雪玉為塵。何須問今古，便是上皇人。',56,'御定全唐詩/json/852.json','["照水冰如鑒，掃雪玉為塵。何須問今古，便是上皇人。", "醉臥茅堂不閉關，覺來開眼見青山。", "松花落處宿猿在，麋鹿群群林際還。"]'),
('yuding-6','臨化示弟子','陳寡言','唐','御定全唐诗','yuding','','[]','我本無形暫有形，偶來人世逐營營。',32,'御定全唐詩/json/852.json','["我本無形暫有形，偶來人世逐營營。", "輪回債負今還畢，搔首翛然歸上清。"]'),
('yuding-7','元白席上作','李升','唐','御定全唐诗','yuding','','[]','生在儒家遇太平，懸纓垂帶布衣輕。',32,'御定全唐詩/json/852.json','["生在儒家遇太平，懸纓垂帶布衣輕。", "誰能世路趨名利，臣事玉皇歸上清。"]'),
('yuding-8','一字至七字詩：書','範堯佐','唐','御定全唐诗','yuding','','[]','書。憑雁，寄魚。出王屋，入匡廬。文生益智，',21,'御定全唐詩/json/852.json','["書。憑雁，寄魚。出王屋，入匡廬。文生益智，"]'),
('yuding-9','言志獻浙東廉訪辭召','徐靈府','唐','御定全唐诗','yuding','','[]','野性歌三樂，皇恩出九重。那煩紫宸命，遠下白雲峰。',48,'御定全唐詩/json/852.json','["野性歌三樂，皇恩出九重。那煩紫宸命，遠下白雲峰。", "多愧書傳鶴，深慚紙畫龍。將何佐明主，甘老在岩松。"]'),
('yuding-10','自詠二首','徐靈府','唐','御定全唐诗','yuding','','[]','寂寂凝神太極初，無心應物等空虛。',64,'御定全唐詩/json/852.json','["寂寂凝神太極初，無心應物等空虛。", "性修自性非求得，欲識真人只是渠。", "學道全真在此生，何須待死更求生。", "今生不了無生理，縱複生知那處生。"]'),
('yuding-11','留觀中詩二首','吳子來','唐','御定全唐诗','yuding','','[]','終日草堂間，清風常往還。耳無塵事擾，心有玩雲閑。',80,'御定全唐詩/json/852.json','["終日草堂間，清風常往還。耳無塵事擾，心有玩雲閑。", "對酒惟思月，餐松不厭山。時時吟內景，自合駐童顏。", "此生此物當生涯，白石青松便是家。", "對月臥雲如野鹿，時時買酒醉煙霞。"]'),
('yuding-0','遊仙二十四首','吳筠','唐','御定全唐诗','yuding','','[]','啟冊觀往載，搖懷考今情。終古已寂寂，舉世何營營。',516,'御定全唐詩/json/853.json','["啟冊觀往載，搖懷考今情。終古已寂寂，舉世何營營。", "悟彼眾仙妙，超然含至精。凝神契沖玄，化服淩太清。", "心同宇宙廣，體合雲霞輕。翔風吹羽蓋，慶霄拂霓旌。", "龍駕朝紫微，後天保令名。豈如寰中士，軒冕矜暫榮。", "鸞鳳棲瑤林，雕鶚集平楚。飲啄本殊好，翱翔終異所。", "吾方遺喧囂，立節慕高舉。解茲區中戀，結彼霄外侶。", "誰謂天路遐，感通自無阻。", "湣俗從遷謝，尋仙去淪沒。三元有真人，與我生道骨。", "淩晨吸丹景，入夜飲黃月。百關彌調暢，方寸益清越。", "棲神合虛無，洞覽周恍惚。不覺隨玉皇，焚香詣金闕。", "西龜初定籙，東華已校名。三官無遺譴，七祖升雲輧。", "體妙塵累隔，心微玄化並。一朝出天地，億載猶童嬰。", "使我齊浩劫，蕭蕭宴玉清。", "怡神在靈府，皎皎含清澄。仙經不吾欺，輕舉信有征。", "疇昔希道念，而今果天矜。豈非陰功著，乃致白日升。", "焉用過洞府，吾其越朱陵。", "高真誠寥邈，道合不我遺。孰謂姑射遠，神人可同嬉。", "結駕從之遊，飄飄出天垂。不理人自化，神凝物無疵。", "因知至精感，足以和四時。", "碧海廣無際，三山高不極。金台羅中天，羽客恣遊息。", "霞液朝可飲，虹芝晚堪食。嘯歌自忘心，騰舉寧假翼。", "保壽同三光，安能紀千億。", "將過太帝宮，暫詣扶桑處。真童已相迓，為我清宿霧。", "海若甯洪濤，羲和止奔馭。五雲結層閣，八景動飛輿。"]'),
('yuding-1','覽古十四首','吳筠','唐','御定全唐诗','yuding','','[]','聖人重周濟，明道欲救時。孔席不暇暖，墨突何嘗緇。',552,'御定全唐詩/json/853.json','["聖人重周濟，明道欲救時。孔席不暇暖，墨突何嘗緇。", "興言振頹綱，將以有所維。君臣恣淫惑，風俗日凋衰。", "三代業遽隕，七雄遂交馳。庶物墜塗炭，區中若棼絲。", "秦皇燎儒術，方冊靡孑遺。大漢曆五葉，斯文複崇推。", "乃驗經籍道，與世同屯夷。弛張固天意，設教安能持。", "興亡道之運，否泰理所全。奈何淳古風，既往不復旋。", "三皇已散朴，五帝初尚賢。王業與霸功，浮偽日以宣。", "忠誠及狙詐，淆混安可甄。餘智入九霄，守愚淪重泉。", "永懷巢居時，感涕徒泫然。", "棟宇代巢穴，其來自三皇。跡生固為累，經始增百王。", "瑤台既滅夏，瓊室複隕湯。覆車世不悟，秦氏興阿房。", "繼踵迷反正，漢家崇建章。力役弊萬人，瑰奇殫八方。", "徇志仍未極，促齡已雲亡。侈靡竟何在，荊榛生廟堂。", "閒居覽前載，惻彼商與秦。所殘必忠良，所寶皆凶嚚。", "昵諛方自聖，不悟禍滅身。箕子作周輔，孫通為漢臣。", "洪范及禮儀，後王用經綸。", "吾觀采苓什，複感青蠅詩。讒佞亂忠孝，古今同所悲。", "奸邪起狡猾，骨肉相殘夷。漢儲殞江充，晉嗣滅驪姬。", "天性猶可間，君臣固其宜。子胥烹吳鼎，文種斷越鈹。", "屈原沈湘流，厥戚咸自貽。何不若範蠡，扁舟無還期。", "嘗稽真仙道，清寂祛眾煩。秦皇及漢武，焉得遊其藩。", "情擾萬機屑，位驕四海尊。既欲先宇宙，仍規後乾坤。", "崇高與久遠，物莫能兩存。矧乃恣所欲，荒淫伐靈根。", "金膏恃延期，玉色複動魂。征戰窮外域，殺傷被中原。"]'),
('yuding-2','步虛詞十首','吳筠','唐','御定全唐诗','yuding','','[]','眾仙仰靈範，肅駕朝神宗。金景相照曜，逶迤升太空。',540,'御定全唐詩/json/853.json','["眾仙仰靈範，肅駕朝神宗。金景相照曜，逶迤升太空。", "七玄已高飛，火煉生珠宮。餘慶逮天壤，平和王道融。", "八威清遊氣，十絕舞祥風。使我躋陽源，其來自陰功。", "逍遙太霞上，真鑒靡不通。", "逸轡登紫清，乘光邁奔電。閬風隔三天，俯視猶可見。", "玉闥摽敞朗，瓊林鬱蔥蒨。自非挺金骨，焉得諧夙願。", "真朋何森森，合景恣遊宴。良會忘淹留，千齡才一眄。", "三宮發明景，朗照同鬱儀。紛然馳飆欻，上采空清蕤。", "令我洞金色，後天耀瓊姿。心協太虛靜，寥寥竟何思。", "玄中有至樂，淡泊終無為。但與正真友，飄颻散遨嬉。", "稟化凝正氣，煉形為真仙。忘心符元宗，返本協自然。", "帝一集絳宮，流光出丹玄。元英與桃君，朗詠長生篇。", "六府煥明霞，百關羅紫煙。飆車涉寥廓，靡靡乘景遷。", "不覺雲路遠，斯須游萬天。", "扶桑誕初景，羽蓋淩晨霞。倏欻造西域，嬉游金母家。", "碧津湛洪源，灼爍敷荷花。煌煌青琳宮，粲粲列玉華。", "真氣溢絳府，自然思無邪。俯矜區中士，夭濁良可嗟。", "瓊台劫萬仞，孤映大羅表。常有三素雲，凝光自飛繞。", "羽幢泛明霞，升降何縹緲。鸞鳳吹雅音，棲翔絳林標。", "玉虛無晝夜，靈景何皎皎。一睹太上京，方知眾天小。", "灼灼青華林，靈風振瓊柯。三光無冬春，一氣清且和。", "回首邇結靈，傾眸親曜羅。豁落制六天，流鈴威百魔。", "綿綿慶不極，誰謂椿齡多。", "高情無侈靡，遇物生華光。至樂無簫歌，金玉音琅琅。"]'),
('yuding-3','登北固山望海','吳筠','唐','御定全唐诗','yuding','','[]','此山鎮京口，迥出滄海湄。躋覽何所見，茫茫潮汐馳。',72,'御定全唐詩/json/853.json','["此山鎮京口，迥出滄海湄。躋覽何所見，茫茫潮汐馳。", "雲生蓬萊島，日出扶桑枝。萬里混一色，焉能分兩儀。", "願言策煙駕，縹緲尋安期。揮手謝人境，吾將從此辭。"]'),
('yuding-4','聽尹煉師彈琴','吳筠','唐','御定全唐诗','yuding','','[]','至樂本太一，幽琴和乾坤。鄭聲久亂雅，此道稀能尊。',84,'御定全唐詩/json/853.json','["至樂本太一，幽琴和乾坤。鄭聲久亂雅，此道稀能尊。", "吾見尹仙翁，伯牙今複存。眾人乘其流，夫子達其源。", "在山峻峰峙，在水洪濤奔。都忘邇城闕，但覺清心魂。", "代乏識微者，幽音誰與論。"]'),
('yuding-5','題龔山人草堂','吳筠','唐','御定全唐诗','yuding','','[]','世人負一美，未肯甘陸沉。獨抱匡濟器，能懷真隱心。',96,'御定全唐詩/json/853.json','["世人負一美，未肯甘陸沉。獨抱匡濟器，能懷真隱心。", "結廬邇城郭，及到雲木深。滅跡慕潁陽，忘機同漢陰。", "啟戶面白水，憑軒對蒼岑。但歌考盤詩，不學梁父吟。", "茲道我所適，感君齊素襟。勖哉龔夫子，勿使囂塵侵。"]'),
('yuding-6','遊廬山五老峰','吳筠','唐','御定全唐诗','yuding','','[]','彭蠡隱深翠，滄波照芙蓉。日初金光滿，景落黛色濃。',121,'御定全唐詩/json/853.json','["彭蠡隱深翠，滄波照芙蓉。日初金光滿，景落黛色濃。", "雲外聽猿鳥，煙中見杉松。自然符幽情，瀟灑愜所從。", "整策務探討，嬉游任從容。玉膏正滴瀝，瑤草多zv茸。", "羽人棲層崖，道合乃一逢。揮手欲輕舉，為余扣瓊鐘。", "空香清人心，正氣信有宗。永用謝物累，吾將乘鸞龍。"]'),
('yuding-7','登廬山東峰觀九江合彭蠡湖','吳筠','唐','御定全唐诗','yuding','','[]','百川灌彭蠡，秋水方浩浩。九派混東流，朝宗合天沼。',96,'御定全唐詩/json/853.json','["百川灌彭蠡，秋水方浩浩。九派混東流，朝宗合天沼。", "寫心陟雲峰，縱目還縹緲。宛轉眾浦分，差池群山繞。", "江妃弄明霞，仿佛呈窈窕。而我臨長風，飄然欲騰矯。", "昔懷滄洲興，斯志果已紹。焉得忘機人，相從洽魚鳥。"]'),
('yuding-8','建業懷古','吳筠','唐','御定全唐诗','yuding','','[]','炎精既失禦，宇內為三分。吳王霸荊越，建都長江濱。',288,'御定全唐詩/json/853.json','["炎精既失禦，宇內為三分。吳王霸荊越，建都長江濱。", "爰資股肱力，以靜淮海民。魏後欲濟師，臨流遽旋軍。", "豈惟限天塹，所忌在有人。惜哉歸命侯，淫虐敗前勳。", "銜璧入洛陽，委躬為晉臣。無何覆宗社，為爾含悲辛。", "俄及永嘉末，中原塞胡塵。五馬浮渡江，一龍躍天津。", "此時成大業，實賴賢縉紳。辟土雖未遠，規模亦振振。", "謝公佐王室，仗節掃偽秦。誰為吳兵孱，用之在有倫。", "荏苒宋齊末，斯須變梁陳。綿曆已六代，興亡互紛綸。", "在德不在險，成敗良有因。高堞複於隍，廣殿摧於榛。", "王風久泯滅，勝氣猶氤氳。皇家一區域，玄化通無垠。", "常言宇宙泰，忽遘雲雷屯。極目梁宋郊，茫茫晦妖氛。", "安得倚天劍，斬茲橫海鱗。徘徊江山暮，感激為誰申。"]'),
('yuding-9','經羊角哀墓作','吳筠','唐','御定全唐诗','yuding','','[]','祇召出江國，路傍旌古墳。伯桃葬角哀，墓近荊將軍。',96,'御定全唐詩/json/853.json','["祇召出江國，路傍旌古墳。伯桃葬角哀，墓近荊將軍。", "神道不相得，稱兵解其紛。幽明信難知，勝負理莫分。", "長呼遂刎頸，此節古未聞。兩賢結情愛，骨肉何足雲。", "感子初並糧，我心正氛氳。遲回駐征騎，不覺空林醺。"]'),
('yuding-10','過天門山懷友','吳筠','唐','御定全唐诗','yuding','','[]','舉帆遇風勁，逸勢如飛奔。縹緲淩煙波，崩騰走川原。',84,'御定全唐詩/json/853.json','["舉帆遇風勁，逸勢如飛奔。縹緲淩煙波，崩騰走川原。", "兩山夾滄江，豁爾開天門。須臾輕舟遠，想像孤嶼存。", "歸路日已近，怡然慰心魂。所經多奇趣，待與吾友論。", "一日如三秋，相思意彌敦。"]'),
('yuding-11','舟中遇柳伯存歸潛山，因有此贈','吳筠','唐','御定全唐诗','yuding','','[]','澆風久成俗，真隱不可求。何悟非所冀，得君在扁舟。',96,'御定全唐詩/json/853.json','["澆風久成俗，真隱不可求。何悟非所冀，得君在扁舟。", "目擊道已存，一笑遂忘言。況觀絕交書，兼睹箴隱文。", "見君浩然心，視世如浮空。君歸潛山曲，我複廬山中。", "形間心不隔，誰能嗟異同。他日或相訪，無辭馭冷風。"]'),
('yuding-12','舟中夜行','吳筠','唐','御定全唐诗','yuding','','[]','榜人識江路，掛席從宵征。莫辨洲渚狀，但聞風波驚。',60,'御定全唐詩/json/853.json','["榜人識江路，掛席從宵征。莫辨洲渚狀，但聞風波驚。", "陰雲正飄颻，落月無光晶。豈不畏艱險，所憑在忠誠。", "何時達遙夜，佇見初日明。"]'),
('yuding-13','晚到湖口見廬山作呈諸故人','吳筠','唐','御定全唐诗','yuding','','[]','夜舟達湖口，漸近廬山側。高高標橫天，隱隱何峻極。',96,'御定全唐詩/json/853.json','["夜舟達湖口，漸近廬山側。高高標橫天，隱隱何峻極。", "石鏡啟晨暉，壚煙凝寒色。旅泊將休暇，歸心已隮陟。", "虛名久為累，使我辭逸域。良願道不違，幽襟果茲得。", "故人在雲嶠，乃複同晏息。鴻飛入青冥，虞氏罷繒弋。"]'),
('yuding-14','苦春霖作寄友','吳筠','唐','御定全唐诗','yuding','','[]','應龍遷南方，霪雨備江幹。俯望失平陸，仰瞻隱崇巒。',120,'御定全唐詩/json/853.json','["應龍遷南方，霪雨備江幹。俯望失平陸，仰瞻隱崇巒。", "陰風斂暄氣，殘月淒已寒。時鳥戢好音，眾芳亦微殘。", "萬流注江湖，日夜增波瀾。數君曠不接，悄然無與歡。", "對酒聊自娛，援琴為誰彈。彈為愁霖引，曲罷仍永歎。", "此歎因感物，誰能識其端。寫懷寄同心，詞極意未殫。"]'),
('yuding-15','酬葉縣劉明府避地廬山言懷詒鄭錄事昆季苟尊師兼見贈之','吳筠','唐','御定全唐诗','yuding','','[]','明哲良罕遇，遇君輒思齊。挺生著天爵，自可析人珪。',180,'御定全唐詩/json/853.json','["明哲良罕遇，遇君輒思齊。挺生著天爵，自可析人珪。", "河洛初沸騰，方期掃虹霓。時命竟未合，安能親鼓鼙。", "從此罷飛鳧，投簪辭割雞。驅車適南土，忠孝兩不暌。", "廬岳鎮江介，于焉愜林棲。入門披彩服，出穀杖紅藜。", "隱令舊閭裏，而今複成躋。鄭公解簪紱，華萼曜松溪。", "賢哉苟征君，滅跡為圃畦。顧已成非薄，忝茲忘筌蹄。", "相觀對綠樽，逸思淩丹梯。道泰我長往，時清君勿迷。", "王孫且無歸，芳草正萋萋。"]'),
('yuding-16','高士詠：混元皇帝','吳筠','唐','御定全唐诗','yuding','','[]','玄元九仙主，道冠三氣初。應物方佐命，棲真亦歸居。',48,'御定全唐詩/json/853.json','["玄元九仙主，道冠三氣初。應物方佐命，棲真亦歸居。", "貽篇訓終古，駕景還太虛。孔父歎猶龍，誰能知所如。"]'),
('yuding-17','高士詠：廣成子','吳筠','唐','御定全唐诗','yuding','','[]','廣成臥雲岫，緬邈逾千齡。軒轅來順風，問道修神形。',48,'御定全唐詩/json/853.json','["廣成臥雲岫，緬邈逾千齡。軒轅來順風，問道修神形。", "至言發玄理，告以從杳冥。三光入無窮，寂默返太寧。"]'),
('yuding-18','高士詠：許先生','吳筠','唐','御定全唐诗','yuding','','[]','大名賢所尚，寶位聖所珍。皎皎許仲武，遺之若纖塵。',48,'御定全唐詩/json/853.json','["大名賢所尚，寶位聖所珍。皎皎許仲武，遺之若纖塵。", "棄瓢箕山下，洗耳潁水濱。物外兩寂寞，獨與玄冥均。"]'),
('yuding-19','高士詠：樊先生','吳筠','唐','御定全唐诗','yuding','','[]','巢父志何遠，潛精人莫知。恥聞讓王事，飲犢方見移。',48,'御定全唐詩/json/853.json','["巢父志何遠，潛精人莫知。恥聞讓王事，飲犢方見移。", "不欲散大樸，焉能為堯師。煉真自輕舉，浮世何足遺。"]'),
('yuding-20','高士詠：柏成子高','吳筠','唐','御定全唐诗','yuding','','[]','大禹受禪讓，子高辭諸侯。退躬適外野，放浪夫何求。',48,'御定全唐詩/json/853.json','["大禹受禪讓，子高辭諸侯。退躬適外野，放浪夫何求。", "萬乘造中畝，一言良見酬。俋俋耕不顧，斯情邈難儔。"]'),
('yuding-21','高士詠：臧丈人','吳筠','唐','御定全唐诗','yuding','','[]','臧叟隱中壑，垂綸心浩然。文王感昔夢，授政道斯全。',48,'御定全唐詩/json/853.json','["臧叟隱中壑，垂綸心浩然。文王感昔夢，授政道斯全。", "一遵無為術，三載淳化宣。功成遂不處，遁跡符沖玄。"]'),
('yuding-22','高士詠：伯夷叔齊','吳筠','唐','御定全唐诗','yuding','','[]','夷齊互崇讓，棄國從所欽。聿來及宗周，乃複非其心。',48,'御定全唐詩/json/853.json','["夷齊互崇讓，棄國從所欽。聿來及宗周，乃複非其心。", "世濁不可處，冰清首陽岑。采薇詠羲農，高義越古今。"]'),
('yuding-23','高士詠：南華真人','吳筠','唐','御定全唐诗','yuding','','[]','南華源道宗，玄遠故不測。動與造化遊，靜合太和息。',48,'御定全唐詩/json/853.json','["南華源道宗，玄遠故不測。動與造化遊，靜合太和息。", "放曠生死外，逍遙神明域。況乃資九丹，輕舉歸太極。"]'),
('yuding-24','高士詠：沖虛真人','吳筠','唐','御定全唐诗','yuding','','[]','沖虛冥至理，體道自玄通。不受子陽祿，但飲壺丘宗。',48,'御定全唐詩/json/853.json','["沖虛冥至理，體道自玄通。不受子陽祿，但飲壺丘宗。", "泠然竟何依，撓挑遊大空。未知風乘我，為是我乘風。"]'),
('yuding-25','高士詠：洞靈真人','吳筠','唐','御定全唐诗','yuding','','[]','亢倉致虛極，潛跡依遠岫。智去愚獨留，日虧歲方就。',48,'御定全唐詩/json/853.json','["亢倉致虛極，潛跡依遠岫。智去愚獨留，日虧歲方就。", "鄉人謀屍祝，不欲聞俎豆。尚賢非至理，堯舜固為陋。"]'),
('yuding-26','高士詠：通玄真人','吳筠','唐','御定全唐诗','yuding','','[]','通玄貴陰德，利物非市朝。悠然大江上，散發揮輕橈。',48,'御定全唐詩/json/853.json','["通玄貴陰德，利物非市朝。悠然大江上，散發揮輕橈。", "已陳緇帷說，複表滄浪謠。滅跡竟何往，遺文獨昭昭。"]'),
('yuding-27','高士詠：文始真人','吳筠','唐','御定全唐诗','yuding','','[]','文始通道源，含光隱關吏。遙欣紫氣浮，果驗真人至。',48,'御定全唐詩/json/853.json','["文始通道源，含光隱關吏。遙欣紫氣浮，果驗真人至。", "玄誥已雲錫，世榮何足累。高步三清境，超登九仙位。"]'),
('yuding-28','高士詠：榮啟期','吳筠','唐','御定全唐诗','yuding','','[]','榮期信知止，帶索無所求。外物非我尚，琴歌自優遊。',48,'御定全唐詩/json/853.json','["榮期信知止，帶索無所求。外物非我尚，琴歌自優遊。", "三樂通至道，一言醉孔丘。居常以待終，嘯傲夫何憂。"]'),
('yuding-29','高士詠：長沮桀溺','吳筠','唐','御定全唐诗','yuding','','[]','賢哉彼沮溺，避世全其真。孔父棲棲者，征途方問津。',48,'御定全唐詩/json/853.json','["賢哉彼沮溺，避世全其真。孔父棲棲者，征途方問津。", "行藏既異跡，語默豈同倫。耦耕長林下，甘與鳥雀群。"]'),
('yuding-30','高士詠：顏闔','吳筠','唐','御定全唐诗','yuding','','[]','世情矜寵譽，效節徼當時。顏闔遵無名，飯牛聊自怡。',48,'御定全唐詩/json/853.json','["世情矜寵譽，效節徼當時。顏闔遵無名，飯牛聊自怡。", "逃聘鄙束帛，鑿壞欣茅茨。托聘囂塵表，放浪世莫知。"]'),
('yuding-31','高士詠：老萊夫妻','吳筠','唐','御定全唐诗','yuding','','[]','萊氏道已遠，懿妻德彌清。一遁囂煩趣，永契雲壑情。',48,'御定全唐詩/json/853.json','["萊氏道已遠，懿妻德彌清。一遁囂煩趣，永契雲壑情。", "祿位非所重，拂衣遂遐征。杳然從我願，豈為物所攖。"]'),
('yuding-32','高士詠：楚狂接輿夫妻','吳筠','唐','御定全唐诗','yuding','','[]','接輿耽沖玄，伉儷亦真逸。傲然辭徵聘，耕績代祿秩。',48,'御定全唐詩/json/853.json','["接輿耽沖玄，伉儷亦真逸。傲然辭徵聘，耕績代祿秩。", "鳳歌誡文宣，龍德遂隱密。一遊峨嵋上，千載保靈術。"]'),
('yuding-33','高士詠：鄭商人弦高','吳筠','唐','御定全唐诗','yuding','','[]','卓哉弦高子，商隱獨摽奇。效謀全鄭國，矯命犒秦師。',48,'御定全唐詩/json/853.json','["卓哉弦高子，商隱獨摽奇。效謀全鄭國，矯命犒秦師。", "賞神義不受，存公滅其私。虛心貴無名，遠跡居九夷。"]'),
('yuding-34','高士詠：柳下惠','吳筠','唐','御定全唐诗','yuding','','[]','展禽抱純粹，滅跡和光塵。高情遺軒冕，降志救世人。',48,'御定全唐詩/json/853.json','["展禽抱純粹，滅跡和光塵。高情遺軒冕，降志救世人。", "百行既無點，三黜道彌真。信謂德超古，豈惟言中倫。"]'),
('yuding-35','高士詠：荷蓧晨門','吳筠','唐','御定全唐诗','yuding','','[]','荷蓧隱耕藝，晨門潛抱關。道尊名可賤，理愜心彌閑。',48,'御定全唐詩/json/853.json','["荷蓧隱耕藝，晨門潛抱關。道尊名可賤，理愜心彌閑。", "混跡是非域，縱懷天地間。同譏孔宣父，匿景杳不還。"]'),
('yuding-36','高士詠：漢陰丈人','吳筠','唐','御定全唐诗','yuding','','[]','野哉漢陰叟，好古遂忘機。抱甕誠亦勤，守朴全道微。',48,'御定全唐詩/json/853.json','["野哉漢陰叟，好古遂忘機。抱甕誠亦勤，守朴全道微。", "子貢初不達，聽言識其非。已為風波人，怳惘失所依。"]'),
('yuding-37','高士詠：于陵夫妻','吳筠','唐','御定全唐诗','yuding','','[]','皎皎於陵子，己賢妻亦明。安茲道德重，顧彼浮華輕。',48,'御定全唐詩/json/853.json','["皎皎於陵子，己賢妻亦明。安茲道德重，顧彼浮華輕。", "琴書不為務，祿位不可榮。逃跡終灌園，誰能達世情。"]'),
('yuding-38','高士詠：項橐','吳筠','唐','御定全唐诗','yuding','','[]','太項冥虛極，微遠不可究。稟量合太初，返形寄童幼。',48,'御定全唐詩/json/853.json','["太項冥虛極，微遠不可究。稟量合太初，返形寄童幼。", "孔父慚至理，顏生賴真授。泛然同萬流，無跡世莫覯。"]'),
('yuding-39','高士詠：太伯延陵','吳筠','唐','御定全唐诗','yuding','','[]','太伯全至讓，遠投蠻夷間。延陵嗣高風，去國不復還。',48,'御定全唐詩/json/853.json','["太伯全至讓，遠投蠻夷間。延陵嗣高風，去國不復還。", "尊榮比蟬翼，道義侔崇山。元規與峻節，曆世無能攀。"]'),
('yuding-40','高士詠：壺丘子','吳筠','唐','御定全唐诗','yuding','','[]','壺丘道為量，玄虛固難知。季咸曜淺術，禦寇初深疑。',48,'御定全唐詩/json/853.json','["壺丘道為量，玄虛固難知。季咸曜淺術，禦寇初深疑。", "至人忘禍福，感變靡定期。太沖杳無朕，元化誰能知。"]'),
('yuding-41','高士詠：段幹木','吳筠','唐','御定全唐诗','yuding','','[]','幹木布衣者，守道杜衡門。德光義且富，肯易王侯尊。',48,'御定全唐詩/json/853.json','["幹木布衣者，守道杜衡門。德光義且富，肯易王侯尊。", "魏主欽其賢，軾廬情亦敦。秦兵遂不舉，高臥為國藩。"]'),
('yuding-42','高士詠：魯仲連','吳筠','唐','御定全唐诗','yuding','','[]','仲連秉奇節，釋難含道情。一言卻秦圍，片劄降聊城。',48,'御定全唐詩/json/853.json','["仲連秉奇節，釋難含道情。一言卻秦圍，片劄降聊城。", "辭金義何遠，讓祿心益清。處世功已立，拂衣蹈滄溟。"]'),
('yuding-43','高士詠：顏歜','吳筠','唐','御定全唐诗','yuding','','[]','高哉彼顏歜，逸氣陵齊宣。道尊義不屈，士重王來前。',48,'御定全唐詩/json/853.json','["高哉彼顏歜，逸氣陵齊宣。道尊義不屈，士重王來前。", "榮祿安可誘，保和從自然。放情任所尚，長揖歸山泉。"]'),
('yuding-44','高士詠：周豐','吳筠','唐','御定全唐诗','yuding','','[]','周豐貴隱耀，靜默尊無名。魯侯詢政體，喻以治道精。',48,'御定全唐詩/json/853.json','["周豐貴隱耀，靜默尊無名。魯侯詢政體，喻以治道精。", "蒞人在忠愨，疑叛由會盟。一言達至義，千載良為程。"]'),
('yuding-45','高士詠：師金','吳筠','唐','御定全唐诗','yuding','','[]','聖人貴素樸，禮義非玄同。師金告顏生，可謂達化宗。',48,'御定全唐詩/json/853.json','["聖人貴素樸，禮義非玄同。師金告顏生，可謂達化宗。", "夫子飾芻狗，自然道斯窮。應物方矯行，俯仰靡不通。"]'),
('yuding-46','高士詠：南郭子綦','吳筠','唐','御定全唐诗','yuding','','[]','子綦方隱幾，冥寂久灰心。悟來應顏遊，清義杳何深。',48,'御定全唐詩/json/853.json','["子綦方隱幾，冥寂久灰心。悟來應顏遊，清義杳何深。", "含響盡天籟，有言同鷇音。是非不足辯，安用勞神襟。"]'),
('yuding-47','高士詠：黔婁先生','吳筠','唐','御定全唐诗','yuding','','[]','黔婁蘊雅操，守約遺代華。淡然常有怡，與物固無瑕。',48,'御定全唐詩/json/853.json','["黔婁蘊雅操，守約遺代華。淡然常有怡，與物固無瑕。", "哲妻配明德，既沒辯正邪。辭祿乃餘貴，表諡良可嘉。"]'),
('yuding-48','高士詠：原憲','吳筠','唐','御定全唐诗','yuding','','[]','原生何淡漠，觀妙自怡性。蓬戶常晏如，弦歌樂天命。',48,'御定全唐詩/json/853.json','["原生何淡漠，觀妙自怡性。蓬戶常晏如，弦歌樂天命。", "無財方是貧，有道固非病。木賜欽高風，退慚車馬盛。"]'),
('yuding-49','高士詠：商山四皓','吳筠','唐','御定全唐诗','yuding','','[]','萬方厭秦德，戰伐何紛紛。四皓同無為，丘中臥白雲。',48,'御定全唐詩/json/853.json','["萬方厭秦德，戰伐何紛紛。四皓同無為，丘中臥白雲。", "自漢成帝業，一來翼儲君。知幾道可尚，隱括成元勳。"]'),
('yuding-50','高士詠：河上公','吳筠','唐','御定全唐诗','yuding','','[]','邈邈河上叟，無名契虛沖。靈關暢玄旨，萬乘趨道風。',48,'御定全唐詩/json/853.json','["邈邈河上叟，無名契虛沖。靈關暢玄旨，萬乘趨道風。", "寵辱不可累，飄然在雲空。獨與造化友，誰能測無窮。"]'),
('yuding-51','高士詠：東方曼倩','吳筠','唐','御定全唐诗','yuding','','[]','東方稟易象，玩世隱廊廟。棲心抱清微，混跡秘光耀。',48,'御定全唐詩/json/853.json','["東方稟易象，玩世隱廊廟。棲心抱清微，混跡秘光耀。", "玄覽寄數術，納規在談笑。賣藥五湖中，還從九仙妙。"]'),
('yuding-52','高士詠：嚴君平','吳筠','唐','御定全唐诗','yuding','','[]','漢皇舉遺逸，多士咸已寧。至德不可拔，嚴君獨湛冥。',48,'御定全唐詩/json/853.json','["漢皇舉遺逸，多士咸已寧。至德不可拔，嚴君獨湛冥。", "蔔筮訓流俗，指歸暢玄經。閉關動元象，何必遊紫庭。"]'),
('yuding-53','高士詠：司馬季主','吳筠','唐','御定全唐诗','yuding','','[]','季主超常倫，沉跡寄蔔筮。宋賈二大夫，停車試觀藝。',48,'御定全唐詩/json/853.json','["季主超常倫，沉跡寄蔔筮。宋賈二大夫，停車試觀藝。", "高談哂朝列，洪辯不可際。終秉鸞鳳心，翛然已遐逝。"]'),
('yuding-54','高士詠：鄭子真張仲蔚','吳筠','唐','御定全唐诗','yuding','','[]','子真岩石下，仲蔚蓬蒿居。禮聘終不屈，清貧長晏如。',48,'御定全唐詩/json/853.json','["子真岩石下，仲蔚蓬蒿居。禮聘終不屈，清貧長晏如。", "心情在耕藝，養壽資玄虛。至樂非外物，道冥歡有餘。"]'),
('yuding-55','高士詠：嚴子陵','吳筠','唐','御定全唐诗','yuding','','[]','漢皇敦故友，物色訪嚴生。三聘迨深澤，一來遇帝庭。',48,'御定全唐詩/json/853.json','["漢皇敦故友，物色訪嚴生。三聘迨深澤，一來遇帝庭。", "紫宸同禦寢，玄象驗客星。祿位終不屈，雲山樂躬耕。"]'),
('yuding-56','高士詠：向子平','吳筠','唐','御定全唐诗','yuding','','[]','子平好真隱，清淨玩老易。探玄樂無為，觀象驗損益。',48,'御定全唐詩/json/853.json','["子平好真隱，清淨玩老易。探玄樂無為，觀象驗損益。", "常抱方外心，且紆人間跡。一朝畢婚娶，五嶽遂長適。"]'),
('yuding-57','高士詠：韓康','吳筠','唐','御定全唐诗','yuding','','[]','伯休抱遐心，隱括自為美。賣藥不二價，有名反深恥。',48,'御定全唐詩/json/853.json','["伯休抱遐心，隱括自為美。賣藥不二價，有名反深恥。", "安能受玄纁，秉願終素履。逃遁從所尚，蕭蕭絕塵軌。"]'),
('yuding-58','高士詠：台佟管甯','吳筠','唐','御定全唐诗','yuding','','[]','吾嘉台孝威，樂道隱岩穴。吾尚管幼安，棲真養高節。',48,'御定全唐詩/json/853.json','["吾嘉台孝威，樂道隱岩穴。吾尚管幼安，棲真養高節。", "采藥聊自給，觀書任所悅。風塵不可混，真素比松雪。"]'),
('yuding-59','高士詠：高鳳','吳筠','唐','御定全唐诗','yuding','','[]','吾觀時人趣，矯跡務馳聲。獨有高文通，訟田求翳名。',48,'御定全唐詩/json/853.json','["吾觀時人趣，矯跡務馳聲。獨有高文通，訟田求翳名。", "公車徒見累，爵祿非所榮。隱身樂魚釣，世網不可攖。"]'),
('yuding-60','高士詠：龐德公','吳筠','唐','御定全唐诗','yuding','','[]','龐公棲鹿門，絕跡遠城市。超然風塵外，自得丘壑美。',48,'御定全唐詩/json/853.json','["龐公棲鹿門，絕跡遠城市。超然風塵外，自得丘壑美。", "耕鑿勤厥躬，耘鋤課妻子。保茲永無患，軒冕何足紀。"]'),
('yuding-61','高士詠：玄晏先生','吳筠','唐','御定全唐诗','yuding','','[]','士安逾弱冠，落魄未修飾。一朝因感激，志學忘寢食。',48,'御定全唐詩/json/853.json','["士安逾弱冠，落魄未修飾。一朝因感激，志學忘寢食。", "著書窮天人，辭聘守玄默。薄葬信昭儉，可為將來則。"]'),
('yuding-62','高士詠：孫公和','吳筠','唐','御定全唐诗','yuding','','[]','孫登好淳古，卉服從穴居。彈琴合天和，讀易見象初。',48,'御定全唐詩/json/853.json','["孫登好淳古，卉服從穴居。彈琴合天和，讀易見象初。", "終日無慍色，恬然在玄虛。貽言誡叔夜，超跡安所如。"]'),
('yuding-63','高士詠：董威輦','吳筠','唐','御定全唐诗','yuding','','[]','董京依白社，散發詠玄風。心出區宇外，跡參城市中。',48,'御定全唐詩/json/853.json','["董京依白社，散發詠玄風。心出區宇外，跡參城市中。", "囂塵不能雜，名位安可籠。匿影留雅什，精微信難窮。"]'),
('yuding-64','高士詠：郭文舉','吳筠','唐','御定全唐诗','yuding','','[]','郭生在童稚，已得方外心。絕跡遺世務，棲真入長林。',48,'御定全唐詩/json/853.json','["郭生在童稚，已得方外心。絕跡遺世務，棲真入長林。", "元和感異類，猛獸懷德音。不憶固無情，斯言微且深。"]'),
('yuding-65','高士詠：陶征君','吳筠','唐','御定全唐诗','yuding','','[]','吾重陶淵明，達生知止足。怡情在樽酒，此外無所欲。',48,'御定全唐詩/json/853.json','["吾重陶淵明，達生知止足。怡情在樽酒，此外無所欲。", "彭澤非我榮，折腰信為辱。歸來北窗下，複采東籬菊。"]'),
('yuding-66','元日言懷，因以自勵，詒諸同志','吳筠','唐','御定全唐诗','yuding','','[]','馳光無時憩，加我五十年。知非慕伯玉，讀易宗文宣。',84,'御定全唐詩/json/853.json','["馳光無時憩，加我五十年。知非慕伯玉，讀易宗文宣。", "經世匪吾事，庶幾唯道全。誰言帝鄉遠，自古多真仙。", "餘滓永可滌，秉心方杳然。孰能無相與，滅跡俱忘筌。", "安用感時變，當期升九天。"]'),
('yuding-67','同劉主簿承介建昌江泛舟作','吳筠','唐','御定全唐诗','yuding','','[]','吾友從吏隱，和光心杳然。鳴琴正多暇，嘯侶浮清川。',120,'御定全唐詩/json/853.json','["吾友從吏隱，和光心杳然。鳴琴正多暇，嘯侶浮清川。", "風霽遠澄映，昭昭涵洞天。坐驚眾峰轉，乃覺孤舟遷。", "崖嶼非一狀，差池過目前。徘徊白日暮，月色江中鮮。", "真興殊未已，滔滔且溯沿。時歌滄浪曲，或誦逍遙篇。", "酣暢迷夜久，遲遲方告旋。此時無相與，其旨在忘筌。"]'),
('yuding-68','緱山廟','吳筠','唐','御定全唐诗','yuding','','[]','朝吾自嵩山，驅駕遵洛汭。逶遲轘轅側，仰望緱山際。',132,'御定全唐詩/json/853.json','["朝吾自嵩山，驅駕遵洛汭。逶遲轘轅側，仰望緱山際。", "王子謝時人，笙歌此賓帝。仙材夙所稟，寶位焉足系。", "為迫丹霄期，闕流蒼生惠。高蹤邈千載，遺廟今一詣。", "肅肅生風雲，森森列松桂。大君弘至道，層構何壯麗。", "稽首環金壇，焚香陟瑤砌。伊餘超浮俗，塵慮久已閉。", "況複清夙心，蕭然葉真契。"]'),
('yuding-69','胡無人行','吳筠','唐','御定全唐诗','yuding','','[]','劍頭利如芒，恒持照眼光。鐵騎追驍虜，金羈討黠羌。',48,'御定全唐詩/json/853.json','["劍頭利如芒，恒持照眼光。鐵騎追驍虜，金羈討黠羌。", "高秋八九月，胡地早風霜。男兒不惜死，破膽與君嘗。"]'),
('yuding-70','別章叟','吳筠','唐','御定全唐诗','yuding','','[]','平昔同邑裏，經年不相思。今日成遠別，相對心淒其。',24,'御定全唐詩/json/853.json','["平昔同邑裏，經年不相思。今日成遠別，相對心淒其。"]'),
('yuding-71','題縉雲嶺永望館','吳筠','唐','御定全唐诗','yuding','','[]','人驚此路險，我愛山前深。猶恐佳趣盡，欲行且沉吟。',24,'御定全唐詩/json/853.json','["人驚此路險，我愛山前深。猶恐佳趣盡，欲行且沉吟。"]'),
('yuding-72','題華山人所居','吳筠','唐','御定全唐诗','yuding','','[]','故人住南郭，邀我對芳樽。歡暢日雲暮，不知城市喧。',24,'御定全唐詩/json/853.json','["故人住南郭，邀我對芳樽。歡暢日雲暮，不知城市喧。"]'),
('yuding-0','初月','杜光庭','唐','御定全唐诗','yuding','','[]','始看東上又西浮，圓缺何曾得自由。照物不能長似鏡，',40,'御定全唐詩/json/854.json','["始看東上又西浮，圓缺何曾得自由。照物不能長似鏡，", "直使奔波急於箭，只應白盡世間頭。"]'),
('yuding-1','題仙居觀','杜光庭','唐','御定全唐诗','yuding','','[]','往歲真人朝玉皇，四真三代住繁陽。初開九鼎丹華熟，',40,'御定全唐詩/json/854.json','["往歲真人朝玉皇，四真三代住繁陽。初開九鼎丹華熟，", "時從白鹿岩前往，應許潛通不死鄉。"]'),
('yuding-2','題鴻都觀','杜光庭','唐','御定全唐诗','yuding','','[]','亡吳霸越已功全，深隱雲林始學仙。鸞鶴自飄三蜀駕，',40,'御定全唐詩/json/854.json','["亡吳霸越已功全，深隱雲林始學仙。鸞鶴自飄三蜀駕，", "也有扁舟歸去興，故鄉東望思悠然。"]'),
('yuding-3','題都慶觀','杜光庭','唐','御定全唐诗','yuding','','[]','三仙一一駕紅鸞，仙去雲閑繞古壇。煉藥舊台空處所，',40,'御定全唐詩/json/854.json','["三仙一一駕紅鸞，仙去雲閑繞古壇。煉藥舊台空處所，", "二十四峰皆古隱，振纓長往亦何難。"]'),
('yuding-4','贈將軍','杜光庭','唐','御定全唐诗','yuding','','[]','□□□□□□□，□□□□□□□。八表順風驚雨露，',40,'御定全唐詩/json/854.json','["□□□□□□□，□□□□□□□。八表順風驚雨露，", "未會漢家青史上，韓彭何處有功勞。"]'),
('yuding-5','題鶴鳴山','杜光庭','唐','御定全唐诗','yuding','','[]','五氣雲龍下泰清，三天真客已功成。人間回首山川小，',40,'御定全唐詩/json/854.json','["五氣雲龍下泰清，三天真客已功成。人間回首山川小，", "鹿裘高士如相遇，不待岩前鶴有聲。"]'),
('yuding-6','題空明洞','杜光庭','唐','御定全唐诗','yuding','','[]','窅然靈岫五雲深，落翮標名振古今。芝朮迎風香馥馥，',40,'御定全唐詩/json/854.json','["窅然靈岫五雲深，落翮標名振古今。芝朮迎風香馥馥，", "欲問空明奇勝處，地藏方石恰如金。"]'),
('yuding-7','題北平沼','杜光庭','唐','御定全唐诗','yuding','','[]','桐柏真人曾此居，焚香厓下誦靈書。朝回時宴三山客，',40,'御定全唐詩/json/854.json','["桐柏真人曾此居，焚香厓下誦靈書。朝回時宴三山客，", "寶芝常在知誰得，好駕金蟾入太虛。"]'),
('yuding-8','題平蓋沼','杜光庭','唐','御定全唐诗','yuding','','[]','勢壓長江空八陣，吳都仙客此修真。寒江向晚波濤急，',40,'御定全唐詩/json/854.json','["勢壓長江空八陣，吳都仙客此修真。寒江向晚波濤急，", "龍車鳳輦非難遇，只要塵心早出塵。"]'),
('yuding-9','題本竹觀','杜光庭','唐','御定全唐诗','yuding','','[]','樓閣層層冠此山，雕軒朱檻一躋攀。碑刊古篆龍蛇動，',40,'御定全唐詩/json/854.json','["樓閣層層冠此山，雕軒朱檻一躋攀。碑刊古篆龍蛇動，", "掃空雙竹今何在，只恐投波去不還。"]'),
('yuding-10','題福唐觀二首','杜光庭','唐','御定全唐诗','yuding','','[]','盤空躡翠到山巔，竹殿雲樓勢逼天。古洞草深微有路，',80,'御定全唐詩/json/854.json','["盤空躡翠到山巔，竹殿雲樓勢逼天。古洞草深微有路，", "自是人間輕舉地，何須蓬島訪真仙。", "曾隨雲水此山遊，行盡層峰更上樓。九月登臨須有意，", "暫熟爐香不須去，佇陪天仗入神州。"]'),
('yuding-11','題莫公台','杜光庭','唐','御定全唐诗','yuding','','[]','奇絕巍台峙濁流，古來人號小瀛洲。路通霄漢雲迷晚，',40,'御定全唐詩/json/854.json','["奇絕巍台峙濁流，古來人號小瀛洲。路通霄漢雲迷晚，", "將軍悟卻希夷訣，贏得清名萬古流。"]'),
('yuding-12','讀書台','杜光庭','唐','御定全唐诗','yuding','','[]','山中猶有讀書台，風掃晴嵐畫障開。',32,'御定全唐詩/json/854.json','["山中猶有讀書台，風掃晴嵐畫障開。", "華月冰壺依舊在，青蓮居士幾時來。"]'),
('yuding-13','贈人','杜光庭','唐','御定全唐诗','yuding','','[]','靜神凝思仰青冥，此夕長天降瑞星。',32,'御定全唐詩/json/854.json','["靜神凝思仰青冥，此夕長天降瑞星。", "海上昨聞鵬羽翼，人間初見鶴儀形。"]'),
('yuding-14','贈蜀州刺史','杜光庭','唐','御定全唐诗','yuding','','[]','再扶日月歸行殿，卻領山河鎮夢刀。',32,'御定全唐詩/json/854.json','["再扶日月歸行殿，卻領山河鎮夢刀。", "從此雄名壓寰海，八溟爭敢起波濤。"]'),
('yuding-15','題劍門','杜光庭','唐','御定全唐诗','yuding','','[]','誰運乾坤陶冶功，鑄為雙劍倚蒼穹。',32,'御定全唐詩/json/854.json','["誰運乾坤陶冶功，鑄為雙劍倚蒼穹。", "題詩曾駐三天駕，礙日長含八海風。"]'),
('yuding-16','題龍鵠山','杜光庭','唐','御定全唐诗','yuding','','[]','抽得閒身伴瘦筇，亂敲青碧喚蛟龍。',32,'御定全唐詩/json/854.json','["抽得閒身伴瘦筇，亂敲青碧喚蛟龍。", "道人掃徑收松子，缺月初圓天柱峰。"]'),
('yuding-17','富貴曲','杜光庭','唐','御定全唐诗','yuding','','[]','美人梳洗時，滿頭間珠翠。豈知兩片雲，戴卻數鄉稅。',24,'御定全唐詩/json/854.json','["美人梳洗時，滿頭間珠翠。豈知兩片雲，戴卻數鄉稅。"]'),
('yuding-18','詠西施','杜光庭','唐','御定全唐诗','yuding','','[]','素面已雲妖，更著花鈿飾。臉橫一寸波，浸破吳王國。',24,'御定全唐詩/json/854.json','["素面已雲妖，更著花鈿飾。臉橫一寸波，浸破吳王國。"]'),
('yuding-19','傷時','杜光庭','唐','御定全唐诗','yuding','','[]','帆力劈開滄海浪，馬蹄踏破亂山青。',32,'御定全唐詩/json/854.json','["帆力劈開滄海浪，馬蹄踏破亂山青。", "浮名浮利過於酒，醉得人心死不醒。"]'),
('yuding-20','題霍山秦尊師','杜光庭','唐','御定全唐诗','yuding','','[]','老鶴玄猿伴采芝，有時長歎獨移時。',32,'御定全唐詩/json/854.json','["老鶴玄猿伴采芝，有時長歎獨移時。", "翠娥紅粉嬋娟劍，殺盡世人人不知。"]'),
('yuding-21','偶題','杜光庭','唐','御定全唐诗','yuding','','[]','似鶴如雲一個身，不憂家國不憂貧。',32,'御定全唐詩/json/854.json','["似鶴如雲一個身，不憂家國不憂貧。", "擬將枕上日高睡，賣與世間榮貴人。"]'),
('yuding-22','思山詠','杜光庭','唐','御定全唐诗','yuding','','[]','因賣丹砂下白雲，鹿裘惟惹九衢塵。',32,'御定全唐詩/json/854.json','["因賣丹砂下白雲，鹿裘惟惹九衢塵。", "不如將耳入山去，萬是千非愁殺人。"]'),
('yuding-23','景福中作','杜光庭','唐','御定全唐诗','yuding','','[]','悶見戈鋋匝四溟，恨無奇策救生靈。',32,'御定全唐詩/json/854.json','["悶見戈鋋匝四溟，恨無奇策救生靈。", "如何飲酒得長醉，直到太平時節醒。"]'),
('yuding-24','招友人游春','杜光庭','唐','御定全唐诗','yuding','','[]','難把長繩系日烏，芳時偷取醉功夫。',32,'御定全唐詩/json/854.json','["難把長繩系日烏，芳時偷取醉功夫。", "任堆金璧磨星斗，買得花枝不老無。"]'),
('yuding-25','山居三首','杜光庭','唐','御定全唐诗','yuding','','[]','悶見有人尋，移庵更入深。落花流澗水，明月照松林。',144,'御定全唐詩/json/854.json','["悶見有人尋，移庵更入深。落花流澗水，明月照松林。", "醉勸頭陀酒，閑教孺子吟。身同雲外鶴，斷得世塵侵。", "冥心棲太室，散發浸流泉。采柏時逢麝，看雲忽見仙。", "夏狂沖雨戲，春醉戴花眠。絕頂登雲望，東都一點煙。", "不求朝野知，臥見歲華移。采藥歸侵夜，聽松飯過時。", "荷竿尋水釣，背局上岩棋。祭廟人來說，中原正亂離。"]'),
('yuding-26','紀道德','杜光庭','唐','御定全唐诗','yuding','','[]','道，德。清虛，玄默。生帝先，為聖則。聽之不聞，',178,'御定全唐詩/json/854.json','["道，德。清虛，玄默。生帝先，為聖則。聽之不聞，", "既鼓鑄於乾坤品物，信充仞乎東西南北。", "三皇高拱兮任以自然，五帝垂衣兮修之不忒。", "以心體之者為四海之主，以身彎之者為萬夫之特。", "有皓齒青娥者為伐命之斧，蘊奇謀廣智者為盜國之賊。", "曾未若軒後順風兮清靜自化，曾未若皋陶邁種兮溫恭允塞。", "故可以越圓清方濁兮不始不終，", "豈不聞乎天地于道德也無以清寧，", "語不雲乎仲尼有言朝聞道夕死可矣，"]'),
('yuding-27','懷古今','杜光庭','唐','御定全唐诗','yuding','','[]','古，今。感事，傷心。驚得喪，歎浮沈。風驅寒暑，',178,'御定全唐詩/json/854.json','["古，今。感事，傷心。驚得喪，歎浮沈。風驅寒暑，", "雁足淒涼兮傳恨緒，鳳台寂寞兮有遺音。", "朔漠幽囚兮天長地久，瀟湘隔別兮水闊煙深。", "誰能絕聖韜賢餐芝餌術，誰能含光遁世煉石燒金。", "君不見屈大夫紉蘭而發諫，君不見賈太傅忌鵩而愁吟。", "君不見四皓避秦峨峨戀商嶺，君不見二疏辭漢飄飄歸故林。", "胡為乎冒進貪名踐危途與傾轍，", "吾所以思抗跡忘機用虛無為師範，", "不能勞神效蘇子張生兮於時而縱辯，"]'),
('yuding-28','句','杜光庭','唐','御定全唐诗','yuding','','[]','銅壺滴滴禁漏起，三十六宮爭捲簾。（《月》，',117,'御定全唐詩/json/854.json','["銅壺滴滴禁漏起，三十六宮爭捲簾。（《月》，", "斜陽古岸歸鴉晚，紅蓼低沙宿雁愁。", "霜雕曲徑寒蕪白，雁下遙村落照黃。", "恩威欲寄黃丞相，仁信先聞郭細侯。", "兵氣此時來世上，文星今日到人間。降因天下思姚宋，", "丹灶河車休矻矻，蚌胎龜息且綿綿。馭景必能趨日域，"]'),
('yuding-0','山居','鄭遨','唐','御定全唐诗','yuding','','[]','悶見有人尋，移庵更入深。落花流澗水，明月照松林。',144,'御定全唐詩/json/855.json','["悶見有人尋，移庵更入深。落花流澗水，明月照松林。", "醉勸頭陀酒，閑教孺子吟。身同雲外鶴，斷得世塵侵。", "冥心棲太室，散發浸流泉。采柏時逢麝，看雲忽見山。", "夏狂沖雨戲，春醉戴花眠。絕頂登雲望，東都一點煙。", "不求朝野知，臥見歲華移。采藥歸侵夜，聽松飯過時。", "荷竿尋水釣，背局上岩棋。祭廟人來說，中原正亂離。"]'),
('yuding-1','茶詩','鄭遨','唐','御定全唐诗','yuding','','[]','嫩芽香且靈，吾謂草中英。夜臼和煙搗，寒爐對雪烹。',48,'御定全唐詩/json/855.json','["嫩芽香且靈，吾謂草中英。夜臼和煙搗，寒爐對雪烹。", "惟憂碧粉散，常見綠花生。最是堪珍重，能令睡思清。"]'),
('yuding-2','哭張道古','鄭遨','唐','御定全唐诗','yuding','','[]','曾陳章疏忤昭皇，撲落西南事可傷。豈使諫臣終屈辱，',40,'御定全唐詩/json/855.json','["曾陳章疏忤昭皇，撲落西南事可傷。豈使諫臣終屈辱，", "誰是後來修史者，言君力死正頹綱。"]'),
('yuding-3','富貴曲','鄭遨','唐','御定全唐诗','yuding','','[]','美人梳洗時，滿頭間珠翠。豈知兩片雲，戴卻數鄉稅。',24,'御定全唐詩/json/855.json','["美人梳洗時，滿頭間珠翠。豈知兩片雲，戴卻數鄉稅。"]'),
('yuding-4','傷農','鄭遨','唐','御定全唐诗','yuding','','[]','一粒紅稻飯，幾滴牛頷血。珊瑚枝下人，銜杯吐不歇。',24,'御定全唐詩/json/855.json','["一粒紅稻飯，幾滴牛頷血。珊瑚枝下人，銜杯吐不歇。"]'),
('yuding-5','詠西施','鄭遨','唐','御定全唐诗','yuding','','[]','素面已雲妖，更著花鈿飾。臉橫一寸波，浸破吳王國。',24,'御定全唐詩/json/855.json','["素面已雲妖，更著花鈿飾。臉橫一寸波，浸破吳王國。"]'),
('yuding-6','思山詠','鄭遨','唐','御定全唐诗','yuding','','[]','因賣丹砂下白雲，鹿裘惟惹九衢塵。',32,'御定全唐詩/json/855.json','["因賣丹砂下白雲，鹿裘惟惹九衢塵。", "不如將耳入山去，萬是千非愁殺人。"]'),
('yuding-7','招友人游春','鄭遨','唐','御定全唐诗','yuding','','[]','難把長繩系日烏，芳時偷取醉工夫。',32,'御定全唐詩/json/855.json','["難把長繩系日烏，芳時偷取醉工夫。", "任堆金璧磨星斗，買得花枝不老無。"]'),
('yuding-8','宿洞庭','鄭遨','唐','御定全唐诗','yuding','','[]','月到君山酒半醒，朗吟疑有水仙聽。',32,'御定全唐詩/json/855.json','["月到君山酒半醒，朗吟疑有水仙聽。", "無人識我真閒事，贏得高秋看洞庭。"]'),
('yuding-9','題病僧寮','鄭遨','唐','御定全唐诗','yuding','','[]','佛前香印廢晨燒，金錫當門照寂寥。',32,'御定全唐詩/json/855.json','["佛前香印廢晨燒，金錫當門照寂寥。", "童子不知師病困，報風吹折好芭蕉。"]'),
('yuding-10','題霍山秦尊師','鄭遨','唐','御定全唐诗','yuding','','[]','老鶴玄猿伴采芝，有時長歎獨移時。',32,'御定全唐詩/json/855.json','["老鶴玄猿伴采芝，有時長歎獨移時。", "翠娥紅粉渾如劍，殺盡世人人不知。"]'),
('yuding-11','偶題','鄭遨','唐','御定全唐诗','yuding','','[]','似鶴如雲一個身，不憂家國不憂貧。',64,'御定全唐詩/json/855.json','["似鶴如雲一個身，不憂家國不憂貧。", "擬將枕上日高睡，賣與世間榮貴人。", "帆力劈開滄海浪，馬蹄踏破亂山青。", "浮名浮利濃於酒，醉得人心死不醒。"]'),
('yuding-12','景福中作','鄭遨','唐','御定全唐诗','yuding','','[]','悶見戈鋋匝四溟，恨無奇策救生靈。',32,'御定全唐詩/json/855.json','["悶見戈鋋匝四溟，恨無奇策救生靈。", "如何飲酒得長醉，直到太平時節醒。"]'),
('yuding-13','題中條靜觀','鄭遨','唐','御定全唐诗','yuding','','[]','松頂留衣上玉霄，永傳異跡在中條。',32,'御定全唐詩/json/855.json','["松頂留衣上玉霄，永傳異跡在中條。", "不知揖遍諸仙否，欲請還丹問昨宵。"]'),
('yuding-14','送臥雲道士','虞有賢','唐','御定全唐诗','yuding','','[]','臥雲道士來相辭，相辭倏忽何所之。紫閣春深煙靄靄，',46,'御定全唐詩/json/855.json','["臥雲道士來相辭，相辭倏忽何所之。紫閣春深煙靄靄，", "冥鴻一見傷弓翼，高飛輾轉心無疑。滿酌數杯酒，"]'),
('yuding-15','示守庚申眾','程紫霄','唐','御定全唐诗','yuding','','[]','不守庚申亦不疑，此心常與道相依。',32,'御定全唐詩/json/855.json','["不守庚申亦不疑，此心常與道相依。", "玉皇已自知行止，任汝三彭說是非。"]'),
('yuding-16','蘭溪靈瑞觀','舒道紀','唐','御定全唐诗','yuding','','[]','澄心坐清境，虛白生林端。夜靜笑聲出，月明松影寒。',48,'御定全唐詩/json/855.json','["澄心坐清境，虛白生林端。夜靜笑聲出，月明松影寒。", "絳霞封藥灶，碧竇濺齋壇。海樹幾回老，先生棋未殘。"]'),
('yuding-17','題赤松宮','舒道紀','唐','御定全唐诗','yuding','','[]','松老赤松原，松間廟宛然。人皆有兄弟，誰得共神仙。',48,'御定全唐詩/json/855.json','["松老赤松原，松間廟宛然。人皆有兄弟，誰得共神仙。", "雙鶴沖天去，群羊化石眠。至今丹井水，香滿北山邊。"]'),
('yuding-18','參同契明鏡圖訣詩二首','彭曉','唐','御定全唐诗','yuding','','[]','造化潛施跡莫窮，簇成真訣指蒙童。三篇秘列八環內，',80,'御定全唐詩/json/855.json','["造化潛施跡莫窮，簇成真訣指蒙童。三篇秘列八環內，", "同人好道宜精究，究得長生路便通。", "至道希夷妙且深，燒丹先認大還心。日爻陰耦生真汞，", "兩端指的鉛金祖，莫向諸般取次尋。"]'),
('yuding-19','題柳公權書度人經後','魚又玄','唐','御定全唐诗','yuding','','[]','臥雲道士來相辭，相辭倏忽何所之。紫閣當春凝煙靄，',46,'御定全唐詩/json/855.json','["臥雲道士來相辭，相辭倏忽何所之。紫閣當春凝煙靄，", "冥鴻複見傷弓翼，高飛輾轉心無疑。滿瀉數杯酒，"]'),
('yuding-0','呈鐘離雲房','呂岩','唐','御定全唐诗','yuding','','[]','生在儒家遇太平，懸纓重滯布衣輕。',32,'御定全唐詩/json/856.json','["生在儒家遇太平，懸纓重滯布衣輕。", "誰能世上爭名利，臣事玉皇歸上清。"]'),
('yuding-1','獻鄭思遠施真人二仙','呂岩','唐','御定全唐诗','yuding','','[]','萬劫千生到此生，此生身始覺飛輕。拋家別國雲山外，',40,'御定全唐詩/json/856.json','["萬劫千生到此生，此生身始覺飛輕。拋家別國雲山外，", "如今獲遇真仙面，紫府仙扉得姓名。"]'),
('yuding-2','得火龍真人劍法','呂岩','唐','御定全唐诗','yuding','','[]','昔年曾遇火龍君，一劍相傳伴此身。天地山河從結沫，',40,'御定全唐詩/json/856.json','["昔年曾遇火龍君，一劍相傳伴此身。天地山河從結沫，", "昨夜鐘離傳一語，六天宮殿欲成塵。"]'),
('yuding-3','七言','呂岩','唐','御定全唐诗','yuding','','[]','周行獨力出群倫，默默昏昏亙古存。無象無形潛造化，',480,'御定全唐詩/json/856.json','["周行獨力出群倫，默默昏昏亙古存。無象無形潛造化，", "此道非從它外得，千言萬語謾評論。", "通靈一顆正金丹，不在天涯地角安。討論窮經深莫究，", "舉世若能知所寓，超凡入聖弗為難。", "落魄紅塵四十春，無為無事信天真。生涯只在乾坤鼎，", "桑田改變依然在，永作人間出世人。", "獨處乾坤萬象中，從頭歷歷運元功。縱橫北斗心機大，", "如何俗士尋常覓，不達希夷不可窮。", "誰信華池路最深，非遐非邇奧難尋。九年采煉如紅玉，", "勸君門外修身者，端念思惟此道心。", "水府尋鉛合火鉛，黑紅紅黑又玄玄。氣中生氣肌膚換，", "出神入定虛華語，徒費功夫萬萬年。", "九鼎烹煎九轉砂，區分時節更無差。精神氣血歸三要，", "終期鳳詔空中降，跨虎騎龍謁紫霞。", "憑君子後午前看，一脈天津在脊端。金闕內藏玄穀子，", "直指幾多求道者，行藏莫離虎龍灘。", "返本還元道氣平，虛非形質轉分明。水中白雪微微結，", "吾今為報修行者，莫向燒金問至精。", "安排鼎灶煉玄根，進退須明卯酉門。繞電奔雲飛日月，", "此道幽微知者少，茫茫塵世與誰論。", "醍醐一盞詩一篇，暮醉朝吟不記年。幹馬屢來遊九地，", "提挈靈童山上望，重重疊疊是金錢。", "認得東西木與金，自然爐鼎虎龍吟。但隨天地明消息，", "神仙親口留斯旨，何用區區向外尋。"]'),
('yuding-0','七言','呂岩','唐','御定全唐诗','yuding','','[]','金丹一粒定長生，須得真鉛煉甲庚。火取南方赤鳳髓，',480,'御定全唐詩/json/857.json','["金丹一粒定長生，須得真鉛煉甲庚。火取南方赤鳳髓，", "齋戒興功成九轉，定應入口鬼神驚。", "功滿來來際會難，又聞東去上仙壇。杖頭春色一壺酒，", "先生去後身須老，乞與貧儒換骨丹。", "碧潭深處一真人，貌似桃花體似銀。鬢髮未斑緣有術，", "任彼桑田變滄海，一丸丹藥定千春。", "爐養丹砂鬢不斑，假將名利住人間。已逢志士傳神藥，", "幸蒙上士甘撈摝，處世輸君一個閑。", "誰解長生似我哉，煉成真氣在三台。盡知白日升天去，", "只吞一粒金丹藥，飛入青霄更不回。", "亂雲堆裏表星都，認得深藏大丈夫。綠酒醉眠閑日月，", "山水路遙人不到，茅君消息近知無。", "鶴為車駕酒為糧，為戀長生不死鄉。地脈尚能縮得短，", "若欲時流親得見，朝朝不離水銀行。", "靈芝無種亦無根，解飲能餐自返魂。但得煙霞供歲月，", "一得不回千古內，更無塚墓示兒孫。", "世上何人會此言，休將名利掛心田。等閒倒盡十分酒，", "他時功滿歸何處，直駕雲車入洞天。", "玄門帝子坐中央，得算明長感玉皇。枕上山河和雨露，", "真個夫妻齊守志，立教牽惹在陰陽。", "遙指高峰笑一聲，紅霞紫霧面前生。每于廛市無人識，", "他時若赴蓬萊洞，知我仙家有姓名。", "堪笑時人問我家，杖擔雲物惹煙霞。眉藏火電非他說，", "騎龍遠出遊三島，夜久無人玩月華。"]'),
('yuding-1','真人行巴陵市太守怒其不避使案吏具其罪真人…詩曰','呂岩','唐','御定全唐诗','yuding','','[]','暫別蓬萊海上游，偶逢太守問根由。身居北斗星杓下，',40,'御定全唐詩/json/857.json','["暫別蓬萊海上游，偶逢太守問根由。身居北斗星杓下，", "相逢何事不相認，卻駕白雲歸去休。"]'),
('yuding-2','仙樂侑席','呂岩','唐','御定全唐诗','yuding','','[]','曾經天上三千劫，又在人間五百年。腰下劍鋒橫紫電，',40,'御定全唐詩/json/857.json','["曾經天上三千劫，又在人間五百年。腰下劍鋒橫紫電，", "小技等閒聊戲爾，無人知我是真仙。"]'),
('yuding-3','題桐柏山黃先生庵門','呂岩','唐','御定全唐诗','yuding','','[]','吾有玄中極玄語，周遊八極無處吐。雲輧飄泛到凝陽，',169,'御定全唐詩/json/857.json','["吾有玄中極玄語，周遊八極無處吐。雲輧飄泛到凝陽，", "無為大道本根源，要君親見求真物。其中有一分三五，", "浮沈升降入中宮，四象五行齊見土。驅青龍，擒白虎，", "既修真，須堅確，能轉乾坤泛海嶽。運行天地莫能知，", "黃秀才，黃秀才，既修真，須且早，人間萬事何時了。", "貪名貪利愛金多，為他財色身衰老。我今勸子心悲切，", "留此片言，用表其意。他日相逢，必與汝決。莫退初心，"]'),
('yuding-0','五言','呂岩','唐','御定全唐诗','yuding','','[]','悟了長生理，秋蓮處處開。金童登錦帳，玉女下香階。',576,'御定全唐詩/json/858.json','["悟了長生理，秋蓮處處開。金童登錦帳，玉女下香階。", "虎嘯天魂住，龍吟地魄來。有人明此道，立使返嬰孩。", "姹女住南方，身邊產太陽。蟾宮烹玉液，坎戶煉瓊漿。", "過去神仙餌，今來到我嘗。一杯延萬紀，物外任翱翔。", "頓悟黃芽理，陰陽稟自然。乾坤爐裏煉，日月鼎中煎。", "木產長生汞，金烹續命鉛。世人明此道，立便返童顏。", "宇宙產黃芽，經爐煆作砂。陰陽烹五彩，水火煉三花。", "鼎內龍降虎，壺中龜遣蛇。功成歸物外，自在樂煙霞。", "要覓長生路，除非認本元。都來一味藥，剛道數千般。", "丹鼎烹成汞，爐中煉就鉛。依時服一粒，白日上沖天。", "姹女住瑤台，仙花滿地開。金苗從此出，玉蕊自天來。", "鳳舞長生曲，鸞歌續命杯。有人明此道，海變已千回。", "古往諸仙子，根元占甲庚。水中聞虎嘯，火裏見龍行。", "進退窮三候，相吞用八紘。沖天功行滿，寒暑不能爭。", "我悟長生理，太陽伏太陰。離宮生白玉，坎戶產黃金。", "要主君臣義，須存子母心。九重神室內，虎嘯與龍吟。", "靈丹產太虛，九轉入重爐。浴就紅蓮顆，燒成白玉珠。", "水中鉛一兩，火內汞三銖。吃了瑤台寶，升天任海枯。", "姹女住離宮，身邊產雌雄。爐中七返畢，鼎內九還終。", "悟了魚投水，迷因鳥在籠。耄年服一粒，立地變沖童。", "盜得乾坤祖，陰陽是本宗。天魂生白虎，地魄產青龍。", "運寶泥丸在，搬精入上宮。有人明此法，萬載貌如童。", "要覓金丹理，根元不易逢。三才七返足，四象九還終。", "浴就微微白，燒成漸漸紅。一丸延萬紀，物外去衝衝。"]'),
('yuding-1','絕句','呂岩','唐','御定全唐诗','yuding','','[]','捉得金晶固命基，日魂東畔月華西。',384,'御定全唐詩/json/858.json','["捉得金晶固命基，日魂東畔月華西。", "于中煉就長生藥，服了還同天地齊。", "莫怪瑤池消息稀，只緣塵事隔天機。", "若人尋得水中火，有一黃童上太微。", "混元海底隱生倫，內有黃童玉帝名。", "白虎神符潛姹女，靈元鎮在七元君。", "三畝丹田無種種，種時須藉赤龍耕。", "曾將此種教人種，不解鉛池道不生。", "閃灼虎龍神劍飛，好憑身事莫相違。", "傳時須在乾坤力，便透三清入紫微。", "不用梯媒向外求，還丹只在體中收。", "莫言大道人難得，自是功夫不到頭。", "飲酒須教一百杯，東浮西泛自梯媒。", "日精自與月華合，有個明珠走上來。", "不負三光不負人，不欺神道不欺貧。", "有人問我修行法，只種心田養此身。", "時人若擬去瀛洲，先過巍巍十八樓。", "自有電雷聲震動，一池金水向東流。", "瓶子如金玉子黃，上升下降續神光。", "三元一會經年淨，這個天中日月長。", "學道須教徹骨貧，囊中只有五三文。", "有人問我修行法，遙指天邊日月輪。", "我自忘心神自悅，跨水穿雲來相謁。", "不問黃芽肘後方，妙道通微怎生說。"]'),
('yuding-2','徽宗齋會','呂岩','唐','御定全唐诗','yuding','','[]','高談闊論若無人，可惜明君不遇真。',32,'御定全唐詩/json/858.json','["高談闊論若無人，可惜明君不遇真。", "陛下問臣來日事，請看午未丙丁春。"]'),
('yuding-3','七夕','呂岩','唐','御定全唐诗','yuding','','[]','四海孤遊一野人，兩壺霜雪足精神。',64,'御定全唐詩/json/858.json','["四海孤遊一野人，兩壺霜雪足精神。", "坎離二物君收得，龍虎丹行運水銀。", "野人本是天臺客，石橋南畔有舊宅。", "父子生來有兩口，多好歌笙不好拍。"]'),
('yuding-4','贈李德成','呂岩','唐','御定全唐诗','yuding','','[]','九重天子寰中貴，五等諸侯門外尊。',32,'御定全唐詩/json/858.json','["九重天子寰中貴，五等諸侯門外尊。", "爭似布衣狂醉客，不教性命屬乾坤。"]'),
('yuding-5','牧童','呂岩','唐','御定全唐诗','yuding','','[]','草鋪橫野六七裏，笛弄晚風三四聲。',32,'御定全唐詩/json/858.json','["草鋪橫野六七裏，笛弄晚風三四聲。", "歸來飽飯黃昏後，不脫蓑衣臥月明。"]'),
('yuding-6','潭州鶴會','呂岩','唐','御定全唐诗','yuding','','[]','這回相見不無緣，滿院風光小洞天。',32,'御定全唐詩/json/858.json','["這回相見不無緣，滿院風光小洞天。", "一劍當空又飛去，洞庭驚起老龍眠。"]'),
('yuding-7','紹興道會','呂岩','唐','御定全唐诗','yuding','','[]','偶乘青帝出蓬萊，劍戟崢嶸遍九垓。',32,'御定全唐詩/json/858.json','["偶乘青帝出蓬萊，劍戟崢嶸遍九垓。", "我在目前人不識，為留一笠莫沉埋。"]'),
('yuding-8','贈曹先生','呂岩','唐','御定全唐诗','yuding','','[]','鶴不西飛龍不行，露幹雲破洞簫清。',32,'御定全唐詩/json/858.json','["鶴不西飛龍不行，露幹雲破洞簫清。", "少年仙子說閒事，遙隔彩雲聞笑聲。"]'),
('yuding-9','海上相逢趙同','呂岩','唐','御定全唐诗','yuding','','[]','南宮水火吾須濟，北闕夫妻我自媒。',32,'御定全唐詩/json/858.json','["南宮水火吾須濟，北闕夫妻我自媒。", "洞裏龍兒嬌郁律，山前童子喜徘徊。"]'),
('yuding-10','題鳳翔府天慶觀','呂岩','唐','御定全唐诗','yuding','','[]','得道年來八百秋，不曾飛劍取人頭。',32,'御定全唐詩/json/858.json','["得道年來八百秋，不曾飛劍取人頭。", "玉皇未有天符至，且貨烏金混世流。"]'),
('yuding-11','劍畫此詩於襄陽雪中','呂岩','唐','御定全唐诗','yuding','','[]','峴山一夜玉龍寒，鳳林千樹梨花老。',32,'御定全唐詩/json/858.json','["峴山一夜玉龍寒，鳳林千樹梨花老。", "襄陽城裏沒人知，襄陽城外江山好。"]'),
('yuding-12','洞庭湖君山頌','呂岩','唐','御定全唐诗','yuding','','[]','午夜君山玩月回，西鄰小圃碧蓮開。',32,'御定全唐詩/json/858.json','["午夜君山玩月回，西鄰小圃碧蓮開。", "天香風露蒼華冷，雲在青霄鶴未來。"]'),
('yuding-13','秦州北山觀留詩','呂岩','唐','御定全唐诗','yuding','','[]','石池清水是吾心，剛被桃花影倒沉。',32,'御定全唐詩/json/858.json','["石池清水是吾心，剛被桃花影倒沉。", "一到邽山宮闕內，銷閑澄慮七弦琴。"]'),
('yuding-14','題永康酒樓','呂岩','唐','御定全唐诗','yuding','','[]','鯨吸鼇吞數百杯，玉山誰起複誰頹。',32,'御定全唐詩/json/858.json','["鯨吸鼇吞數百杯，玉山誰起複誰頹。", "醒時兩袂天風冷，一朵紅雲海上來。"]'),
('yuding-15','贈滕宗諒','呂岩','唐','御定全唐诗','yuding','','[]','華州回道人，來到岳陽城。別我遊何處，秋空一劍橫。',24,'御定全唐詩/json/858.json','["華州回道人，來到岳陽城。別我遊何處，秋空一劍橫。"]'),
('yuding-16','贈江州太平觀道士','呂岩','唐','御定全唐诗','yuding','','[]','落魄薛高士，年高無白髭。雲中閑臥石，山裏冷尋碑。',48,'御定全唐詩/json/858.json','["落魄薛高士，年高無白髭。雲中閑臥石，山裏冷尋碑。", "誇我飲大酒，嫌人說小詩。不知甚麼漢，一任輩流嗤。"]'),
('yuding-17','宋朝張天覺為相之日有襤縷道人及門求施…留詩於案上雲','呂岩','唐','御定全唐诗','yuding','','[]','捏土為香事有因，世間宜假不宜真。',32,'御定全唐詩/json/858.json','["捏土為香事有因，世間宜假不宜真。", "皇朝宰相張天覺，天下雲遊呂洞賓。"]'),
('yuding-18','贈陳處士','呂岩','唐','御定全唐诗','yuding','','[]','青霄一路少人行，休話興亡事不成。金榜因何無姓字，',40,'御定全唐詩/json/858.json','["青霄一路少人行，休話興亡事不成。金榜因何無姓字，", "深謝宋朝明聖主，解書丹詔詔先生。"]'),
('yuding-19','哭陳先生','呂岩','唐','御定全唐诗','yuding','','[]','天網恢恢萬象疏，一身親到華山區。寒雲去後留殘月，',40,'御定全唐詩/json/858.json','["天網恢恢萬象疏，一身親到華山區。寒雲去後留殘月，", "自從遺卻先生後，南北東西少丈夫。"]'),
('yuding-20','化江南簡寂觀道士侯用晦磨劍','呂岩','唐','御定全唐诗','yuding','','[]','欲整鋒鋩敢憚勞，淩晨開匣玉龍嗥。手中氣概冰三尺，',40,'御定全唐詩/json/858.json','["欲整鋒鋩敢憚勞，淩晨開匣玉龍嗥。手中氣概冰三尺，", "削平浮世不平事，與爾相將上九霄。"]'),
('yuding-21','熙甯元年八月十九日過湖州東林沈山用石榴…自號回山人','呂岩','唐','御定全唐诗','yuding','','[]','西鄰已富憂不足，東老雖貧樂有餘。',32,'御定全唐詩/json/858.json','["西鄰已富憂不足，東老雖貧樂有餘。", "白酒釀來緣好客，黃金散盡為收書。"]'),
('yuding-22','大雲寺茶詩','呂岩','唐','御定全唐诗','yuding','','[]','玉蕊一槍稱絕品，僧家造法極功夫。兔毛甌淺香雲白，',40,'御定全唐詩/json/858.json','["玉蕊一槍稱絕品，僧家造法極功夫。兔毛甌淺香雲白，", "幽叢自落溪岩外，不肯移根入上都。"]'),
('yuding-23','別詩二首','呂岩','唐','御定全唐诗','yuding','','[]','無心獨坐轉黃庭，不逐時流入利名。救老只存真一氣，',80,'御定全唐詩/json/858.json','["無心獨坐轉黃庭，不逐時流入利名。救老只存真一氣，", "莫笑老人貧裏樂，十年功滿上三清。", "時人受氣稟陰陽，均體乾坤壽命長。為重本宗能壽永，", "咫尺昆侖山上玉，幾人知是藥中王。"]'),
('yuding-24','贈羅浮道士','呂岩','唐','御定全唐诗','yuding','','[]','羅浮道士誰同流，草衣木食輕王侯。世間甲子管不得，',40,'御定全唐詩/json/858.json','["羅浮道士誰同流，草衣木食輕王侯。世間甲子管不得，", "飲餘回首話歸路，遙指白雲天際頭。"]'),
('yuding-25','宿州天慶觀殿門留贈符離道士','呂岩','唐','御定全唐诗','yuding','','[]','秋景蕭條葉亂飛，庭松影裏坐移時。',32,'御定全唐詩/json/858.json','["秋景蕭條葉亂飛，庭松影裏坐移時。", "雲迷鶴駕何方去，仙洞朝元失我期。"]'),
('yuding-26','題黃鶴樓石照','呂岩','唐','御定全唐诗','yuding','','[]','黃鶴樓前吹笛時，白蘋紅蓼滿江湄。',32,'御定全唐詩/json/858.json','["黃鶴樓前吹笛時，白蘋紅蓼滿江湄。", "衷情欲訴誰能會，惟有清風明月知。"]'),
('yuding-27','答僧見','呂岩','唐','御定全唐诗','yuding','','[]','三千裏外無家客，七百年來雲水身。行滿蓬萊為別館，',40,'御定全唐詩/json/858.json','["三千裏外無家客，七百年來雲水身。行滿蓬萊為別館，", "積德求師何患少，由來天地不私親。"]'),
('yuding-28','與潭州智度寺慧覺詩','呂岩','唐','御定全唐诗','yuding','','[]','達者推心兼濟物，聖賢傳法不離真。',32,'御定全唐詩/json/858.json','["達者推心兼濟物，聖賢傳法不離真。", "請師開說西來意，七祖如今未有人。"]'),
('yuding-29','參黃龍機悟後呈偈','呂岩','唐','御定全唐诗','yuding','','[]','棄卻瓢囊摵碎琴，如今不戀□中金。',32,'御定全唐詩/json/858.json','["棄卻瓢囊摵碎琴，如今不戀□中金。", "自從一見黃龍後，始覺從前錯用心。"]'),
('yuding-30','題僧房絕句','呂岩','唐','御定全唐诗','yuding','','[]','唐朝進士，今日神仙。足躡紫霧，卻返洞天。',20,'御定全唐詩/json/858.json','["唐朝進士，今日神仙。足躡紫霧，卻返洞天。"]'),
('yuding-31','賜齊州李希遇詩','呂岩','唐','御定全唐诗','yuding','','[]','少飲欺心酒，休貪不義財。福因慈善得，禍向巧奸來。',24,'御定全唐詩/json/858.json','["少飲欺心酒，休貪不義財。福因慈善得，禍向巧奸來。"]'),
('yuding-32','六言','呂岩','唐','御定全唐诗','yuding','','[]','春暖群花半開，逍遙石上徘徊。獨攜玉律丹訣，',35,'御定全唐詩/json/858.json','["春暖群花半開，逍遙石上徘徊。獨攜玉律丹訣，", "逢人莫話他事，笑指白雲去來。"]'),
('yuding-33','明胎息','呂岩','唐','御定全唐诗','yuding','','[]','密室靜存神，陰陽重一斤。煉成離女液，咽盡坎男津。',48,'御定全唐詩/json/858.json','["密室靜存神，陰陽重一斤。煉成離女液，咽盡坎男津。", "漸變逍遙體，超然自在身。更修功業滿，旌鶴引朝真。"]'),
('yuding-34','警世','呂岩','唐','御定全唐诗','yuding','','[]','二八佳人體似酥，腰間仗劍斬凡夫。',32,'御定全唐詩/json/858.json','["二八佳人體似酥，腰間仗劍斬凡夫。", "雖然不見人頭落，暗裏教君骨髓枯。"]'),
('yuding-35','通道','呂岩','唐','御定全唐诗','yuding','','[]','通道複通玄，名留四海傳。交親一拄杖，活計兩空拳。',48,'御定全唐詩/json/858.json','["通道複通玄，名留四海傳。交親一拄杖，活計兩空拳。", "要果逡巡種，思茶逐旋煎。豈知來混世，不久卻回天。"]'),
('yuding-36','為賈師雄發明古鐵鏡','呂岩','唐','御定全唐诗','yuding','','[]','手內青蛇淩白日，洞中仙果豔長春。',32,'御定全唐詩/json/858.json','["手內青蛇淩白日，洞中仙果豔長春。", "須知物外煙霞客，不是塵中磨鏡人。"]'),
('yuding-37','題全州道士蔣暉壁','呂岩','唐','御定全唐诗','yuding','','[]','醉舞高歌海上山，天瓢承露結金丹。',32,'御定全唐詩/json/858.json','["醉舞高歌海上山，天瓢承露結金丹。", "夜深鶴透秋空碧，萬里西風一劍寒。"]'),
('yuding-38','謁石守道','呂岩','唐','御定全唐诗','yuding','','[]','高心休擬鳳池游，朱紱銀章寵已優。',32,'御定全唐詩/json/858.json','["高心休擬鳳池游，朱紱銀章寵已優。", "欲待禍來名欲滅，林泉養法預為謀。"]'),
('yuding-39','題廣陵妓屏二首','呂岩','唐','御定全唐诗','yuding','','[]','嫫母西施共此身，可憐老少隔千春。',64,'御定全唐詩/json/858.json','["嫫母西施共此身，可憐老少隔千春。", "他年鶴發雞皮媼，今日玉顏花貌人。", "花開花落兩悲歡，花與人還事一般。", "開在枝間妨客折，落來地上請誰看。"]'),
('yuding-40','題東都妓館壁','呂岩','唐','御定全唐诗','yuding','','[]','一吸鸞笙裂太清，綠衣童子步虛聲。',32,'御定全唐詩/json/858.json','["一吸鸞笙裂太清，綠衣童子步虛聲。", "玉樓喚醒千年夢，碧桃枝上金雞鳴。"]'),
('yuding-41','崔中舉進士游岳陽遇真人錄沁園春詞詰其姓名…留詩于壁','呂岩','唐','御定全唐诗','yuding','','[]','腹內嬰兒養已成，且居廛市暫娛情。',32,'御定全唐詩/json/858.json','["腹內嬰兒養已成，且居廛市暫娛情。", "無端措大剛饒舌，卻入白雲深處行。"]'),
('yuding-42','題詩紫極宮','呂岩','唐','御定全唐诗','yuding','','[]','宮門一閑入，臨水憑欄立。無人知我來，朱頂鶴聲急。',24,'御定全唐詩/json/858.json','["宮門一閑入，臨水憑欄立。無人知我來，朱頂鶴聲急。"]'),
('yuding-43','閑題','呂岩','唐','御定全唐诗','yuding','','[]','獨自行來獨自坐，無限世人不識我。',32,'御定全唐詩/json/858.json','["獨自行來獨自坐，無限世人不識我。", "惟有城南老樹精，分明知道神仙過。"]'),
('yuding-44','山隱','呂岩','唐','御定全唐诗','yuding','','[]','松枯石老水縈回，個裏難教俗客來。',32,'御定全唐詩/json/858.json','["松枯石老水縈回，個裏難教俗客來。", "抬眼試看山外景，紛紛風急障黃埃。"]'),
('yuding-45','絕句','呂岩','唐','御定全唐诗','yuding','','[]','息精息氣養精神，精養丹田氣養身。',96,'御定全唐詩/json/858.json','["息精息氣養精神，精養丹田氣養身。", "有人學得這般術，便是長生不死人。", "斗笠為帆扇作舟，五湖四海任遨遊。", "大千沙界須臾至，石爛松枯經幾秋。", "或為道士或為僧，混俗和光別有能。", "苦海翻成天上路，毗盧常照百千燈。"]'),
('yuding-46','勸世','呂岩','唐','御定全唐诗','yuding','','[]','一毫之善，與人方便。一毫之惡，勸君莫作。衣食隨緣，',45,'御定全唐詩/json/858.json','["一毫之善，與人方便。一毫之惡，勸君莫作。衣食隨緣，", "天眼昭昭，報應甚速。諦聽吾言，神欽鬼伏。"]'),
('yuding-47','窯頭坯歌','呂岩','唐','御定全唐诗','yuding','','[]','窯頭坯，隨雨破，只是未曾經水火。若經水火燒成磚，',338,'御定全唐詩/json/858.json','["窯頭坯，隨雨破，只是未曾經水火。若經水火燒成磚，", "凡水火，尚成功，堅完萬物誰能同。修行路上多少人，", "既不悟，終不悔，死了猶來借精髓。主持正念大艱辛，", "執迷不悟修真理，焉知潛合造化功。又不見九江張尚書，", "又不見三衢趙樞密，參禪作鬼終不識。修完外體在何邊，", "大丈夫，超覺性，了盡空門不為證。伏羲傳道至於今，", "坎離即是真常家，見者超凡須入聖。坎是虎，離是龍，", "剝而複，否而泰，進退往來定交會。弦而望，明而晦，", "餌之千日功便成，金筋玉骨身已輕。此個景象惟自身，", "飲凡酒，食膻腥，補養元和沖更盈。自融結，轉光明，", "不食方為真絕糧，真氣薰蒸肢體強。既不食，超百億，", "到此遂成無漏身，胎息丹田湧真火。老氏自此號嬰兒，", "真人出現大神通，從此天仙可相賀。聖賢三教不異門，", "學人學人細尋覓，且須研究古金碧。金碧參同不計年，"]'),
('yuding-0','贈劉方處士','呂岩','唐','御定全唐诗','yuding','','[]','六國愁看沉與浮，攜琴長嘯出神州。擬向煙霞煮白石，',241,'御定全唐詩/json/859.json','["六國愁看沉與浮，攜琴長嘯出神州。擬向煙霞煮白石，", "年來摘得黃岩翠，琪樹參差連地肺。露飄香隴玉苗滋，", "忽因乘興下白雲，與君邂逅於塵世。塵世相逢開口希，", "醉中亦話興亡事，雲道總無珪組累。浮世短景倏成空，", "芳樽但繼曉複昏，樂事不窮今與古。何如識個玄玄道，", "但能制得水中華，水火翻成金丹灶。丹就人間不久居，", "鸞車鶴駕逐雲飛，迢迢瑤池應易到。耳聞爭戰還傾覆，", "蜉蝣世界實足悲，槿花性命莫遲遲。珠璣溢屋非為福，", "劉方劉方審聽我，流光迅速如飛過。陰b2果決用心除，", "破車壞鉛須震驚，直遇伯陽應不可。悠悠憂家複憂國，"]'),
('yuding-1','寄白龍洞劉道人','呂岩','唐','御定全唐诗','yuding','','[]','玉走金飛兩曜忙，始聞花發又秋霜。徒誇篯壽千來歲，',259,'御定全唐詩/json/859.json','["玉走金飛兩曜忙，始聞花發又秋霜。徒誇篯壽千來歲，", "其間寒暑互煎熬，不覺童顏暗中失。縱有兒孫滿眼前，", "延年之道既無計，不免將身歸逝水。但看古往聖賢人，", "競向山中尋草藥，伏鉛制汞點丹陽。點丹陽，事迥別，", "時節正，用媒人，金翁姹女結親姻。金翁偏愛騎白虎，", "兩獸相逢戰一場，波浪奔騰如鼎沸。黃婆丁老助威靈，", "從此根芽漸長成，隨時灌溉抱真精。十月脫胎吞入口，", "宿世若無仙骨分，容易如何得遇之。金液丹，宜便煉，", "莫教燭被風吹滅，六道輪回難怨天。近來世上人多詐，", "卻雲服氣與休糧，別有門庭道路長。豈不見陰君破迷歌裏說，", "惟君心與我心同，方敢傾心與君說。"]'),
('yuding-2','贈喬二郎','呂岩','唐','御定全唐诗','yuding','','[]','與君相見皇都裏，陶陶動便經年醉。醉中往往愛藏真，',112,'御定全唐詩/json/859.json','["與君相見皇都裏，陶陶動便經年醉。醉中往往愛藏真，", "煙霞欲去如何去，先須肘後飛金晶。金晶飛到上宮裏，", "從此夫妻相際會，歡娛踴躍情無外。水火都來兩半間，", "到底根元是何物，分明只是水中金。喬公喬公急下手，", "人道長生沒得來，自古至今有有有。"]'),
('yuding-3','鄂渚悟道歌','呂岩','唐','御定全唐诗','yuding','','[]','縱橫天際為閑客，時遇季秋重陽節。陰雲一布遍長空，',160,'御定全唐詩/json/859.json','["縱橫天際為閑客，時遇季秋重陽節。陰雲一布遍長空，", "試問鄰公可相傳，一言許肯更無難。數篇奇怪文入手，", "恍惚之中見有物，狀如日輪明突屼。自言便是丹砂精，", "不用鉛，不用汞，還丹須向爐中種。玄中之玄號真鉛，", "丹砂一粒名千般，一中有一為丹母。火莫燃，水莫凍，", "龍吞玄寶忽升飛，飛龍被我捉來騎。一翥上朝歸碧落，", "自從修到無為地，始覺奇之又怪之。"]'),
('yuding-4','又記','呂岩','唐','御定全唐诗','yuding','','[]','數載樂幽幽，欲逃寒暑逼。不求名與利，猶恐身心役。',276,'御定全唐詩/json/859.json','["數載樂幽幽，欲逃寒暑逼。不求名與利，猶恐身心役。", "苦志慕黃庭，殷勤求道跡。陰功暗心修，善行長日積。", "世路果逢師，時人皆不識。我師機行密，懷量性孤僻。", "解把五行移，能將四象易。傳餘造化門，始悟希夷則。", "服取兩般真，從頭路端的。烹煎日月壺，不離乾坤側。", "至道眼前觀，得之元咫尺。真空空不空，真色色非色。", "推倒玉葫蘆，迸出黃金液。緊把赤龍頭，猛將驪珠吸。", "吞歸臟腑中，奪得神仙力。妙號一黍珠，延年千萬億。", "同途聽我吟，與道相親益。未曉真黃芽，徒勞遊紫陌。", "把住赤烏魂，突出銀蟾魄。未省此中玄，常流容易測。", "三天應有路，九地終無厄。守道且藏愚，忘機要混跡。", "群生莫相輕，已是蓬萊客。"]'),
('yuding-5','秘訣歌','呂岩','唐','御定全唐诗','yuding','','[]','求之不見，來即不見。不見不見，君之素面。火裏曾飛，',25,'御定全唐詩/json/859.json','["求之不見，來即不見。不見不見，君之素面。火裏曾飛，"]'),
('yuding-6','勉牛生、夏侯生','呂岩','唐','御定全唐诗','yuding','','[]','二秀才，二秀才兮非秀才，非秀才兮是仙才。',128,'御定全唐詩/json/859.json','["二秀才，二秀才兮非秀才，非秀才兮是仙才。", "中華國裏親遭遇，仰面觀天笑眼開。鶴形兮龜骨，", "但煦日吹月，咽雨呵雷。火寄冥宮，水濟丹台。", "金木交而土歸位，鉛汞分而丹露胎。赤血換而白乳流，", "孩兒喘而不死，腹空虛兮長齋。酬名利兮狂歌醉舞，", "青山白雲好居住，勸君歸去來兮歸去來。"]'),
('yuding-7','題四明金鵝寺壁','呂岩','唐','御定全唐诗','yuding','','[]','方丈有門出不鑰，見個山童露雙腳。問伊方丈何寂寥，',48,'御定全唐詩/json/859.json','["方丈有門出不鑰，見個山童露雙腳。問伊方丈何寂寥，", "我來謁見不得見，謁心耿耿生埃塵。歸去也，波浩渺，"]'),
('yuding-8','穀神歌','呂岩','唐','御定全唐诗','yuding','','[]','我有一腹空穀虛，言之道有又還無。言之無兮不可舍，',142,'御定全唐詩/json/859.json','["我有一腹空穀虛，言之道有又還無。言之無兮不可舍，", "保之守之不死名，修之煉之仙人號。神得一以靈，", "龍又吟，虎又嘯，風雲際會黃婆叫。火中姹女正含嬌，", "金殿玉堂門十二，金翁木母正來過。重門過後牢關鎖，", "曲江東岸金烏飛，西岸清光玉兔輝。烏兔走歸峰頂上，", "十月情濃產一男，說道長生永不死。勸君煉，勸君修，"]'),
('yuding-9','修身訣','呂岩','唐','御定全唐诗','yuding','','[]','人命急如線，上下來往速如箭。認得是元神，',44,'御定全唐詩/json/859.json','["人命急如線，上下來往速如箭。認得是元神，", "既得一，勿遺失，失了永求無一物。堪歎荒郊塚墓中，"]'),
('yuding-10','長短句','呂岩','唐','御定全唐诗','yuding','','[]','落魄且落魄，夜宿鄉村，朝遊城郭。閑來無事玩青山，',40,'御定全唐詩/json/859.json','["落魄且落魄，夜宿鄉村，朝遊城郭。閑來無事玩青山，", "醉後吟哦動鬼神，任意日頭向西落。"]'),
('yuding-11','直指大丹歌','呂岩','唐','御定全唐诗','yuding','','[]','三清宮殿隱昆巔，日月光浮起紫煙。池沼泓泓翻玉液，',72,'御定全唐詩/json/859.json','["三清宮殿隱昆巔，日月光浮起紫煙。池沼泓泓翻玉液，", "欲得坎男求匹偶，須憑離女結因緣。黃婆設盡千般計，", "黑龜卻伏紅爐下，朱雀還棲華閣前。然後澄神窺見影，"]'),
('yuding-12','漁父詞一十八首：入定','呂岩','唐','御定全唐诗','yuding','','[]','閉目藏真神思凝，杳冥中裏見吾宗。',32,'御定全唐詩/json/859.json','["閉目藏真神思凝，杳冥中裏見吾宗。", "無邊畔，迥朦朧，玄景觀來覺盡空。"]'),
('yuding-13','漁父詞一十八首：初九','呂岩','唐','御定全唐诗','yuding','','[]','大道從來屬自然。空堂寂坐守機關。',32,'御定全唐詩/json/859.json','["大道從來屬自然。空堂寂坐守機關。", "三田寶，鎮長存，赤帝分明坐廣寒。"]'),
('yuding-14','漁父詞一十八首：玄用','呂岩','唐','御定全唐诗','yuding','','[]','日月交加曉夜奔，昆侖頂上定乾坤。',32,'御定全唐詩/json/859.json','["日月交加曉夜奔，昆侖頂上定乾坤。", "真鏡裏，實堪論，靉靉紅霞曉寂門。"]'),
('yuding-15','漁父詞一十八首：神效','呂岩','唐','御定全唐诗','yuding','','[]','恍惚擒來得自然，偷他造化在其間。',32,'御定全唐詩/json/859.json','["恍惚擒來得自然，偷他造化在其間。", "神鼎內，火烹煎，盡曆陰陽結作丹。"]'),
('yuding-16','漁父詞一十八首：沐浴','呂岩','唐','御定全唐诗','yuding','','[]','卯酉門中作用時，赤龍時蘸玉清池。',32,'御定全唐詩/json/859.json','["卯酉門中作用時，赤龍時蘸玉清池。", "雲薄薄，雨微微，看取妖容露雪肌。"]'),
('yuding-17','漁父詞一十八首：延壽','呂岩','唐','御定全唐诗','yuding','','[]','子午常餐日月精，玄關門戶啟還扃。',32,'御定全唐詩/json/859.json','["子午常餐日月精，玄關門戶啟還扃。", "長如此，過平生，且把陰陽子細烹。"]'),
('yuding-18','漁父詞一十八首：瑞鼎','呂岩','唐','御定全唐诗','yuding','','[]','會合都從戊巳家，金鉛水汞莫須誇。',32,'御定全唐詩/json/859.json','["會合都從戊巳家，金鉛水汞莫須誇。", "只此物，結丹砂，反復陰陽色轉華。"]'),
('yuding-19','漁父詞一十八首：活得','呂岩','唐','御定全唐诗','yuding','','[]','位立三才屬五行，陰陽合處便相生。',32,'御定全唐詩/json/859.json','["位立三才屬五行，陰陽合處便相生。", "龍飛踴，虎狌獰，吐個神珠各戰爭。"]'),
('yuding-20','漁父詞一十八首：燦爛','呂岩','唐','御定全唐诗','yuding','','[]','四象分明八卦周，乾坤男女論綢繆。',32,'御定全唐詩/json/859.json','["四象分明八卦周，乾坤男女論綢繆。", "交會處，更嬌羞，轉覺情深玉體柔。"]'),
('yuding-21','漁父詞一十八首：煉質','呂岩','唐','御定全唐诗','yuding','','[]','運本還元於此尋，周流金鼎虎龍吟。',32,'御定全唐詩/json/859.json','["運本還元於此尋，周流金鼎虎龍吟。", "身不老，俗難侵，貌返童顏骨變金。"]'),
('yuding-22','漁父詞一十八首：神異','呂岩','唐','御定全唐诗','yuding','','[]','還返初成立變童，瑞蓮開處色輝紅。',32,'御定全唐詩/json/859.json','["還返初成立變童，瑞蓮開處色輝紅。", "金鼎內，迥朦朧，換骨添筋處處通。"]'),
('yuding-23','漁父詞一十八首：知路','呂岩','唐','御定全唐诗','yuding','','[]','那個仙經述此方，參同大易顯陰陽。',32,'御定全唐詩/json/859.json','["那個仙經述此方，參同大易顯陰陽。", "須窮取，莫顛狂，會者名高道自昌。"]'),
('yuding-24','漁父詞一十八首：朝帝','呂岩','唐','御定全唐诗','yuding','','[]','九轉功成數盡幹，開爐撥鼎見金丹。',32,'御定全唐詩/json/859.json','["九轉功成數盡幹，開爐撥鼎見金丹。", "餐餌了，別塵寰，足躡青雲突上天。"]'),
('yuding-25','漁父詞一十八首：方契理','呂岩','唐','御定全唐诗','yuding','','[]','舉世人生何所依，不求自己更求誰。',32,'御定全唐詩/json/859.json','["舉世人生何所依，不求自己更求誰。", "絕嗜欲，斷貪癡，莫把神明暗裏欺。"]'),
('yuding-26','漁父詞一十八首：自無憂','呂岩','唐','御定全唐诗','yuding','','[]','學道初從此處修，斷除貪愛別嬌柔。',32,'御定全唐詩/json/859.json','["學道初從此處修，斷除貪愛別嬌柔。", "長守靜，處深幽，服氣餐霞飽即休。"]'),
('yuding-27','漁父詞一十八首：作甚物','呂岩','唐','御定全唐诗','yuding','','[]','貪貴貪榮逐利名，追遊醉後戀歡情。',32,'御定全唐詩/json/859.json','["貪貴貪榮逐利名，追遊醉後戀歡情。", "年不永，代君驚，一報身終那裏生。"]'),
('yuding-28','漁父詞一十八首：疾瞥地','呂岩','唐','御定全唐诗','yuding','','[]','萬劫千生得個人，須知先世種來因。',32,'御定全唐詩/json/859.json','["萬劫千生得個人，須知先世種來因。", "速覺悟。出迷津，莫使輪回受苦辛。"]'),
('yuding-29','漁父詞一十八首：常自在','呂岩','唐','御定全唐诗','yuding','','[]','閉目尋真真自歸，玄珠一顆出輝輝。',32,'御定全唐詩/json/859.json','["閉目尋真真自歸，玄珠一顆出輝輝。", "終日玩，莫拋離，免使閻王遣使追。"]'),
('yuding-30','口占','呂岩','唐','御定全唐诗','yuding','','[]','非神亦非仙，非術亦非幻。天地有終窮，桑田幾遷變。',48,'御定全唐詩/json/859.json','["非神亦非仙，非術亦非幻。天地有終窮，桑田幾遷變。", "身固非我有，財亦何足戀。曷不從吾遊，騎鯨騰汗漫。"]'),
('yuding-31','敲爻歌','呂岩','唐','御定全唐诗','yuding','','[]','漢終唐國飄蓬客，所以敲爻不可測。縱橫逆順沒遮欄，',576,'御定全唐詩/json/859.json','["漢終唐國飄蓬客，所以敲爻不可測。縱橫逆順沒遮欄，", "行歌唱詠胭粉詞，持戒酒肉常充腹。色是藥，酒是祿，", "不破戒，不犯淫，破戒真如性即沈。犯淫壞失長生寶，", "花街柳巷覓真人，真人只在花街玩。摘花戴飲長生酒，", "到此鄉，非常客，姹女嬰兒生喜樂。洞中常采四時花，", "時人不達花中理，一訣天機直萬金。謝天地，感虛空，", "第一峰，是仙物，惟產金花生恍惚。口口相傳不記文，", "七七白虎雙雙養，八八青龍總一斤。真父母，送元宮，", "鉛初就，汞初生，玉爐金鼎未經烹。一夫一婦同天地，", "拔取天根並地髓，白雪黃芽自長成。鉛亦生，汞亦生，", "黃婆匹配得團圓，時刻無差口付傳。八卦三元全藉汞，", "杳杳冥冥生恍惚，恍恍惚惚結成團。性須空，意要專，", "玉爐中，文火爍，十二時中惟守一。此時黃道會陰陽，", "加添火候切防危，初九潛龍不可煉。消息火，刀圭變，", "火足數，藥方成，便有龍吟虎嘯聲。三鉛只得一鉛就，", "日精才現月華凝，二八相交在壬丙。龍汞結，虎鉛成，", "達此理，道方成，三萬神龍護水晶。守時定日明符刻，", "三車搬運珍珠寶，送歸寶藏自通靈。天神佑，地祇迎，", "朱砂配，水銀停，一派紅霞列太清。鉛池迸出金光現，", "一時辰內金丹就，上朝金闕紫雲生。仙桃熟。摘取餌，", "參同理，煉金丹，水火薰蒸透百關。養胎十月神丹結，", "結成一塊紫金丸，變化飛騰天地久。丹入腹，非尋常，", "三清客，駕瓊輿，跨鳳騰霄入太虛。似此逍遙多快樂，", "一物無，唯顯道，五方透出真人貌。仙童仙女彩雲迎，"]'),
('yuding-32','三字訣','呂岩','唐','御定全唐诗','yuding','','[]','這個道，非常道。性命根，生死竅。說著醜，行著妙。',184,'御定全唐詩/json/859.json','["這個道，非常道。性命根，生死竅。說著醜，行著妙。", "人人憎，個個笑。大關鍵，在顛倒。莫厭穢，莫計較。", "得他來，立見效。地天泰，為朕兆。口對口，竅對竅。", "吞入腹，自知道。藥苗新，先天兆。審眉間，行逆道。", "滓質物，自繼紹。二者餘，方絕妙。要行持，令人叫。", "氣要堅，神莫耗。若不行，空老耄。認得真，老還少。", "不知音，莫語要。些兒法，合大道。精氣神，不老藥。", "靜裏全，明中報。乘鳳鸞，聽天詔。"]'),
('yuding-33','百字碑','呂岩','唐','御定全唐诗','yuding','','[]','養氣忘言守，降心為不為。動靜知宗祖，無事更尋誰。',120,'御定全唐詩/json/859.json','["養氣忘言守，降心為不為。動靜知宗祖，無事更尋誰。", "真常須應物，應物要不迷。不迷性自住，性住氣自回。", "氣回丹自結，壺中配坎離。陰陽生返複，普化一聲雷。", "白雲朝頂上，甘露灑須彌。自飲長生酒，逍遙誰得知。", "坐聽無弦曲，明通造化機。都來二十句，端的上天梯。"]'),
('yuding-34','句','呂岩','唐','御定全唐诗','yuding','','[]','莫道神仙無學處，古今多少上升人。',16,'御定全唐詩/json/859.json','["莫道神仙無學處，古今多少上升人。"]'),
('yuding-0','四言詩','孫思邈','唐','御定全唐诗','yuding','','[]','取金之精，合石之液。列為夫婦，結為魂魄。一體混沌，',100,'御定全唐詩/json/860.json','["取金之精，合石之液。列為夫婦，結為魂魄。一體混沌，", "煙未及黔，焰不假碧。如畜扶桑，若藏霹靂。姹女氣索，", "宛其死矣，適然從革。惡黜善遷，情回性易。紫色內達，", "霧散五內，川流百脈。骨變金植，顏駐玉澤。陽德乃敷，"]'),
('yuding-1','留詩','葉法善','唐','御定全唐诗','yuding','','[]','昔在禹餘天，還依太上家。忝以掌仙錄，去來乘煙霞。',144,'御定全唐詩/json/860.json','["昔在禹餘天，還依太上家。忝以掌仙錄，去來乘煙霞。", "暫下宛利城，渺然思金華。自此非久住，雲上登香車。", "適向人間世，時複濟蒼生。度人初行滿，輔國亦功成。", "但念清微樂，誰忻下界榮。門人好住此，翛然雲上征。", "退仙時此地，去俗久為榮。今日登雲天，歸真遊上清。", "泥丸空示世，騰舉不為名。為報學仙者，知餘朝玉京。"]'),
('yuding-2','題登真洞','張果','唐','御定全唐诗','yuding','','[]','修成金骨煉歸真，洞鎖遺蹤不計春。野草謾隨青嶺秀，',40,'御定全唐詩/json/860.json','["修成金骨煉歸真，洞鎖遺蹤不計春。野草謾隨青嶺秀，", "自是神仙多變異，肯教蹤跡掩紅塵。"]'),
('yuding-3','負薪行','許宣平','唐','御定全唐诗','yuding','','[]','負薪朝出賣，沽酒日西歸。路人莫問歸何處，',20,'御定全唐詩/json/860.json','["負薪朝出賣，沽酒日西歸。路人莫問歸何處，"]'),
('yuding-4','庵壁題詩','許宣平','唐','御定全唐诗','yuding','','[]','隱居三十載，石室南山巔。靜夜玩明月，清朝飲碧泉。',48,'御定全唐詩/json/860.json','["隱居三十載，石室南山巔。靜夜玩明月，清朝飲碧泉。", "樵人歌壟上，穀鳥戲岩前。樂矣不知老，都忘甲子年。"]'),
('yuding-5','見李白詩又吟','許宣平','唐','御定全唐诗','yuding','','[]','一池荷葉衣無盡，兩畝黃精食有餘。',32,'御定全唐詩/json/860.json','["一池荷葉衣無盡，兩畝黃精食有餘。", "又被人來尋討著，移庵不免更深居。"]'),
('yuding-6','題壁','成真人','唐','御定全唐诗','yuding','','[]','蜀路南行，燕師北至。本擬白日升天，且看黑龍飲渭。',24,'御定全唐詩/json/860.json','["蜀路南行，燕師北至。本擬白日升天，且看黑龍飲渭。"]'),
('yuding-7','對趙潁歌','朱子真','唐','御定全唐诗','yuding','','[]','人間幾日變桑田，誰識神仙洞裏天。',32,'御定全唐詩/json/860.json','["人間幾日變桑田，誰識神仙洞裏天。", "短促共知有□異，且須歡醉在生前。"]'),
('yuding-8','兜玄國懷歸詩','申歡','唐','御定全唐诗','yuding','','[]','風軟景和煦，異香馥林塘。登高一長望，信美非吾鄉。',24,'御定全唐詩/json/860.json','["風軟景和煦，異香馥林塘。登高一長望，信美非吾鄉。"]'),
('yuding-9','題壁','李遐周','唐','御定全唐诗','yuding','','[]','燕市人皆去，函關馬不歸。若逢山下鬼，環上系羅衣。',24,'御定全唐詩/json/860.json','["燕市人皆去，函關馬不歸。若逢山下鬼，環上系羅衣。"]'),
('yuding-10','遺簡詩','趙惠宗','唐','御定全唐诗','yuding','','[]','生我於虛，置我於無。至精為神，元氣為軀。散陽為明，',50,'御定全唐詩/json/860.json','["生我於虛，置我於無。至精為神，元氣為軀。散陽為明，", "吾駕時馬，日月為衛。洞耀九霄，上謁天帝。明明我眾，"]'),
('yuding-11','遇蓮葉二客詩','欒清','唐','御定全唐诗','yuding','','[]','得飲攄公酒，複登攄公舟。便得神體清，超遙曠無憂。',24,'御定全唐詩/json/860.json','["得飲攄公酒，複登攄公舟。便得神體清，超遙曠無憂。"]'),
('yuding-12','附：蓮葉二客詩','不詳','唐','御定全唐诗','yuding','','[]','行時雲作伴，坐即酒為侶。腹以元化充，衣將雲霞補。',72,'御定全唐詩/json/860.json','["行時雲作伴，坐即酒為侶。腹以元化充，衣將雲霞補。", "紂虐與堯仁，可惜皆朽腐。", "楫棹無所假，超然信萍查。朝浮旭日輝，夕蔭清月華。", "營營功業人，朽骨成泥沙。"]'),
('yuding-13','言志','韓湘','唐','御定全唐诗','yuding','','[]','青山雲水窟，此地是吾家。後夜流瓊液，淩晨咀絳霞。',84,'御定全唐詩/json/860.json','["青山雲水窟，此地是吾家。後夜流瓊液，淩晨咀絳霞。", "琴彈碧玉調，爐煉白朱砂。寶鼎存金虎，元田養白鴉。", "一瓢藏世界，三尺斬妖邪。解造逡巡酒，能開頃刻花。", "有人能學我，同去看仙葩。"]'),
('yuding-14','答從叔愈','韓湘','唐','御定全唐诗','yuding','','[]','舉世都為名利醉，伊予獨向道中醒。',32,'御定全唐詩/json/860.json','["舉世都為名利醉，伊予獨向道中醒。", "他時定是飛升去，衝破秋空一點青。"]'),
('yuding-15','題院詩','侯道華','唐','御定全唐诗','yuding','','[]','帖裏大還丹，多年色不移。前宵盜吃卻，今日碧空飛。',72,'御定全唐詩/json/860.json','["帖裏大還丹，多年色不移。前宵盜吃卻，今日碧空飛。", "慚愧深珍重，珍重鄧天師。他年煉得藥，留著與內芝。", "吾師知此術，速煉莫為遲。三清專相待，大羅的有期。"]'),
('yuding-16','贈樊夫人詩','裴航','唐','御定全唐诗','yuding','','[]','向為胡越猶懷想，況遇天仙隔錦屏。',32,'御定全唐詩/json/860.json','["向為胡越猶懷想，況遇天仙隔錦屏。", "儻若玉京朝會去，願隨鸞鶴入青冥。"]'),
('yuding-17','附：樊夫人答裴航','樊夫人','唐','御定全唐诗','yuding','','[]','一飲瓊漿百感生，玄霜搗盡見雲英。',32,'御定全唐詩/json/860.json','["一飲瓊漿百感生，玄霜搗盡見雲英。", "藍橋便是神仙窟，何必崎嶇上玉清。"]'),
('yuding-18','題長安酒肆壁三絕句','鐘離權','唐','御定全唐诗','yuding','','[]','坐臥常攜酒一壺，不教雙眼識皇都。',96,'御定全唐詩/json/860.json','["坐臥常攜酒一壺，不教雙眼識皇都。", "乾坤許大無名姓，疏散人中一丈夫。", "得道高僧不易逢，幾時歸去願相從。", "自言住處連滄海，別是蓬萊第一峰。", "莫厭追歡笑語頻，尋思離亂好傷神。", "閑來屈指從頭數，得見清平有幾人。"]'),
('yuding-19','贈呂洞賓','鐘離權','唐','御定全唐诗','yuding','','[]','知君幸有英靈骨，所以教君心恍惚。含元殿上水晶宮，',119,'御定全唐詩/json/860.json','["知君幸有英靈骨，所以教君心恍惚。含元殿上水晶宮，", "五行匹配自刀圭，執取龜蛇顛倒訣。三屍神，須打徹，", "九九道至成真日，三界四府朝元節。氣翱翔兮神烜赫，", "道心不退故傳君，立誓約言親灑血。逢人兮莫亂說，", "執手相別意如何，今日為君重作歌。說盡千般玄妙理，"]'),
('yuding-0','登杭州秦望山','馬湘','唐','御定全唐诗','yuding','','[]','太乙初分何處尋，空留歷數變人心。九天日月移朝暮，',40,'御定全唐詩/json/861.json','["太乙初分何處尋，空留歷數變人心。九天日月移朝暮，", "秦皇謾作驅山計，滄海茫茫轉更深。"]'),
('yuding-1','題龍興觀壁','馬湘','唐','御定全唐诗','yuding','','[]','世有無窮事，生知遂百春。問程方外路，宜是上清人。',24,'御定全唐詩/json/861.json','["世有無窮事，生知遂百春。問程方外路，宜是上清人。"]'),
('yuding-2','又詩一首','馬湘','唐','御定全唐诗','yuding','','[]','昔日曾隨魏伯陽，無端醉臥紫金床。',32,'御定全唐詩/json/861.json','["昔日曾隨魏伯陽，無端醉臥紫金床。", "東君謂我多情賴，罰向人間作酒狂。"]'),
('yuding-3','又詩二首','馬湘','唐','御定全唐诗','yuding','','[]','省悟前非一息間，更拋閒事棄塵寰。徒誇美酒如瓊液，',72,'御定全唐詩/json/861.json','["省悟前非一息間，更拋閒事棄塵寰。徒誇美酒如瓊液，", "雲中幸有堪歸路，無限青山是我山。", "何用燒丹學駐顏，鬧非城市靜非山。", "時人若覓長生藥，對景無心是大還。"]'),
('yuding-4','題壁','張辭','唐','御定全唐诗','yuding','','[]','爭那金烏何，頭上飛不住。紅爐漫燒藥，玉顏安可駐。',48,'御定全唐詩/json/861.json','["爭那金烏何，頭上飛不住。紅爐漫燒藥，玉顏安可駐。", "今年花發枝，明年葉落樹。不如且飲酒，莫管流年度。"]'),
('yuding-5','上鹽城令述德詩','張辭','唐','御定全唐诗','yuding','','[]','門風常有蕙蘭馨，鼎族家傳霸國名。容貌靜懸秋月彩，',40,'御定全唐詩/json/861.json','["門風常有蕙蘭馨，鼎族家傳霸國名。容貌靜懸秋月彩，", "今日東漸橋下水，一條從此鎮常清。"]'),
('yuding-6','謝令學道詩','張辭','唐','御定全唐诗','yuding','','[]','何用梯媒向外求，長生只合內中修。',32,'御定全唐詩/json/861.json','["何用梯媒向外求，長生只合內中修。", "莫言大道人難得，自是行心不到頭。"]'),
('yuding-7','別令詩','張辭','唐','御定全唐诗','yuding','','[]','張辭張辭自不會，天下經書在腹內。',32,'御定全唐詩/json/861.json','["張辭張辭自不會，天下經書在腹內。", "身即騰騰處世間，心即逍遙出天外。"]'),
('yuding-8','贈吳生','陸禹臣','唐','御定全唐诗','yuding','','[]','露下瑤簪濕，雲生石室寒。星壇鸞鶴舞，丹灶虎龍蟠。',24,'御定全唐詩/json/861.json','["露下瑤簪濕，雲生石室寒。星壇鸞鶴舞，丹灶虎龍蟠。"]'),
('yuding-9','丈人山詩','李真','唐','御定全唐诗','yuding','','[]','春凍曉韉露重，夜寒幽枕雲生。',28,'御定全唐詩/json/861.json','["春凍曉韉露重，夜寒幽枕雲生。", "豈是與山無素，丈人著帽相迎。"]'),
('yuding-10','醉歌','殷七七','唐','御定全唐诗','yuding','','[]','琴彈碧玉調，藥煉白朱砂。解醞頃刻酒，能開非時花。',24,'御定全唐詩/json/861.json','["琴彈碧玉調，藥煉白朱砂。解醞頃刻酒，能開非時花。"]'),
('yuding-11','陽春曲','殷七七','唐','御定全唐诗','yuding','','[]','愁見唱陽春，令人離腸結。郎去未歸家，柳自飄香雪。',24,'御定全唐詩/json/861.json','["愁見唱陽春，令人離腸結。郎去未歸家，柳自飄香雪。"]'),
('yuding-12','寄杜光庭','張令問','唐','御定全唐诗','yuding','','[]','試問朝中為宰相，何如林下作神仙。',32,'御定全唐詩/json/861.json','["試問朝中為宰相，何如林下作神仙。", "一壺美酒一爐藥，飽聽松風清晝眠。"]'),
('yuding-13','上升歌','吳涵虛','唐','御定全唐诗','yuding','','[]','玉皇有詔登仙職，龍吐雲兮鳳著力。眼前驀地見樓臺，',40,'御定全唐詩/json/861.json','["玉皇有詔登仙職，龍吐雲兮鳳著力。眼前驀地見樓臺，", "當時不為上升忙，一時提向瀛洲賣。"]'),
('yuding-14','答常學士','李夢符','唐','御定全唐诗','yuding','','[]','罷修儒業罷修真，養拙藏愚春複春。到老不疏林裏鹿，',40,'御定全唐詩/json/861.json','["罷修儒業罷修真，養拙藏愚春複春。到老不疏林裏鹿，", "深謝名賢遠相訪，求聞難博鳳為鄰。"]'),
('yuding-15','漁父引二首','李夢符','唐','御定全唐诗','yuding','','[]','村寺鐘聲度遠灘，半輪殘月落山前。',64,'御定全唐詩/json/861.json','["村寺鐘聲度遠灘，半輪殘月落山前。", "徐徐撥棹卻歸灣，浪疊朝霞錦繡翻。", "漁弟漁兄喜到來，波官賽卻坐江隈。", "椰榆杓子木瘤杯，爛煮鱸魚滿案堆。"]'),
('yuding-16','察考取狀答','李夢符','唐','御定全唐诗','yuding','','[]','插花飲酒何妨事，樵唱漁歌不礙時。',16,'御定全唐詩/json/861.json','["插花飲酒何妨事，樵唱漁歌不礙時。"]'),
('yuding-17','答高安宰','沈廷瑞','唐','御定全唐诗','yuding','','[]','何須問我道成時，紫府清都自有期。',32,'御定全唐詩/json/861.json','["何須問我道成時，紫府清都自有期。", "手握藥苗人不識，體含金骨俗爭知。"]'),
('yuding-18','贈僧昭瑩','沈廷瑞','唐','御定全唐诗','yuding','','[]','南北東西路，人生會不無。早曾依閣皂，又卻上玄都。',48,'御定全唐詩/json/861.json','["南北東西路，人生會不無。早曾依閣皂，又卻上玄都。", "雲片隨天闊，泉聲落石孤。何期早相遇，樂共煮菖蒲。"]'),
('yuding-19','寄袁州陳智周','沈廷瑞','唐','御定全唐诗','yuding','','[]','名山相別後，別後會難期。金鼎銷紅日，丹田老紫芝。',48,'御定全唐詩/json/861.json','["名山相別後，別後會難期。金鼎銷紅日，丹田老紫芝。", "訪君雖有路，懷我豈無詩。休羨繁華事，百年能幾時。"]'),
('yuding-20','壟穴遺詩','沈廷瑞','唐','御定全唐诗','yuding','','[]','虛勞營殯玉山前，殯後那知已脫蟬。應是元神歸洞府，',40,'御定全唐詩/json/861.json','["虛勞營殯玉山前，殯後那知已脫蟬。應是元神歸洞府，", "堪歎浮生今古事，北邙山下草芊芊。"]'),
('yuding-21','大言詩','譚峭','唐','御定全唐诗','yuding','','[]','線作長江扇作天，靸鞋拋向海東邊。',32,'御定全唐詩/json/861.json','["線作長江扇作天，靸鞋拋向海東邊。", "蓬萊通道無多路，只在譚生拄杖前。"]'),
('yuding-22','句','譚峭','唐','御定全唐诗','yuding','','[]','雲外星霜如走電，世間娛樂似拋磚。',16,'御定全唐詩/json/861.json','["雲外星霜如走電，世間娛樂似拋磚。"]'),
('yuding-23','望江南詞詠鼓','伊用昌','唐','御定全唐诗','yuding','','[]','江南鼓，梭肚兩頭欒。釘著不知侵骨髓，',18,'御定全唐詩/json/861.json','["江南鼓，梭肚兩頭欒。釘著不知侵骨髓，"]'),
('yuding-24','題茶陵縣門','伊用昌','唐','御定全唐诗','yuding','','[]','茶陵一道好長街，兩畔栽柳不栽槐。',32,'御定全唐詩/json/861.json','["茶陵一道好長街，兩畔栽柳不栽槐。", "夜後不聞更漏鼓，只聽錘芒織草鞋。"]'),
('yuding-25','題酒樓壁','伊用昌','唐','御定全唐诗','yuding','','[]','此生生在此生先，何事從玄不復玄。',32,'御定全唐詩/json/861.json','["此生生在此生先，何事從玄不復玄。", "已在淮南雞犬後，而今便到玉皇前。"]'),
('yuding-26','題遊帷觀真君殿后','伊用昌','唐','御定全唐诗','yuding','','[]','日日祥雲瑞氣連，儂家應作大神仙。筆頭灑起風雷力，',40,'御定全唐詩/json/861.json','["日日祥雲瑞氣連，儂家應作大神仙。筆頭灑起風雷力，", "列仙功業只如此，直上三清第一天。"]'),
('yuding-27','留題閣皂觀','伊用昌','唐','御定全唐诗','yuding','','[]','花洞門前吠似雷，險聲流斷俗塵埃。雨噴山腳毒龍起，',40,'御定全唐詩/json/861.json','["花洞門前吠似雷，險聲流斷俗塵埃。雨噴山腳毒龍起，", "兩壇詩客何年去，去後門關更不開。"]'),
('yuding-28','湖南闖齋吟','伊用昌','唐','御定全唐诗','yuding','','[]','誰人能識白元君，上士由來盡見聞。避世早空南火宅，',40,'御定全唐詩/json/861.json','["誰人能識白元君，上士由來盡見聞。避世早空南火宅，", "學取大羅些子術，免教松下作孤墳。"]'),
('yuding-29','游溧陽霞泉寺限白字','許堅2','唐','御定全唐诗','yuding','','[]','近枕吳溪與越峰，前朝恩賜雲泉額。竹林晴見雁塔高，',40,'御定全唐詩/json/861.json','["近枕吳溪與越峰，前朝恩賜雲泉額。竹林晴見雁塔高，", "客有經年別故林，落日啼猿情脈脈。"]'),
('yuding-30','幽棲觀','許堅2','唐','御定全唐诗','yuding','','[]','仙翁上升去，丹井寄晴壑。山色接天臺，湖光照寥廓。',48,'御定全唐詩/json/861.json','["仙翁上升去，丹井寄晴壑。山色接天臺，湖光照寥廓。", "玉洞絕無人，老檜猶棲鶴。我欲掣青蛇，他時沖碧落。"]'),
('yuding-31','題茅山觀','許堅2','唐','御定全唐诗','yuding','','[]','嘗恨清風千載鬱，洞天今得恣遊遨。松楸一色古壇靜，',40,'御定全唐詩/json/861.json','["嘗恨清風千載鬱，洞天今得恣遊遨。松楸一色古壇靜，", "分明有個長生路，休向紅塵歎二毛。"]'),
('yuding-32','題扇','許堅2','唐','御定全唐诗','yuding','','[]','哦吟但寫胸中妙，飲酒能忘身後名。',32,'御定全唐詩/json/861.json','["哦吟但寫胸中妙，飲酒能忘身後名。", "但願長閑有詩酒，一溪風月共清明。"]'),
('yuding-33','上徐舍人鉉','許堅2','唐','御定全唐诗','yuding','','[]','幾宵煙月鎖樓臺，欲寄侯門薦禰才。',32,'御定全唐詩/json/861.json','["幾宵煙月鎖樓臺，欲寄侯門薦禰才。", "滿面塵埃人不識，謾隨流水出山來。"]'),
('yuding-34','句','許堅2','唐','御定全唐诗','yuding','','[]','道既學不得，仙從何處來。',34,'御定全唐詩/json/861.json','["道既學不得，仙從何處來。", "臥久似慵伸雪項，立遲猶未整霜衣。（《病鶴》，"]'),
('yuding-35','醉吟','許碏','唐','御定全唐诗','yuding','','[]','閬苑花前是醉鄉，踏翻王母九霞觴。',32,'御定全唐詩/json/861.json','["閬苑花前是醉鄉，踏翻王母九霞觴。", "群仙拍手嫌輕薄，謫向人間作酒狂。"]'),
('yuding-36','題南嶽招仙觀壁上','許碏','唐','御定全唐诗','yuding','','[]','洪爐烹鍛人性命，器用不同分皆定。妖精鬼魅鬥神通，',64,'御定全唐詩/json/861.json','["洪爐烹鍛人性命，器用不同分皆定。妖精鬼魅鬥神通，", "還為萬靈威聖力，移月在南日在北。玉為玉兮石是石，", "丈夫未達莫相侵，攀龍附鳳捐精神。"]'),
('yuding-37','武陵春色','張白','唐','御定全唐诗','yuding','','[]','武陵春色好，十二酒家樓。大醉方回首，逢人不舉頭。',48,'御定全唐詩/json/861.json','["武陵春色好，十二酒家樓。大醉方回首，逢人不舉頭。", "是非都不采，名利混然休。戴個星冠子，浮沈逐世流。"]'),
('yuding-38','贈酒店崔氏','張白','唐','御定全唐诗','yuding','','[]','武陵城裏崔家酒，地上應無天上有。',32,'御定全唐詩/json/861.json','["武陵城裏崔家酒，地上應無天上有。", "南游道士飲一鬥，臥向白雲深洞口。"]'),
('yuding-39','哭陸先生','張白','唐','御定全唐诗','yuding','','[]','六親慟哭還復蘇，我笑先生淚個無。',32,'御定全唐詩/json/861.json','["六親慟哭還復蘇，我笑先生淚個無。", "脫履定歸天上去，空墳留入武陵圖。"]'),
('yuding-40','市中狂吟','段穀','唐','御定全唐诗','yuding','','[]','一間茅屋，尚自修治。任狂風吹，連簷破碎。枓栱斜欹，',25,'御定全唐詩/json/861.json','["一間茅屋，尚自修治。任狂風吹，連簷破碎。枓栱斜欹，"]'),
('yuding-41','詩','趙自然','唐','御定全唐诗','yuding','','[]','常欲棲山島，閑眠玉洞寒。丹哥時引舞，來去跨雲鸞。',24,'御定全唐詩/json/861.json','["常欲棲山島，閑眠玉洞寒。丹哥時引舞，來去跨雲鸞。"]'),
('yuding-42','大丹詩四首','李浩','唐','御定全唐诗','yuding','','[]','混沌未分我獨存，包含四象立乾坤。',128,'御定全唐詩/json/861.json','["混沌未分我獨存，包含四象立乾坤。", "還丹須向此中覓，得此方為至妙門。", "煮石烹金煉太元，神仙不肯等閒傳。", "人能認得其中理，奪盡乾坤造化權。", "百首荒辭義亦深，因傳同道決疑心。", "華池本是真神水，神水元來是白金。", "取將白金為鼎器，鼎成潛伏汞來侵。", "汞入金鼎終年盡，產出靈砂似太陰。"]'),
('yuding-43','自吟','徐釣者','唐','御定全唐诗','yuding','','[]','曾見秦皇架石橋，海神忙迫漲驚潮。',32,'御定全唐詩/json/861.json','["曾見秦皇架石橋，海神忙迫漲驚潮。", "蓬萊隔海雖難到，直上三清卻不遙。"]'),
('yuding-44','踏歌','藍采和','唐','御定全唐诗','yuding','','[]','踏歌踏歌藍采和，世界能幾何。紅顏三春樹，',44,'御定全唐詩/json/861.json','["踏歌踏歌藍采和，世界能幾何。紅顏三春樹，", "朝騎鸞鳳到碧落，暮見桑田生白波。長景明暉在空際，"]'),
('yuding-0','同沈恭子遊虎丘寺有作','清遠道士','唐','御定全唐诗','yuding','','[]','我本長殷周，遭罹曆秦漢。四瀆與五嶽，名山盡幽竄。',144,'御定全唐詩/json/862.json','["我本長殷周，遭罹曆秦漢。四瀆與五嶽，名山盡幽竄。", "及此寰區中，始有近峰玩。近峰何鬱鬱，平湖渺彌漫。", "吟俯川之陰，步上山之岸。山川共澄澈，光彩交淩亂。", "白雲蓊欲歸，青松忽消半。客去川島靜，人來山鳥散。", "穀深中見日，崖幽曉非旦。聞子盛遊遨，風流足詞翰。", "嘉茲好松石，一言常累歎。勿謂餘鬼神，忻君共幽贊。"]'),
('yuding-1','遊春台詩','春台仙','唐','御定全唐诗','yuding','','[]','玉幢亙碧虛，此乃真人居。裴回仍未進，邪省猶難除。',128,'御定全唐詩/json/862.json','["玉幢亙碧虛，此乃真人居。裴回仍未進，邪省猶難除。", "日落煙水黯，驪珠色豈昏。寒光射萬里，霜縞遍千門。", "玉魄東方開，嫦娥逐影來。洗心兼滌目，怳若遊春台。", "清波滔碧天，烏藏黯黮連。二儀不辨處，忽吐清光圓。", "烏沈海西岸，蟾吐天東頭。", "鳳凰三十六，碧天高太清。元君夫人蹋雲語，"]'),
('yuding-2','醉吟','酒肆布衣','唐','御定全唐诗','yuding','','[]','陽春時節天氣和，萬物芳盛人如何。素秋時節天地肅，',40,'御定全唐詩/json/862.json','["陽春時節天氣和，萬物芳盛人如何。素秋時節天地肅，", "一旦形羸又發白，舊遊空使淚連連。"]'),
('yuding-3','又吟','酒肆布衣','唐','御定全唐诗','yuding','','[]','有形皆朽孰不知，休吟春景與秋時。',32,'御定全唐詩/json/862.json','["有形皆朽孰不知，休吟春景與秋時。", "爭如且醉長安酒，榮華零悴總奚為。"]'),
('yuding-4','嫁女詩','嵩岳諸仙','唐','御定全唐诗','yuding','','[]','勸君酒，為君悲且吟。自從頻見市朝改，無複瑤池宴樂心。',397,'御定全唐詩/json/862.json','["勸君酒，為君悲且吟。自從頻見市朝改，無複瑤池宴樂心。", "奉君酒，休歎市朝非。早知無複瑤池興，悔駕驊騮草草歸。", "八馬回乘汗漫風，猶思往事憩昭宮。宴移玄圃情方洽，", "昆侖回首不知處，疑是酒酣魂夢中。", "一曲笙歌瑤水濱，曾留逸足駐征輪。人間甲子周千歲，", "悄知碧海饒詞句，歌向俗流疑誤人。", "珠露金風下界秋，漢家陵樹冷修修。", "當時不得仙桃力，尋作浮塵飄隴頭。", "五十餘年四海清，自親丹藥得長生。", "若言儘是仙桃力，看取神仙簿上名。", "月照驪山露泣花，似悲先帝早升遐。", "至今猶有長生鹿，時繞溫泉望翠華。", "幽薊煙塵別九重，貴妃湯殿罷歌鐘。中宵扈從無全仗，", "荊榛一閉朝元路，唯有悲風吹晚松。", "上清神女，玉京仙郎。樂此今夕，和鳴鳳凰。", "鳳凰和鳴，將翱將翔。與天齊休，慶流無央。", "玉為質兮花為顏，蟬為鬢兮雲為鬟。何勞傅粉兮施渥丹，", "水晶帳開銀燭明，風搖珠佩連雲清。", "休勻紅粉飾花態，早駕雙鸞朝玉京。", "三星在天銀河回，人間曙色東方來。", "玉苗瓊蕊亦宜夜，莫使一花沖曉開。"]'),
('yuding-5','吟','不詳','唐','御定全唐诗','yuding','','[]','餌柏身輕疊嶂間，是非無意到塵寰。',64,'御定全唐詩/json/862.json','["餌柏身輕疊嶂間，是非無意到塵寰。", "冠裳暫備論浮世，一餉雲遊碧落間。", "誰知古是與今非，閑躡青霞與翠微。", "簫管秦樓應寂寂，彩雲空惹薜蘿衣。"]'),
('yuding-6','授炙轂子歌二首','希道','唐','御定全唐诗','yuding','','[]','木津天魂，金液地魄。坎離運行寬無成，金木有數秦晉合。',70,'御定全唐詩/json/862.json','["木津天魂，金液地魄。坎離運行寬無成，金木有數秦晉合。", "近效宜六旬，遠期三載闊。", "魄微入魂牝牡結，陽呴陰滋神鬼滅。", "千歌萬贊皆未決，古往今來拋日月。"]'),
('yuding-7','李泌庭黑石詩','隱者','唐','御定全唐诗','yuding','','[]','神真煉形年未足，化為我子功相續。',32,'御定全唐詩/json/862.json','["神真煉形年未足，化為我子功相續。", "丞相瘞之刻玄玉，仙路何長死何促。"]'),
('yuding-8','戲吟','廣陵道士','唐','御定全唐诗','yuding','','[]','無事到揚州，相攜上酒樓。藥囊為贈別，千載更何求。',24,'御定全唐詩/json/862.json','["無事到揚州，相攜上酒樓。藥囊為贈別，千載更何求。"]'),
('yuding-9','授馬氏女詩','黃冠野夫','唐','御定全唐诗','yuding','','[]','女是寄生枝，男是冬青木。冬青駕白鵝，寄生跨黃鹿。',48,'御定全唐詩/json/862.json','["女是寄生枝，男是冬青木。冬青駕白鵝，寄生跨黃鹿。", "若遇寇相淩，穩便拋家族。早早上三清，莫候丹砂熟。"]'),
('yuding-10','歌','蜀酒閣道人','唐','御定全唐诗','yuding','','[]','尾閭不禁滄溟竭，九轉神丹都謾說。',32,'御定全唐詩/json/862.json','["尾閭不禁滄溟竭，九轉神丹都謾說。", "惟有班龍頂上珠，能補玉堂關下穴。"]'),
('yuding-11','吟','章江書生','唐','御定全唐诗','yuding','','[]','西去長沙東上船，思量此事已千年。',32,'御定全唐詩/json/862.json','["西去長沙東上船，思量此事已千年。", "長春殿掩無人掃，滿眼梨花哭杜鵑。"]'),
('yuding-12','示邊洞元','萼嶺書生','唐','御定全唐诗','yuding','','[]','邂逅相逢萼嶺邊，對傾浮蟻共談玄。',32,'御定全唐詩/json/862.json','["邂逅相逢萼嶺邊，對傾浮蟻共談玄。", "擬將劍法親傳授，卻為迷人未有緣。"]'),
('yuding-13','示胡二郎歌','成都醉道士','唐','御定全唐诗','yuding','','[]','欲究丹砂理，幽玄無處尋。不離鉛與汞，無出水中金。',112,'御定全唐詩/json/862.json','["欲究丹砂理，幽玄無處尋。不離鉛與汞，無出水中金。", "金欲煉時須得水，水遇土兮終不起。但知火候不參差，", "豈知光景片時間，將謂人生長似此。何不回心師至道，", "二郎切切聽我語，仙鄉咫尺無寒暑。與君說盡只如斯，", "吟成數句贈君辭，不覺便成今與古。"]'),
('yuding-14','貽白永年詩','樵夫','唐','御定全唐诗','yuding','','[]','清秋無所事，乘露出遙天。憑仗樵人語，相期白永年。',24,'御定全唐詩/json/862.json','["清秋無所事，乘露出遙天。憑仗樵人語，相期白永年。"]'),
('yuding-15','留詩','李公佐僕','唐','御定全唐诗','yuding','','[]','我有衣中珠，不嫌衣上塵。我有長生理，不厭有生身。',72,'御定全唐詩/json/862.json','["我有衣中珠，不嫌衣上塵。我有長生理，不厭有生身。", "江南神仙窟，吾當混其真。不嫌市井喧，來救世間人。", "蘇子跡已往，顓蒙事可親。莫言東海變，天地有長春。"]'),
('yuding-16','木客','李公佐僕','唐','御定全唐诗','yuding','','[]','酒盡君莫沽，壺傾我當發。城市多囂塵，還山弄明月。',24,'御定全唐詩/json/862.json','["酒盡君莫沽，壺傾我當發。城市多囂塵，還山弄明月。"]'),
('yuding-17','西山吟','許大','唐','御定全唐诗','yuding','','[]','自從明府歸仙後，出入塵寰直至今。',32,'御定全唐詩/json/862.json','["自從明府歸仙後，出入塵寰直至今。", "不是藏名混時俗，賣藥沽酒要安心。"]'),
('yuding-18','東洛貨丹','許學士','唐','御定全唐诗','yuding','','[]','三千功滿去升天，一住人間數百年。',32,'御定全唐詩/json/862.json','["三千功滿去升天，一住人間數百年。", "華表他時卻歸日，滄溟應恐變桑田。"]'),
('yuding-19','天關回到世吟','許學士','唐','御定全唐诗','yuding','','[]','九霄雲路奇哉險，曾把沖身入太和。',32,'御定全唐詩/json/862.json','["九霄雲路奇哉險，曾把沖身入太和。", "今日東歸渾似夢，望崖回首隔天波。"]'),
('yuding-20','送青城丈人酒','紫微孫處士','唐','御定全唐诗','yuding','','[]','深羨青城好洞天，白龍一覺已千年。',32,'御定全唐詩/json/862.json','["深羨青城好洞天，白龍一覺已千年。", "鋪雲枕石長松下，朝退看書盡日眠。"]'),
('yuding-21','送王懿昌酒','紫微孫處士','唐','御定全唐诗','yuding','','[]','將知骨分到仙鄉，酒飲金華玉液漿。',32,'御定全唐詩/json/862.json','["將知骨分到仙鄉，酒飲金華玉液漿。", "莫道人間只如此，回頭已是一年強。"]'),
('yuding-22','送太乙真君酒','青城丈人','唐','御定全唐诗','yuding','','[]','峨嵋仙府靜沉沉，玉液金華莫厭斟。',32,'御定全唐詩/json/862.json','["峨嵋仙府靜沉沉，玉液金華莫厭斟。", "凡客欲知真一洞，劍門西北五雲深。"]'),
('yuding-23','送紫微處士酒','太乙真君','唐','御定全唐诗','yuding','','[]','此中何必羨青城，玉樹雲棲不記名。',32,'御定全唐詩/json/862.json','["此中何必羨青城，玉樹雲棲不記名。", "悶即乘龍遊紫府，北辰南斗逐君行。"]'),
('yuding-24','題法雲寺雙檜','方壺居士','唐','御定全唐诗','yuding','','[]','謝郎雙檜綠於雲，昏曉濃陰色未分。',32,'御定全唐詩/json/862.json','["謝郎雙檜綠於雲，昏曉濃陰色未分。", "若並亳宮仙鹿跡，定知高峭不如君。"]'),
('yuding-25','隋堤詞','方壺居士','唐','御定全唐诗','yuding','','[]','嘗憶江都大業秋，曾隨鑾蹕戲龍舟。',32,'御定全唐詩/json/862.json','["嘗憶江都大業秋，曾隨鑾蹕戲龍舟。", "傷心一覺興亡夢，堤柳無情識世愁。"]'),
('yuding-26','畫地吟','太白山玄士','唐','御定全唐诗','yuding','','[]','學得丹青數萬年，人間幾度變桑田。',32,'御定全唐詩/json/862.json','["學得丹青數萬年，人間幾度變桑田。", "桑田雖變丹青在，誰向丹青合得仙。"]'),
('yuding-27','貨丹吟','鄰道場人','唐','御定全唐诗','yuding','','[]','尋仙何必三山上，但使神存九竅清。',32,'御定全唐詩/json/862.json','["尋仙何必三山上，但使神存九竅清。", "煉得綿綿元氣定，自然不食亦長生。"]'),
('yuding-28','靈響詞','無名氏','唐','御定全唐诗','yuding','','[]','此響非俗響，心知是靈仙。不曾離耳裏，高下如秋蟬。',120,'御定全唐詩/json/862.json','["此響非俗響，心知是靈仙。不曾離耳裏，高下如秋蟬。", "入夜聲則厲，在晝聲則微。神靈斥眾惡，與我作風威。", "妙響無住時，晝夜常輪回。那是偶然事，上界特使來。", "何以辨靈應，事須得梯媒。自從靈響降，如有真人來。", "存念長在心，輾轉無停音。可憐清爽夜，靜聽秋蟬吟。"]'),
('yuding-29','度世古玄歌','無名氏','唐','御定全唐诗','yuding','','[]','始青之下月與日，兩半同升合為一。大如彈丸甘如蜜，',24,'御定全唐詩/json/862.json','["始青之下月與日，兩半同升合為一。大如彈丸甘如蜜，"]'),
('yuding-30','鬻丹砂醉吟','劉道昌','唐','御定全唐诗','yuding','','[]','心田但使靈芝長，氣海常教法水朝。',32,'御定全唐詩/json/862.json','["心田但使靈芝長，氣海常教法水朝。", "功滿自然留不住，更將何物馭丹霄。"]'),
('yuding-31','龜市告別','劉道昌','唐','御定全唐诗','yuding','','[]','還丹功滿氣成胎，九百年來混俗埃。',32,'御定全唐詩/json/862.json','["還丹功滿氣成胎，九百年來混俗埃。", "自此三山一歸去，無因重到世間來。"]'),
('yuding-32','摘紫芝','李太玄','唐','御定全唐诗','yuding','','[]','偶遊洞府到芝田，星月茫茫欲曙天。',32,'御定全唐詩/json/862.json','["偶遊洞府到芝田，星月茫茫欲曙天。", "雖則似離塵世了，不知何處偶真仙。"]'),
('yuding-33','玉女舞霓裳','李太玄','唐','御定全唐诗','yuding','','[]','舞勢隨風散複收，歌聲似磬韻還幽。',32,'御定全唐詩/json/862.json','["舞勢隨風散複收，歌聲似磬韻還幽。", "千回赴節填詞處，嬌眼如波入鬢流。"]'),
('yuding-34','玩月詩','曲龍山仙','唐','御定全唐诗','yuding','','[]','曲龍橋頂玩瀛洲，凡骨空陪汗漫遊。',128,'御定全唐詩/json/862.json','["曲龍橋頂玩瀛洲，凡骨空陪汗漫遊。", "不假丹梯躡霄漢，水晶盤冷桂花秋。", "月砌瑤階泉滴乳，玉簫催鳳和煙舞。", "青城丈人何處游，玄鶴唳天雲一縷。", "造化天橋碧海東，玉輪還過輾晴虹。", "霓襟似拂瀛洲頂，顥氣潛消橐鑰中。", "危橋橫石架雲端，跨鹿登臨景象寬。", "顥魄洗煙澄碧落，桂花低拂玉簪寒。"]'),
('yuding-35','句','陳複休','唐','御定全唐诗','yuding','','[]','夜坐空庭月色微，一樹寒梅發兩枝。',16,'御定全唐詩/json/862.json','["夜坐空庭月色微，一樹寒梅發兩枝。"]'),
('yuding-36','句','鄭冠卿','唐','御定全唐诗','yuding','','[]','不緣過去行方便，安得今朝會碧虛。',16,'御定全唐詩/json/862.json','["不緣過去行方便，安得今朝會碧虛。"]'),
('yuding-37','句','陳蓬','唐','御定全唐诗','yuding','','[]','竹籬疏見浦，茅屋漏通星。',12,'御定全唐詩/json/862.json','["竹籬疏見浦，茅屋漏通星。"]'),
('yuding-38','句','伊夢昌','唐','御定全唐诗','yuding','','[]','惟有松杉空弄月，更無雲鶴暗迷人。',32,'御定全唐詩/json/862.json','["惟有松杉空弄月，更無雲鶴暗迷人。", "露凝金盞滴殘酒，檀點佳人噴異香。"]'),
('yuding-0','與薛昭合婚詩','張雲容','唐','御定全唐诗','yuding','','[]','臉花不綻幾含幽，今夕陽春獨換秋。',128,'御定全唐詩/json/863.json','["臉花不綻幾含幽，今夕陽春獨換秋。", "我守孤燈無白日，寒雲隴上更添愁。", "幽谷啼鶯整羽翰，犀沈玉冷自長歎。", "月華不向扃泉戶，露滴松枝一夜寒。", "韶光不見分成塵，曾餌金丹忽有神。", "不意薛生攜舊律，獨開幽谷一枝春。", "誤入宮垣漏網人，月華靜洗玉階塵。", "自疑飛到蓬萊頂，瓊豔三枝半夜春。"]'),
('yuding-1','留別盧陲','崔少玄','唐','御定全唐诗','yuding','','[]','得之一元，匪受自天。太老之真，無上之仙。光含影藏，',45,'御定全唐詩/json/863.json','["得之一元，匪受自天。太老之真，無上之仙。光含影藏，", "丹霄碧虛，上聖之儔。百歲之後，空餘墳丘。"]'),
('yuding-2','歌','戚逍遙','唐','御定全唐诗','yuding','','[]','笑看滄海欲成塵，王母花前別眾真。',32,'御定全唐詩/json/863.json','["笑看滄海欲成塵，王母花前別眾真。", "千歲卻歸天上去，一心珍重世間人。"]'),
('yuding-3','錦城春望','卓英英','唐','御定全唐诗','yuding','','[]','和風裝點錦城春，細雨如絲壓玉塵。',32,'御定全唐詩/json/863.json','["和風裝點錦城春，細雨如絲壓玉塵。", "漫把詩情訪奇景，豔花濃酒屬閒人。"]'),
('yuding-4','理笙','卓英英','唐','御定全唐诗','yuding','','[]','頻倚銀屏理鳳笙，調中幽意起春情。',32,'御定全唐詩/json/863.json','["頻倚銀屏理鳳笙，調中幽意起春情。", "因思往事成惆悵，不得緱山和一聲。"]'),
('yuding-5','遊福感寺答少年','卓英英','唐','御定全唐诗','yuding','','[]','牡丹未及開時節，況是秋風莫近前。',32,'御定全唐詩/json/863.json','["牡丹未及開時節，況是秋風莫近前。", "留待來年二三月，一枝和露壓神仙。"]'),
('yuding-6','答玄士','卓英英','唐','御定全唐诗','yuding','','[]','數載幽欄種牡丹，裹香包豔待神仙。',32,'御定全唐詩/json/863.json','["數載幽欄種牡丹，裹香包豔待神仙。", "神仙既有丹青術，攜取何妨入洞天。"]'),
('yuding-7','和卓英英錦城春望','眉娘','唐','御定全唐诗','yuding','','[]','蠶市初開處處春，九衢明豔起香塵。',32,'御定全唐詩/json/863.json','["蠶市初開處處春，九衢明豔起香塵。", "世間總有浮華事，爭及仙山出世人。"]'),
('yuding-8','和卓英英理笙','眉娘','唐','御定全唐诗','yuding','','[]','但于閨閣熟吹笙，太白真仙自有情。',32,'御定全唐詩/json/863.json','["但于閨閣熟吹笙，太白真仙自有情。", "他日丹霄驂白鳳，何愁子晉不聞聲。"]'),
('yuding-9','附：太白山玄士畫地吟','眉娘','唐','御定全唐诗','yuding','','[]','學得丹青數萬年，人間幾度變桑田。',32,'御定全唐詩/json/863.json','["學得丹青數萬年，人間幾度變桑田。", "桑田雖變丹青在，誰向丹青合得仙。"]'),
('yuding-10','答張鬱歌','洛川仙女','唐','御定全唐诗','yuding','','[]','彩雲入帝鄉，白鶴又回翔。久留深不可，蓬島路遐長。',48,'御定全唐詩/json/863.json','["彩雲入帝鄉，白鶴又回翔。久留深不可，蓬島路遐長。", "空愛長生術，不是長生人。今日洛川別，可惜洞中春。"]'),
('yuding-11','附：張郁洛川沿步吟','洛川仙女','唐','御定全唐诗','yuding','','[]','浮生如夢能幾何，浮生複更憂患多。',32,'御定全唐詩/json/863.json','["浮生如夢能幾何，浮生複更憂患多。", "無人與我長生術，洛川春日且長歌。"]'),
('yuding-12','題玉壺贈元柳二子','南溟夫人','唐','御定全唐诗','yuding','','[]','來從一葉舟中來，去向百花橋上去。',32,'御定全唐詩/json/863.json','["來從一葉舟中來，去向百花橋上去。", "若到人間扣玉壺，鴛鴦自解分明語。"]'),
('yuding-13','會真詩','雲台峰女仙','唐','御定全唐诗','yuding','','[]','人世徒紛擾，其生似夢華。誰言今昔裏，俯首視雲霞。',24,'御定全唐詩/json/863.json','["人世徒紛擾，其生似夢華。誰言今昔裏，俯首視雲霞。"]'),
('yuding-14','會真詩','雲台峰女仙','唐','御定全唐诗','yuding','','[]','幾劫澄煩思，今身僅小成。誓將雲外隱，不向世間存。',24,'御定全唐詩/json/863.json','["幾劫澄煩思，今身僅小成。誓將雲外隱，不向世間存。"]'),
('yuding-15','會真詩','雲台峰女仙','唐','御定全唐诗','yuding','','[]','綽約離塵世，從容上太清。雲衣無綻日，鶴駕沒遙程。',24,'御定全唐詩/json/863.json','["綽約離塵世，從容上太清。雲衣無綻日，鶴駕沒遙程。"]'),
('yuding-16','會真詩','雲台峰女仙','唐','御定全唐诗','yuding','','[]','華嶽無三尺，東瀛僅一杯。入雲騎彩鳳，歌舞上蓬萊。',24,'御定全唐詩/json/863.json','["華嶽無三尺，東瀛僅一杯。入雲騎彩鳳，歌舞上蓬萊。"]'),
('yuding-17','會真詩','雲台峰女仙','唐','御定全唐诗','yuding','','[]','共作雲山侶，俱辭世界塵。靜思前日事，拋卻幾年身。',24,'御定全唐詩/json/863.json','["共作雲山侶，俱辭世界塵。靜思前日事，拋卻幾年身。"]'),
('yuding-18','仙詩五首','吳清妻','唐','御定全唐诗','yuding','','[]','道啟真心覺漸清，天教絕粒應精誠。',160,'御定全唐詩/json/863.json','["道啟真心覺漸清，天教絕粒應精誠。", "雲外仙歌笙管合，花間風引步虛聲。", "□□□□□□□，□君隱處當一星。", "□□蓮花山頭飯，黃精仙人掌上經。", "飛鳥莫到人莫攀，一隱十年不下山。", "袖中短書誰為達，華山道士賣藥還。", "日落焚香坐醮壇，庭花露濕漸更闌。", "淨水仙童調玉液，春宵羽客化金丹。", "攝念精思引彩霞，焚香虛室對煙花。", "道合雲霄遊紫府，湛然真境瑞皇家。"]'),
('yuding-19','贈封陟','上元夫人','唐','御定全唐诗','yuding','','[]','謫居蓬島別瑤池，春媚煙花有所思。',32,'御定全唐詩/json/863.json','["謫居蓬島別瑤池，春媚煙花有所思。", "為愛君心能潔白，願操箕帚奉屏幃。"]'),
('yuding-20','再贈','上元夫人','唐','御定全唐诗','yuding','','[]','弄玉有夫皆得道，劉綱兼室盡登仙。',32,'御定全唐詩/json/863.json','["弄玉有夫皆得道，劉綱兼室盡登仙。", "君能仔細窺朝露，須逐雲車拜洞天。"]'),
('yuding-21','留別','上元夫人','唐','御定全唐诗','yuding','','[]','蕭郎不顧鳳樓人，雲澀回車淚臉新。',32,'御定全唐詩/json/863.json','["蕭郎不顧鳳樓人，雲澀回車淚臉新。", "愁想蓬瀛歸去路，難窺舊苑碧桃春。"]'),
('yuding-22','題寺廊柱','慈恩院女仙','唐','御定全唐诗','yuding','','[]','皇子陂頭好月明，忘卻華筵到曉行。',64,'御定全唐詩/json/863.json','["皇子陂頭好月明，忘卻華筵到曉行。", "煙收山低翠黛橫，折得荷花遠恨生。", "湖水團團夜如鏡，碧樹紅花相掩映。", "北斗闌幹移曉柄，有似佳期常不定。"]'),
('yuding-23','後土夫人','蜀宮群仙','唐','御定全唐诗','yuding','','[]','偶引群仙到世間，熏風殿裏醉華筵。',32,'御定全唐詩/json/863.json','["偶引群仙到世間，熏風殿裏醉華筵。", "等閒貪賞不歸去，愁殺韋郎一覺眠。"]'),
('yuding-24','王母','蜀宮群仙','唐','御定全唐诗','yuding','','[]','滄海成塵幾萬秋，碧桃花發長春愁。',32,'御定全唐詩/json/863.json','["滄海成塵幾萬秋，碧桃花發長春愁。", "不來便是數千載，周穆漢皇何處遊。"]'),
('yuding-25','麻姑','蜀宮群仙','唐','御定全唐诗','yuding','','[]','世間何事不潸然，得失人情命不延。',32,'御定全唐詩/json/863.json','["世間何事不潸然，得失人情命不延。", "適向蔡家廳上飲，回頭已見一千年。"]'),
('yuding-26','上元夫人','蜀宮群仙','唐','御定全唐诗','yuding','','[]','思量往事一愁容，阿母曾邀到漢宮。',32,'御定全唐詩/json/863.json','["思量往事一愁容，阿母曾邀到漢宮。", "城闕不存人不見，茂陵荒草恨無窮。"]'),
('yuding-27','弄玉','蜀宮群仙','唐','御定全唐诗','yuding','','[]','采鳳飛來到禁闈，便隨王母駐瑤池。',32,'御定全唐詩/json/863.json','["采鳳飛來到禁闈，便隨王母駐瑤池。", "如今記得秦樓上，偷見蕭郎惱妾時。"]'),
('yuding-28','太真','蜀宮群仙','唐','御定全唐诗','yuding','','[]','春夢悠揚生下界，一堪成笑一堪悲。',32,'御定全唐詩/json/863.json','["春夢悠揚生下界，一堪成笑一堪悲。", "馬嵬不是無情地，自遇蓬萊睡覺時。"]'),
('yuding-29','贈郭翰二首','織女','唐','御定全唐诗','yuding','','[]','河漢雖雲闊，三秋尚有期。情人終已矣，良會更何時。',48,'御定全唐詩/json/863.json','["河漢雖雲闊，三秋尚有期。情人終已矣，良會更何時。", "朱閣臨清溪，瓊宮銜紫房。佳情期在此，只是斷人腸。"]'),
('yuding-30','附：郭翰酬織女','織女','唐','御定全唐诗','yuding','','[]','人世將天上，由來不可期。誰知一回顧，更作兩相思。',48,'御定全唐詩/json/863.json','["人世將天上，由來不可期。誰知一回顧，更作兩相思。", "贈枕猶香澤，啼衣尚淚痕。玉顏霄漢裏，空有往來魂。"]'),
('yuding-31','書任生案','嵩山女','唐','御定全唐诗','yuding','','[]','我本籍上清，謫居遊五嶽。以君無俗累，來勸神仙學。',48,'御定全唐詩/json/863.json','["我本籍上清，謫居遊五嶽。以君無俗累，來勸神仙學。", "葛洪還有婦，王母亦有夫。神仙盡靈匹，君意合何如。"]'),
('yuding-32','臨去書贈','嵩山女','唐','御定全唐诗','yuding','','[]','君子既執迷，無由達情素。明月海山上，秋風獨歸去。',24,'御定全唐詩/json/863.json','["君子既執迷，無由達情素。明月海山上，秋風獨歸去。"]'),
('yuding-33','與趙旭叩柱歌','青童','唐','御定全唐诗','yuding','','[]','白雲飄飄星漢斜，獨行窈窕浮雲車。',32,'御定全唐詩/json/863.json','["白雲飄飄星漢斜，獨行窈窕浮雲車。", "仙郎獨邀青童君，結情羅帳連心花。"]'),
('yuding-34','題壁','觀梅女仙','唐','御定全唐诗','yuding','','[]','南枝向暖北枝寒，一種春花有兩般。',32,'御定全唐詩/json/863.json','["南枝向暖北枝寒，一種春花有兩般。", "憑仗高樓莫吹笛，大家留取倚闌看。"]'),
('yuding-35','歌','吳彩鸞','唐','御定全唐诗','yuding','','[]','若能相伴陟仙壇，應得文簫駕彩鸞。',32,'御定全唐詩/json/863.json','["若能相伴陟仙壇，應得文簫駕彩鸞。", "自有繡襦並甲帳，瑤台不怕雪霜寒。"]'),
('yuding-36','臨化絕句','王氏女','唐','御定全唐诗','yuding','','[]','玩水登山無足時，諸仙頻下聽吟詩。',32,'御定全唐詩/json/863.json','["玩水登山無足時，諸仙頻下聽吟詩。", "此心不戀居人世，唯見天邊雙鶴飛。"]'),
('yuding-37','贈華山遊人','毛女正美','唐','御定全唐诗','yuding','','[]','藥苗不滿笥，又更上危巔。回首歸去路，相將入翠煙。',56,'御定全唐詩/json/863.json','["藥苗不滿笥，又更上危巔。回首歸去路，相將入翠煙。", "曾折松枝為寶櫛，又編栗葉代羅襦。", "有時問卻秦宮事，笑撚山花望太虛。"]'),
('yuding-38','在紫霄夫人席上作','桃花夫人','唐','御定全唐诗','yuding','','[]','昔時訓子西河上，漢使經過問妾緣。',32,'御定全唐詩/json/863.json','["昔時訓子西河上，漢使經過問妾緣。", "自到仙山不知老，凡間喚作幾千年。"]'),
('yuding-39','答孫玄照','王仙仙','唐','御定全唐诗','yuding','','[]','鴛鴦相見不相隨，籠裏籠前整羽衣。',32,'御定全唐詩/json/863.json','["鴛鴦相見不相隨，籠裏籠前整羽衣。", "但得他時人放去，水中長作一雙飛。"]'),
('yuding-40','附：孫玄照琴中歌贈王仙仙','王仙仙','唐','御定全唐诗','yuding','','[]','相如曾作鳳兮吟，昔被文君會此音。',32,'御定全唐詩/json/863.json','["相如曾作鳳兮吟，昔被文君會此音。", "今日孤鸞還獨語，痛哉仙子不彈琴。"]'),
('yuding-41','臨刑賦','楊損','唐','御定全唐诗','yuding','','[]','聖主何曾識仲都，可嗟社稷在須臾。',32,'御定全唐詩/json/863.json','["聖主何曾識仲都，可嗟社稷在須臾。", "市東便是神仙窟，何必乘舟泛五湖。"]'),
('yuding-42','別遙見詩','妙女','唐','御定全唐诗','yuding','','[]','手攀橋柱立，滴淚天河滿。',12,'御定全唐詩/json/863.json','["手攀橋柱立，滴淚天河滿。"]'),
('yuding-0','宴柳毅詩','洞庭龍君','唐','御定全唐诗','yuding','','[]','大天蒼蒼兮大地茫茫，人各有志兮何可思量。',188,'御定全唐詩/json/864.json','["大天蒼蒼兮大地茫茫，人各有志兮何可思量。", "狐神鼠聖兮薄社依牆，雷霆一發兮其孰敢當。", "荷貞人兮信義長，令骨肉兮還故鄉，永言慚愧兮何時忘。", "上天配合兮生死有途，此不當婦兮彼不當夫。", "腹心辛苦兮涇水之隅，風霜滿鬢兮雨雪羅襦。", "賴明公兮引素書，令骨肉兮家如初，永言珍重兮無時無。", "碧雲悠悠兮涇水東流，傷嗟美人兮雨泣花愁。", "尺書遠達兮以解君憂，哀冤果雪兮還處其休。", "荷君和雅兮感甘羞，山家寂寞兮難久留，"]'),
('yuding-1','鑄鏡歌','龍護老人','唐','御定全唐诗','yuding','','[]','盤龍盤龍，隱於鏡中。分野有象，變化無窮。',40,'御定全唐詩/json/864.json','["盤龍盤龍，隱於鏡中。分野有象，變化無窮。", "興雲吐霧，行雨生風。上清仙子，來獻聖聰。"]'),
('yuding-2','示韋泛祿命','冥吏','唐','御定全唐诗','yuding','','[]','前陽複後楊，後楊年年強，七月之節歸玄鄉。',20,'御定全唐詩/json/864.json','["前陽複後楊，後楊年年強，七月之節歸玄鄉。"]'),
('yuding-3','贈僧','滕傳胤','唐','御定全唐诗','yuding','','[]','卓立不求名出家，長懷片志在青霞。',32,'御定全唐詩/json/864.json','["卓立不求名出家，長懷片志在青霞。", "今日英雄氣沖蓋，誰能久坐寶蓮花。"]'),
('yuding-4','贈人','滕傳胤','唐','御定全唐诗','yuding','','[]','平生才不足，立身信有餘。自歎無大故，君子莫相疏。',24,'御定全唐詩/json/864.json','["平生才不足，立身信有餘。自歎無大故，君子莫相疏。"]'),
('yuding-5','鄭鋒宅神詩','滕傳胤','唐','御定全唐诗','yuding','','[]','浦口潮來初淼漫，蓮舟搖颺采花難。',64,'御定全唐詩/json/864.json','["浦口潮來初淼漫，蓮舟搖颺采花難。", "春心不愜空歸去，會待潮回更折看。", "忽然湖上片雲飛，不覺舟中雨濕衣。", "折得蓮花渾忘卻，空將荷葉蓋頭歸。"]'),
('yuding-6','與鄭德璘奇遇詩','水府君','唐','御定全唐诗','yuding','','[]','物觸輕舟心自知，風恬煙靜月光微。',160,'御定全唐詩/json/864.json','["物觸輕舟心自知，風恬煙靜月光微。", "夜深江上解愁思，拾得紅蕖香惹衣。", "纖手垂鉤對水窗，紅蕖秋色豔長江。", "既能解佩投交甫，更有明珠乞一雙。", "湖面狂風且莫吹，浪花初綻月光微。", "沈潛暗想橫波淚，得共鮫人相對垂。", "洞庭風軟荻花秋，新沒青娥細浪愁。", "淚滴白蘋君不見，月明江上有輕鷗。", "昔日江頭菱芡人，蒙君數飲松醪春。", "活君家室以為報，珍重長沙鄭德璘。"]'),
('yuding-7','笑巫詩','李序','唐','御定全唐诗','yuding','','[]','魍魎何曾見，頭旋即下神。圖他衫子段，詐道大王嗔。',24,'御定全唐詩/json/864.json','["魍魎何曾見，頭旋即下神。圖他衫子段，詐道大王嗔。"]'),
('yuding-8','霅溪夜宴詩','水神','唐','御定全唐诗','yuding','','[]','濁波揚揚兮凝曉霧，公無渡河兮公竟渡。',44,'御定全唐詩/json/864.json','["濁波揚揚兮凝曉霧，公無渡河兮公竟渡。", "風號水激兮呼不聞，提衣看入兮中流去。浪排衣兮隨步沒，"]'),
('yuding-9','霅溪夜宴詩','水神','唐','御定全唐诗','yuding','','[]','悲風淅淅兮波綿綿，蘆花萬里兮凝蒼煙。',109,'御定全唐詩/json/864.json','["悲風淅淅兮波綿綿，蘆花萬里兮凝蒼煙。", "虯螭窟宅兮淵且玄，排波疊浪兮沈我天。", "所覆不全兮身甯全，溢眸恨血兮徒漣漣。", "誓將柔荑抉鋸牙之喙，空水府而藏其腥涎。", "青娥翠黛兮沈江壖，碧雲斜月兮空嬋娟。", "吞聲飲恨兮語無力，徒揚哀怨兮登歌筵。"]'),
('yuding-10','霅溪夜宴詩','水神','唐','御定全唐诗','yuding','','[]','白露漙兮西風高，碧波萬里兮翻洪濤。',33,'御定全唐詩/json/864.json','["白露漙兮西風高，碧波萬里兮翻洪濤。", "莫言天下至柔者，載舟覆舟皆我曹。"]'),
('yuding-11','霅溪夜宴詩','水神','唐','御定全唐诗','yuding','','[]','君不見夜來渡口擁千艘，中載萬姓之脂膏。',78,'御定全唐詩/json/864.json','["君不見夜來渡口擁千艘，中載萬姓之脂膏。", "當樓船泛泛於疊浪，恨珠貝又輕於鴻毛。", "又不見朝來津亭維一舠，中有一士青其袍。", "赴宰邑之良日，任波吼而風號。是知溺名溺利者，"]'),
('yuding-12','霅溪夜宴詩','水神','唐','御定全唐诗','yuding','','[]','山勢縈回水脈分，水光山色翠連雲。',32,'御定全唐詩/json/864.json','["山勢縈回水脈分，水光山色翠連雲。", "四時盡入詩人詠，役殺吳興柳使君。"]'),
('yuding-13','霅溪夜宴詩','水神','唐','御定全唐诗','yuding','','[]','渺渺煙波接九疑，幾人經此泣江蘺。',32,'御定全唐詩/json/864.json','["渺渺煙波接九疑，幾人經此泣江蘺。", "年年綠水青山色，不改重華南狩時。"]'),
('yuding-14','霅溪夜宴詩','水神','唐','御定全唐诗','yuding','','[]','浪闊波澄秋氣涼，沉沉水殿夜初長。自憐休退五湖客，',40,'御定全唐詩/json/864.json','["浪闊波澄秋氣涼，沉沉水殿夜初長。自憐休退五湖客，", "酒酣獨泛扁舟去，笑入琴高不死鄉。"]'),
('yuding-15','霅溪夜宴詩','水神','唐','御定全唐诗','yuding','','[]','珠光龍耀火燑燑，夜接朝雲宴渚宮。鳳管清吹淒極浦，',40,'御定全唐詩/json/864.json','["珠光龍耀火燑燑，夜接朝雲宴渚宮。鳳管清吹淒極浦，", "雲雨各飛真境後，不堪波上起悲風。"]'),
('yuding-16','霅溪夜宴詩','水神','唐','御定全唐诗','yuding','','[]','鳳鶱鶱以降瑞兮，患山雞之雜飛。玉溫溫以呈器兮，',158,'御定全唐詩/json/864.json','["鳳鶱鶱以降瑞兮，患山雞之雜飛。玉溫溫以呈器兮，", "既瑞器而無庸兮，宜昏暗之相微。徒刳石以為舟兮，", "矜孑孑于空江兮，靡群援之可依。血淋淋而滂流兮，", "羈魂汩沒兮我名永浮，碧波雖涸兮厥譽長流。", "向使甘言盛行於曩昔，豈今日居君王之座頭。", "是知貪名徇祿而隨世磨滅者，雖正寢之死乎無得與吾儔。", "當鼎足之嘉會兮，獲周旋于君侯。雕盤玉豆兮羅珍羞，"]'),
('yuding-17','霅溪夜宴詩','水神','唐','御定全唐诗','yuding','','[]','行殿秋未晚，水宮風初涼。誰言此中夜，得接朝宗行。',168,'御定全唐詩/json/864.json','["行殿秋未晚，水宮風初涼。誰言此中夜，得接朝宗行。", "靈鼉振冬冬，神龍耀煌煌。紅樓壓波起，翠幄連雲張。", "玉簫冷吟秋，瑤瑟清含商。賢臻江湖叟，貴列川瀆王。", "諒予衰俗人，無能振頹綱。分辭皆亂世，樂寐蛟螭鄉。", "棲遲幽島間，幾見波成桑。爾來盡流俗，難與傾壺觴。", "今日登華筵，稍覺神揚揚。方歡滄浪侶，遽恐白日光。", "海人瑞錦前，豈敢言文章。聊歌靈境會，此會誠難忘。"]'),
('yuding-18','霅溪夜宴詩','水神','唐','御定全唐诗','yuding','','[]','雪集大野兮血波洶洶，玄黃交戰兮吳無全隴。',62,'御定全唐詩/json/864.json','["雪集大野兮血波洶洶，玄黃交戰兮吳無全隴。", "既霸業之將墜，宜嘉謨之不從。國步顛蹶兮吾道遘凶，", "願保上善之柔德，何行樂之地兮難相逢。"]'),
('yuding-19','為劉洪作','輔國將軍','唐','御定全唐诗','yuding','','[]','烏烏在虛飛，玄駒遂野依。名今編戶籍，翠過葉生稀。',48,'御定全唐詩/json/864.json','["烏烏在虛飛，玄駒遂野依。名今編戶籍，翠過葉生稀。", "個樹枝條朽，三花五面啼。移家朝度日，誰覺□□□。"]'),
('yuding-20','語','太白山神','唐','御定全唐诗','yuding','','[]','三珠並一珠，驢馬沒人驅。歲月甲庚午，中興戊己土。',24,'御定全唐詩/json/864.json','["三珠並一珠，驢馬沒人驅。歲月甲庚午，中興戊己土。"]'),
('yuding-21','月夜吟','瀵水神','唐','御定全唐诗','yuding','','[]','夜月明皎皎，綠波空悠悠。',12,'御定全唐詩/json/864.json','["夜月明皎皎，綠波空悠悠。"]'),
('yuding-22','答鄭生歌','湘中蛟女','唐','御定全唐诗','yuding','','[]','溯青山兮江之隅，拖湘波兮褭綠裾。',32,'御定全唐詩/json/864.json','["溯青山兮江之隅，拖湘波兮褭綠裾。", "荷拳拳兮情未舒，匪同歸兮將焉如。"]'),
('yuding-23','風光詞','湘中蛟女','唐','御定全唐诗','yuding','','[]','隆佳秀兮昭盛時，播熏綠兮淑華歸。故里荑與處萼兮，',49,'御定全唐詩/json/864.json','["隆佳秀兮昭盛時，播熏綠兮淑華歸。故里荑與處萼兮，", "醉融光兮渺渺彌彌，迷千里兮涵煙眉。晨陶陶兮暮熙熙，"]'),
('yuding-24','附：鄭生詩','湘中蛟女','唐','御定全唐诗','yuding','','[]','情無垠兮水湯湯，懷佳期兮屬三湘。',16,'御定全唐詩/json/864.json','["情無垠兮水湯湯，懷佳期兮屬三湘。"]'),
('yuding-25','感懷詩','龍女','唐','御定全唐诗','yuding','','[]','海門連洞庭，每去三千里。十載一歸來，辛苦瀟湘水。',24,'御定全唐詩/json/864.json','["海門連洞庭，每去三千里。十載一歸來，辛苦瀟湘水。"]'),
('yuding-26','寄張無頗','廣利王女','唐','御定全唐诗','yuding','','[]','羞解明璫尋漢渚，但憑春夢訪天涯。',64,'御定全唐詩/json/864.json','["羞解明璫尋漢渚，但憑春夢訪天涯。", "紅樓日暮鶯飛去，愁殺深宮落砌花。", "燕語春泥墮錦筵，情愁無意整花鈿。", "寒閨欹枕不成夢，香炷金爐自褭煙。"]'),
('yuding-27','與崔渥冥會雜詩','不詳','唐','御定全唐诗','yuding','','[]','萬里同心別九重，定知涉曆此相逢。',288,'御定全唐詩/json/864.json','["萬里同心別九重，定知涉曆此相逢。", "誰人翻向群峰路，不得蒼梧徇玉容。", "春鳥交交引思濃，豈期塵跡拜仙宮。", "鸞歌鳳舞飄珠翠，疑是陽臺一夢中。", "鸞輿昔日出蒲關，一去蒼梧更不還。", "若是不留千古恨，湘江何事竹猶斑。", "愁聞黃鳥夜關關，溈汭春來有夢還。", "遺美代移刊勒絕，唯聞留得淚痕斑。", "方承恩寵醉金杯，豈為干戈驟到來。", "亡國破家皆有恨，捧心無語淚蘇台。", "桃花流水兩堪傷，洞口煙波月漸長。", "莫道仙家無別恨，至今垂淚憶劉郎。", "涇陽平野草初春，遙望家鄉淚滴頻。", "當此不知多少恨，至今空憶在靈姻。", "目斷魂銷正惘然，九疑山際路漫漫。", "何人知得心中恨，空有湘江竹萬竿。", "常說仙家事不同，偶陪花月此宵中。", "錦屏銀燭皆堪恨，惆悵紗窗向曉風。"]'),
('yuding-28','又湘妃詩四首','不詳','唐','御定全唐诗','yuding','','[]','渺渺三湘萬里程，淚篁幽石助芳貞。',128,'御定全唐詩/json/864.json','["渺渺三湘萬里程，淚篁幽石助芳貞。", "孤雲目斷蒼梧野，不得攀龍到玉京。", "碧杜紅蘅縹緲香，冰絲彈月弄清涼。", "峰巒一一俱相似，九處堪疑九斷腸。", "玉輦金根去不回，湘川秋晚楚弦哀。", "自從泣盡江蘺血，夜夜愁風怨雨來。", "少將風月怨平湖，見盡扶桑水到枯。", "相約杏花壇上去，畫闌紅子鬥摴蒱。"]'),
('yuding-29','與何光遠贈答詩','何光遠','唐','御定全唐诗','yuding','','[]','簷上簷前燕語新，花開柳發自傷神。',32,'御定全唐詩/json/864.json','["簷上簷前燕語新，花開柳發自傷神。", "誰能將我相思意，說與江隈解佩人。"]'),
('yuding-30','與何光遠贈答詩','龍女','唐','御定全唐诗','yuding','','[]','坐久風吹綠綺寒，九天月照水精盤。',32,'御定全唐詩/json/864.json','["坐久風吹綠綺寒，九天月照水精盤。", "不思卻返沈潛去，為惜春光一夜歡。"]'),
('yuding-31','與何光遠贈答詩','何光遠','唐','御定全唐诗','yuding','','[]','澹蕩春光物象饒，一枝瓊豔不勝嬌。',32,'御定全唐詩/json/864.json','["澹蕩春光物象饒，一枝瓊豔不勝嬌。", "若能許解相思佩，何羨星天渡鵲橋。"]'),
('yuding-32','與何光遠贈答詩','何光遠','唐','御定全唐诗','yuding','','[]','玉漏涓涓銀漢清，鵲橋新架路初成。',64,'御定全唐詩/json/864.json','["玉漏涓涓銀漢清，鵲橋新架路初成。", "催妝既要裁篇詠，鳳吹鸞歌早會迎。", "寶車輾駐彩雲開，誤到蓬萊頂上來。", "瓊室既登花得折，永將凡骨逐風雷。"]'),
('yuding-33','與何光遠贈答詩','龍女','唐','御定全唐诗','yuding','','[]','負妾當時寤寐求，從茲粉面阻綢繆。',32,'御定全唐詩/json/864.json','["負妾當時寤寐求，從茲粉面阻綢繆。", "宮空月苦瑤雲斷，寂寞巴江水自流。"]'),
('yuding-34','寄紫蓋陽居士','黃陵美人','唐','御定全唐诗','yuding','','[]','落葉棲鴉掩廟扉，菟絲金縷舊羅衣。',32,'御定全唐詩/json/864.json','["落葉棲鴉掩廟扉，菟絲金縷舊羅衣。", "渡頭明月好攜手，獨自待郎郎不歸。"]'),
('yuding-35','贈謝府君','吳興神女','唐','御定全唐诗','yuding','','[]','玉釵空中墮，金釧色已歇。獨泣謝春風，秋夜傷明月。',24,'御定全唐詩/json/864.json','["玉釵空中墮，金釧色已歇。獨泣謝春風，秋夜傷明月。"]'),
('yuding-0','塚上答太宗','慕容垂','唐','御定全唐诗','yuding','','[]','我昔勝君昔，君今勝我今。榮華各異代，何用苦追尋。',24,'御定全唐詩/json/865.json','["我昔勝君昔，君今勝我今。榮華各異代，何用苦追尋。"]'),
('yuding-1','遺畫工詩','釋明解','唐','御定全唐诗','yuding','','[]','握手不能別，撫膺聊自傷。痛矣時陰短，悲哉泉路長。',48,'御定全唐詩/json/865.json','["握手不能別，撫膺聊自傷。痛矣時陰短，悲哉泉路長。", "松林驚野吹，荒隧落寒霜。言離何以贈，留心內典章。"]'),
('yuding-2','夜吟','巴峽鬼','唐','御定全唐诗','yuding','','[]','秋徑填黃葉，寒摧露草根。猿聲一叫斷，客淚數重痕。',24,'御定全唐詩/json/865.json','["秋徑填黃葉，寒摧露草根。猿聲一叫斷，客淚數重痕。"]'),
('yuding-3','愧謝詩','河湄鬼','唐','御定全唐诗','yuding','','[]','我本邯鄲士，祇役死河湄。不得家人哭，勞君行路悲。',24,'御定全唐詩/json/865.json','["我本邯鄲士，祇役死河湄。不得家人哭，勞君行路悲。"]'),
('yuding-4','擲裴武公詩','介胄鬼','唐','御定全唐诗','yuding','','[]','屢策羸驂曆亂峋，叢嵐映日晝如曛。長橋駕險浮天漢，',40,'御定全唐詩/json/865.json','["屢策羸驂曆亂峋，叢嵐映日晝如曛。長橋駕險浮天漢，", "廢興盡系前生數，休衒英雄勇冠軍。"]'),
('yuding-5','死後詩','李叔霽','唐','御定全唐诗','yuding','','[]','忽作無期別，沈冥恨有餘。長安雖不遠，無信可傳書。',24,'御定全唐詩/json/865.json','["忽作無期別，沈冥恨有餘。長安雖不遠，無信可傳書。"]'),
('yuding-6','洋州館夜吟','竇裕','唐','御定全唐诗','yuding','','[]','門依楚水岸，身寄洋州館。望月獨相思，塵襟淚痕滿。',24,'御定全唐詩/json/865.json','["門依楚水岸，身寄洋州館。望月獨相思，塵襟淚痕滿。"]'),
('yuding-7','獻元載','書生','唐','御定全唐诗','yuding','','[]','城東城西舊居處，城裏飛花亂如絮。',32,'御定全唐詩/json/865.json','["城東城西舊居處，城裏飛花亂如絮。", "海燕銜泥欲下來，屋裏無人卻飛去。"]'),
('yuding-8','詩二首','虎丘石壁鬼','唐','御定全唐诗','yuding','','[]','高松多悲風，蕭蕭清且哀。南山接幽壟，幽壟空崔嵬。',144,'御定全唐詩/json/865.json','["高松多悲風，蕭蕭清且哀。南山接幽壟，幽壟空崔嵬。", "白日徒昭昭，不照長夜台。雖知生者樂，魂魄安能回。", "況複念所親，慟哭心肝摧。慟哭更何言，哀哉複哀哉。", "神仙不可學，形化空遊魂。白日非我朝，青松為我門。", "雖複隔幽顯，猶知念子孫。何以遣悲惋，萬物歸其根。", "寄語世上人，莫厭臨芳尊。莊生問枯骨，三樂成虛言。"]'),
('yuding-9','祭後見石上詩','虎丘石壁鬼','唐','御定全唐诗','yuding','','[]','幽明雖異路，平昔忝攻文。欲知潛昧處，山北兩孤墳。',24,'御定全唐詩/json/865.json','["幽明雖異路，平昔忝攻文。欲知潛昧處，山北兩孤墳。"]'),
('yuding-10','詠浮雲','陸憑','唐','御定全唐诗','yuding','','[]','虛虛複空空，瞬息天地中。假合成此像，吾亦非吾躬。',24,'御定全唐詩/json/865.json','["虛虛複空空，瞬息天地中。假合成此像，吾亦非吾躬。"]'),
('yuding-11','呈李續','韓弇','唐','御定全唐诗','yuding','','[]','我有敵國讎，無人可為雪。每至秦隴頭，遊魂自嗚咽。',24,'御定全唐詩/json/865.json','["我有敵國讎，無人可為雪。每至秦隴頭，遊魂自嗚咽。"]'),
('yuding-12','和崔侍禦','尉佗','唐','御定全唐诗','yuding','','[]','千歲荒台隳路隅，一煩太守重椒塗。',32,'御定全唐詩/json/865.json','["千歲荒台隳路隅，一煩太守重椒塗。", "感君拂拭意何極，贈爾美婦與明珠。"]'),
('yuding-13','贈竇丞','劉溉','唐','御定全唐诗','yuding','','[]','冥路杳杳人不知，不用苦說使人悲。',32,'御定全唐詩/json/865.json','["冥路杳杳人不知，不用苦說使人悲。", "喜得逢君傳家信，後會茫茫何處期。"]'),
('yuding-14','敘幽冤','鄭瓊羅','唐','御定全唐诗','yuding','','[]','痛填心兮不能語，寸斷腸兮訴何處。',32,'御定全唐詩/json/865.json','["痛填心兮不能語，寸斷腸兮訴何處。", "春生萬物妾不生，更恨香魂不相遇。"]'),
('yuding-15','過台城感舊','沈青箱','唐','御定全唐诗','yuding','','[]','六代舊山川，興亡幾百年。繁華今寂寞，朝市昔喧闐。',48,'御定全唐詩/json/865.json','["六代舊山川，興亡幾百年。繁華今寂寞，朝市昔喧闐。", "夜月琉璃水，春風卵色天。傷時與懷古，垂淚國門前。"]'),
('yuding-16','詩','襄陽舉人','唐','御定全唐诗','yuding','','[]','流水涓涓芹努芽，織烏西飛客還家。',32,'御定全唐詩/json/865.json','["流水涓涓芹努芽，織烏西飛客還家。", "荒村無人作寒食，殯宮空對棠梨花。"]'),
('yuding-17','踏歌','河中鬼','唐','御定全唐诗','yuding','','[]','河水流溷溷，山頭種蕎麥。兩個胡孫門底來，',20,'御定全唐詩/json/865.json','["河水流溷溷，山頭種蕎麥。兩個胡孫門底來，"]'),
('yuding-18','題少陵別墅','蕭微','唐','御定全唐诗','yuding','','[]','新構茅齋野澗東，松楸交影足悲風。',32,'御定全唐詩/json/865.json','["新構茅齋野澗東，松楸交影足悲風。", "人間歲月如流水，何事頻行此路中。"]'),
('yuding-19','夢張垂贈詩','張省躬','唐','御定全唐诗','yuding','','[]','戚戚複戚戚，秋堂百年色。而我獨茫茫，荒郊遇寒食。',24,'御定全唐詩/json/865.json','["戚戚複戚戚，秋堂百年色。而我獨茫茫，荒郊遇寒食。"]'),
('yuding-20','秋月聯句','商山三丈夫','唐','御定全唐诗','yuding','','[]','秋月圓如鏡，——王步兵',44,'御定全唐詩/json/865.json','["秋月圓如鏡，——王步兵", "秋風利似刀。——蕭中郎", "秋雲輕比絮，——梁璟", "秋草細如毛。——諸葛長史"]'),
('yuding-21','天明聯句','不詳','唐','御定全唐诗','yuding','','[]','幽樹高高影，——蕭中郎',44,'御定全唐詩/json/865.json','["幽樹高高影，——蕭中郎", "山花寂寂香。——王步兵", "山天遙歷歷，——諸葛長史", "山水急湯湯。——梁璟"]'),
('yuding-22','贈張珽','鄭適','唐','御定全唐诗','yuding','','[]','昔為吟風嘯月人，今為吟風嘯月身。',32,'御定全唐詩/json/865.json','["昔為吟風嘯月人，今為吟風嘯月身。", "塚壞路邊吟嘯罷，安知今日又勞神。"]'),
('yuding-23','西軒詩','甘露寺鬼','唐','御定全唐诗','yuding','','[]','趙壹能為賦，鄒陽解獻書。可惜西江水，不救轍中魚。',104,'御定全唐詩/json/865.json','["趙壹能為賦，鄒陽解獻書。可惜西江水，不救轍中魚。", "偉哉橫海鱗，壯矣垂天翼。一旦失風水，翻為螻蟻食。", "功遂侔昔人，保退無智力。既涉太行險，茲路信難陟。", "握裏龍蛇紙上鸞，逡巡千幅不將難。", "顧雲已往羅隱耄，更有何人逞筆端。"]'),
('yuding-24','降巫詩','邵謁','唐','御定全唐诗','yuding','','[]','青山山下少年郎，失意當時別故鄉。',32,'御定全唐詩/json/865.json','["青山山下少年郎，失意當時別故鄉。", "惆悵不堪回首望，隔溪遙見舊書堂。"]'),
('yuding-25','贈雷殿直','石恪','唐','御定全唐诗','yuding','','[]','衡陽去此正三年，一路程途甚坦然。深邃門牆三楚外，',40,'御定全唐詩/json/865.json','["衡陽去此正三年，一路程途甚坦然。深邃門牆三楚外，", "公退只應無別事，朱陵後洞看神仙。"]'),
('yuding-26','吟','富春沙際鬼','唐','御定全唐诗','yuding','','[]','陊江三十年，潮打形骸朽。家人都不知，何處奠杯酒。',24,'御定全唐詩/json/865.json','["陊江三十年，潮打形骸朽。家人都不知，何處奠杯酒。"]'),
('yuding-27','又吟','富春沙際鬼','唐','御定全唐诗','yuding','','[]','莫問我姓名，向君言亦空。潮生沙骨冷，魂魄悲秋風。',24,'御定全唐詩/json/865.json','["莫問我姓名，向君言亦空。潮生沙骨冷，魂魄悲秋風。"]'),
('yuding-28','獻高駢','趙z7','唐','御定全唐诗','yuding','','[]','我昔勝君昔，君今勝我今。人生一世事，何用苦相侵。',24,'御定全唐詩/json/865.json','["我昔勝君昔，君今勝我今。人生一世事，何用苦相侵。"]'),
('yuding-0','吟','九華山白衣','唐','御定全唐诗','yuding','','[]','澗水潺潺聲不絕，溪壟茫茫野花發。',32,'御定全唐詩/json/866.json','["澗水潺潺聲不絕，溪壟茫茫野花發。", "自去自來人不知，歸時唯對空山月。"]'),
('yuding-1','詩','田達誠宅鬼','唐','御定全唐诗','yuding','','[]','天然與我一靈通，還與人間事不同。',32,'御定全唐詩/json/866.json','["天然與我一靈通，還與人間事不同。", "要識吾家真姓字，天地南頭一段紅。"]'),
('yuding-2','秋夜吟','長安中鬼','唐','御定全唐诗','yuding','','[]','六街鼓歇行人絕，九衢茫茫室有月。——',36,'御定全唐詩/json/866.json','["六街鼓歇行人絕，九衢茫茫室有月。——", "九衢生人何勞勞，長安土盡槐根高。——"]'),
('yuding-3','題窗上詩','隔窗鬼','唐','御定全唐诗','yuding','','[]','何人窗下讀書聲，南斗闌幹北斗橫。',32,'御定全唐詩/json/866.json','["何人窗下讀書聲，南斗闌幹北斗橫。", "千里思家歸不得，春風腸斷石頭城。"]'),
('yuding-4','柱上詩','巴陵館鬼','唐','御定全唐诗','yuding','','[]','爺娘送我青楓根，不記青楓幾回落。',32,'御定全唐詩/json/866.json','["爺娘送我青楓根，不記青楓幾回落。", "當時手刺衣上花，今日為灰不堪著。"]'),
('yuding-5','留別安鳳','徐侃','唐','御定全唐诗','yuding','','[]','君寄長安久，恥不還故鄉。我別長安去，切在慰高堂。',36,'御定全唐詩/json/866.json','["君寄長安久，恥不還故鄉。我別長安去，切在慰高堂。", "不意與離恨，泉下亦難忘。"]'),
('yuding-6','附：安鳳贈別徐侃','安鳳','唐','御定全唐诗','yuding','','[]','一自離鄉國，十年在咸秦。泣盡卞和血，不逢一故人。',60,'御定全唐詩/json/866.json','["一自離鄉國，十年在咸秦。泣盡卞和血，不逢一故人。", "今日舊友別，羞此漂泊身。離情吟詩處，麻衣掩淚頻。", "淚別各分袂，且及來年春。"]'),
('yuding-7','述懷','商山客死生','唐','御定全唐诗','yuding','','[]','家住驛北路，百里無四鄰。往來不相問，寂寂山家春。',72,'御定全唐詩/json/866.json','["家住驛北路，百里無四鄰。往來不相問，寂寂山家春。", "南岡夜蕭蕭，青松與白楊。家人應有夢，遠客已無腸。", "白草寒露裏，亂山明月中。是夕苦吟罷，寒燭與君同。"]'),
('yuding-8','續鄭郊吟','塚中人','唐','御定全唐诗','yuding','','[]','塚上兩竿竹，風吹常嫋嫋。——鄭郊',33,'御定全唐詩/json/866.json','["塚上兩竿竹，風吹常嫋嫋。——鄭郊", "下有百年人，長眠不知曉。——塚中人"]'),
('yuding-9','題壁','崇聖寺鬼','唐','御定全唐诗','yuding','','[]','禁煙佳節同遊此，正值酴醿夾岸香。',64,'御定全唐詩/json/866.json','["禁煙佳節同遊此，正值酴醿夾岸香。", "緬首十年前往事，強吟風景亂愁腸。", "策馬暫尋原上路，落花芳草尚依然。", "家亡國破一場夢，惆悵又逢寒食天。"]'),
('yuding-10','血書詩','任彥思家鬼','唐','御定全唐诗','yuding','','[]','物類易遷變，我行人不見。珍重任彥思，相別日已遠。',24,'御定全唐詩/json/866.json','["物類易遷變，我行人不見。珍重任彥思，相別日已遠。"]'),
('yuding-11','贈馬植','峽中白衣','唐','御定全唐诗','yuding','','[]','截竹為筒作笛吹，鳳凰池上鳳凰飛。',32,'御定全唐詩/json/866.json','["截竹為筒作笛吹，鳳凰池上鳳凰飛。", "勞君更向黔南去，即是陶鈞萬類時。"]'),
('yuding-12','題芭蕉葉上','張仁寶','唐','御定全唐诗','yuding','','[]','寒食家家盡禁煙，野棠風墜小花鈿。',32,'御定全唐詩/json/866.json','["寒食家家盡禁煙，野棠風墜小花鈿。", "如今空有孤魂夢，半在嘉陵半錦川。"]'),
('yuding-13','官坡館聯句','崔常侍','唐','御定全唐诗','yuding','','[]','床頭錦衾班複班，架上朱衣殷複殷。',32,'御定全唐詩/json/866.json','["床頭錦衾班複班，架上朱衣殷複殷。", "空庭朗月閑複閑，夜長路遠山複山。"]'),
('yuding-14','亡後見形詩','李煜','唐','御定全唐诗','yuding','','[]','異國非所志，煩勞殊清閒。驚濤千萬里，無乃見鐘山。',24,'御定全唐詩/json/866.json','["異國非所志，煩勞殊清閒。驚濤千萬里，無乃見鐘山。"]'),
('yuding-15','同鹿門少年馬紹隆冥遊詩：同望荊門','龐德公','唐','御定全唐诗','yuding','','[]','千年故國歲華奔，一柱高臺已斷魂。',32,'御定全唐詩/json/866.json','["千年故國歲華奔，一柱高臺已斷魂。", "唯有峴亭清夜月，與君長嘯學蘇門。"]'),
('yuding-16','同鹿門少年馬紹隆冥遊詩：憶荊南','龐德公','唐','御定全唐诗','yuding','','[]','高名宋玉遺閑麗，作賦蘭成絕盛才。',32,'御定全唐詩/json/866.json','["高名宋玉遺閑麗，作賦蘭成絕盛才。", "誰似遼東千歲鶴，倚天華表卻歸來。"]'),
('yuding-17','貽常夷詩','朱均','唐','御定全唐诗','yuding','','[]','平生遊城郭，殂沒委荒榛。自我辭人世，不知秋與春。',108,'御定全唐詩/json/866.json','["平生遊城郭，殂沒委荒榛。自我辭人世，不知秋與春。", "牛羊久來牧，松柏幾成薪。分絕車馬好，甘隨狐兔群。", "何處清風至，君子幸為鄰。烈烈盛名德，依依佇良賓。", "千年何旦暮，一室動人神。喬木如在望，通衢良易遵。", "高門儻無隔，向與析龍津。"]'),
('yuding-18','空館夜歌','夷陵女郎','唐','御定全唐诗','yuding','','[]','明月清風，良宵會同。星河易翻，歡娛不終。',119,'御定全唐詩/json/866.json','["明月清風，良宵會同。星河易翻，歡娛不終。", "綠樽翠杓，為君斟酌。今夕不飲，何時歡樂。", "楊柳楊柳，嫋嫋隨風急。西樓美人春夢長，", "玉戶金缸，願陪君王。邯鄲宮中，金石絲簧。", "衛女秦娥，左右成行。紈縞繽紛，翠眉紅妝。", "王歡顧盼，為王歌舞。願得君歡，常無災苦。"]'),
('yuding-19','贈夫詩三首','孔氏','唐','御定全唐诗','yuding','','[]','不忿成故人，掩涕每盈巾。死生今有隔，相見永無因。',72,'御定全唐詩/json/866.json','["不忿成故人，掩涕每盈巾。死生今有隔，相見永無因。", "匣裏殘妝粉，留將與後人。黃泉無用處，恨作塚中塵。", "有意懷男女，無情亦任君。欲知腸斷處，明月照孤墳。"]'),
('yuding-20','答夫詩二首','張氏','唐','御定全唐诗','yuding','','[]','不分殊幽顯，那堪異古今。陰陽徒自隔，聚散兩難心。',48,'御定全唐詩/json/866.json','["不分殊幽顯，那堪異古今。陰陽徒自隔，聚散兩難心。", "蘭階兔月斜，銀燭半含花。自憐長夜客，泉路以為家。"]'),
('yuding-21','附：唐晅悼妻詩','唐晅','唐','御定全唐诗','yuding','','[]','寢室悲長簟，妝樓泣鏡臺。獨悲桃李節，不共夜泉開。',84,'御定全唐詩/json/866.json','["寢室悲長簟，妝樓泣鏡臺。獨悲桃李節，不共夜泉開。", "魂兮若有感，仿佛夢中來。", "常時華堂靜，笑語度更籌。恍惚人事改，冥寞委荒丘。", "陽原歌薤露，陰壑惜藏舟。清夜妝台月，空想畫眉愁。"]'),
('yuding-22','贈妻詩','唐晅','唐','御定全唐诗','yuding','','[]','嶧陽桐半死，延津劍一沈。如何宿昔內，空負百年心。',24,'御定全唐詩/json/866.json','["嶧陽桐半死，延津劍一沈。如何宿昔內，空負百年心。"]'),
('yuding-23','贈姊','韋璜','唐','御定全唐诗','yuding','','[]','修短各有分，浮華亦非真。斷腸泉壤下，幽憂難具陳。',36,'御定全唐詩/json/866.json','["修短各有分，浮華亦非真。斷腸泉壤下，幽憂難具陳。", "淒淒白楊風，日暮堪愁人。"]'),
('yuding-24','贈夫二首','韋璜','唐','御定全唐诗','yuding','','[]','不得長相守，青春夭蕣華。舊遊今永已，泉路卻為家。',56,'御定全唐詩/json/866.json','["不得長相守，青春夭蕣華。舊遊今永已，泉路卻為家。", "早知離別切人心，悔作從來恩愛深。", "黃泉冥寞雖長逝，白日屏帷還重尋。"]'),
('yuding-25','贈嫂','韋璜','唐','御定全唐诗','yuding','','[]','赤心用盡為相知，慮後防前只定疑。',32,'御定全唐詩/json/866.json','["赤心用盡為相知，慮後防前只定疑。", "案牘可申生節目，桃符雖聖欲何為。"]'),
('yuding-26','與獨孤穆冥會詩','臨淄縣主','唐','御定全唐诗','yuding','','[]','江都昔喪亂，闕下多構兵。豺虎恣吞噬，干戈日縱橫。',514,'御定全唐詩/json/866.json','["江都昔喪亂，闕下多構兵。豺虎恣吞噬，干戈日縱橫。", "逆徒自外至，半夜開重城。膏血浸宮殿，刀槍倚簷楹。", "今知從逆者，乃是公與卿。白刃汙黃屋，邦家遂因傾。", "疾風知勁草，世亂識忠臣。哀哀獨孤公，臨死乃結纓。", "天地既板蕩，雲雷時未亨。今者二百載，幽懷猶未平。", "山河風月古，陵寢露煙青。君子秉祖德，方垂忠烈名。", "華軒一惠顧，土室以為榮。丈夫立志操，存沒感其情。", "求義若可托，誰能抱幽貞。", "皇天昔降禍，隋室若綴旒。患難在雙闕，干戈連九州。", "出門皆凶豎，所向多逆謀。白日忽然暮，頹波不可收。", "望夷既結釁，宗社亦貽羞。溫室兵始合，宮闈血已流。", "憫哉吹簫子，悲啼下鳳樓。霜刃徒見逼，玉笄不可求。", "羅襦遺侍者，粉黛成仇讎。邦國已淪覆，餘生誓不留。", "英英將軍祖，獨以社稷憂。丹血濺黼扆，豐肌染戈矛。", "今來見禾黍，盡日悲宗周。玉樹已寂寞，泉台千萬秋。", "感茲一顧重，願以死節酬。幽顯儻不昧，終焉契綢繆。", "平陽縣中樹，久作廣陵塵。不意何郎至，黃泉重見春。", "金閨久無主，羅袂坐生塵。願作吹簫伴，同為騎鳳人。", "朱軒下長路，青草啟孤墳。猶勝陽臺上，空看朝暮雲。", "露草芊芊，頹塋未遷。自我居此，於今幾年。與君先祖，", "俟君之北，攜手同歸。", "伊彼維揚，在天一方。驅馬悠悠，忽來異鄉。情通幽顯，", "惟子之故，不遑淹留。"]'),
('yuding-27','與李章武贈答詩','王氏婦','唐','御定全唐诗','yuding','','[]','怨鴦綺，知結幾千絲。別後尋交頸，應傷未別時。',166,'御定全唐詩/json/866.json','["怨鴦綺，知結幾千絲。別後尋交頸，應傷未別時。", "撚指環，相思見環重相憶。願君永持玩，迴圈無終極。", "河漢已傾斜，神魂欲超越。願郎更回抱，終天從此訣。", "分從幽顯隔，豈謂有佳期。寧辭重重別，所歎去何之。", "昔辭懷後會，今別便終天。新悲與舊恨，千古閉窮泉。", "後期杳無約，前恨已相尋。別路無行信，何因得寄心。", "水不西歸月暫圓，令人惆悵古城邊。蕭條明早分岐路，"]'),
('yuding-28','附：李助為章武賦','李助','唐','御定全唐诗','yuding','','[]','石沈遼海闊，劍別楚天長。會合知無日，離心滿夕陽。',24,'御定全唐詩/json/866.json','["石沈遼海闊，劍別楚天長。會合知無日，離心滿夕陽。"]'),
('yuding-29','與曾季衡冥會詩','王麗真','唐','御定全唐诗','yuding','','[]','五原分袂真吳越燕拆鶯離芳草歇年少煙花處處春北邙空恨清秋月',56,'御定全唐詩/json/866.json','["五原分袂真吳越燕拆鶯離芳草歇年少煙花處處春北邙空恨清秋月", "莎草青青雁欲歸玉腮珠淚灑臨岐雲鬟飄去香風盡愁見鶯啼紅樹枝"]'),
('yuding-30','贈段何','客戶裏女子','唐','御定全唐诗','yuding','','[]','樂廣清羸經幾年，姹娘相托不論錢。',32,'御定全唐詩/json/866.json','["樂廣清羸經幾年，姹娘相托不論錢。", "輕盈妙質歸何處，惆悵碧樓紅玉鈿。"]'),
('yuding-31','湖城廳吟','密陀僧','唐','御定全唐诗','yuding','','[]','黃帝上天時，鼎湖元在茲。七十二玉女，化作黃金芝。',24,'御定全唐詩/json/866.json','["黃帝上天時，鼎湖元在茲。七十二玉女，化作黃金芝。"]'),
('yuding-32','謝王軒','西施','唐','御定全唐诗','yuding','','[]','妾自吳宮還越國，素衣千載無人識。',32,'御定全唐詩/json/866.json','["妾自吳宮還越國，素衣千載無人識。", "當時心比金石堅，今日為君堅不得。"]'),
('yuding-33','附：王軒題西施石詩','王軒','唐','御定全唐诗','yuding','','[]','嶺上千峰秀，江邊細草春。今逢浣紗石，不見浣紗人。',24,'御定全唐詩/json/866.json','["嶺上千峰秀，江邊細草春。今逢浣紗石，不見浣紗人。"]'),
('yuding-34','附：軒詩','王軒','唐','御定全唐诗','yuding','','[]','佳人去千載，溪山久寂寞。野水浮白煙，岩花自開落。',48,'御定全唐詩/json/866.json','["佳人去千載，溪山久寂寞。野水浮白煙，岩花自開落。", "猿鳥舊清音，風月閑樓閣。無語立斜陽，幽情入天幕。"]'),
('yuding-35','西施詩','西施','唐','御定全唐诗','yuding','','[]','高花岩外曉相鮮，幽鳥雨中啼不歇。',32,'御定全唐詩/json/866.json','["高花岩外曉相鮮，幽鳥雨中啼不歇。", "紅雲飛過大江西，從此人間怨風月。"]'),
('yuding-36','附：軒詩','王軒','唐','御定全唐诗','yuding','','[]','當時計拙笑將軍，何事安邦賴美人。',32,'御定全唐詩/json/866.json','["當時計拙笑將軍，何事安邦賴美人。", "一自仙葩入吳國，從茲越國更無春。"]'),
('yuding-37','西施詩','西施','唐','御定全唐诗','yuding','','[]','雲霞出沒群峰外，鷗鳥浮沈一水間。',32,'御定全唐詩/json/866.json','["雲霞出沒群峰外，鷗鳥浮沈一水間。", "一自越兵齊振地，夢魂不到虎丘山。"]'),
('yuding-38','與蕭曠冥會詩','甄後','唐','御定全唐诗','yuding','','[]','玉箸凝腮憶魏宮，朱弦一弄洗清風。',32,'御定全唐詩/json/866.json','["玉箸凝腮憶魏宮，朱弦一弄洗清風。", "明晨追賞應愁寂，沙渚煙銷翠羽空。"]'),
('yuding-39','與蕭曠冥會詩','織綃女','唐','御定全唐诗','yuding','','[]','織綃泉底少歡娛，更勸蕭郎盡酒壺。',32,'御定全唐詩/json/866.json','["織綃泉底少歡娛，更勸蕭郎盡酒壺。", "愁見玉琴彈別鶴，又將清淚滴真珠。"]'),
('yuding-40','與蕭曠冥會詩','蕭曠','唐','御定全唐诗','yuding','','[]','紅蘭吐豔間夭桃，自喜尋芳數已遭。',32,'御定全唐詩/json/866.json','["紅蘭吐豔間夭桃，自喜尋芳數已遭。", "珠佩鵲橋從此斷，遙天空恨碧雲高。"]'),
('yuding-41','五原夜吟','沙磧女子','唐','御定全唐诗','yuding','','[]','雲鬟消盡轉蓬稀，埋骨窮荒失所依。',32,'御定全唐詩/json/866.json','["雲鬟消盡轉蓬稀，埋骨窮荒失所依。", "牧馬不嘶沙月白，孤魂空逐雁南飛。"]'),
('yuding-42','與顏浚冥會詩','陳宮妃嬪','唐','御定全唐诗','yuding','','[]','秋草荒台響夜蛩，白楊凋盡減悲風。',128,'御定全唐詩/json/866.json','["秋草荒台響夜蛩，白楊凋盡減悲風。", "彩箋曾擘欺江總，綺閣塵消玉樹空。", "寶閣排雲稱望仙，五雲高豔擁朝天。", "清溪猶有當時月，應照瓊花綻綺筵。", "素魄初圓恨翠娥，繁華濃豔竟如何。", "南朝唯有長江水，依舊門前作逝波。", "簫管清吟怨麗華，秋江寒月綺窗斜。", "慚非後主題箋客，得見臨春閣上花。"]'),
('yuding-43','驛樓誦詩','湘中女子','唐','御定全唐诗','yuding','','[]','紅樹醉秋色，碧溪彈夜弦。佳期不可再，風雨杳如年。',24,'御定全唐詩/json/866.json','["紅樹醉秋色，碧溪彈夜弦。佳期不可再，風雨杳如年。"]'),
('yuding-44','贈楊蘊中','薛濤','唐','御定全唐诗','yuding','','[]','玉漏聲長燈耿耿，東牆西牆時見影。',32,'御定全唐詩/json/866.json','["玉漏聲長燈耿耿，東牆西牆時見影。", "月明窗外子規啼，忍使孤魂愁夜永。"]'),
('yuding-45','葬後見形詩','張太華','唐','御定全唐诗','yuding','','[]','獨臥經秋墮鬢蟬，白楊風起不成眠。',32,'御定全唐詩/json/866.json','["獨臥經秋墮鬢蟬，白楊風起不成眠。", "尋思往日椒房寵，淚濕夜襟損翠鈿。"]');
